/* ============================================================================
   linux+  ::  quizEngine.js
   The XK0-006 question bank (500 items, content/quizN merged here), the PBQ
   database (30 items), and the assessment engines (domain/quick/adaptive/
   missed quizzes, timed mock, and the PBQ simulator). Exposes window.QUIZ.
   Every exam figure is read from LINUXPLUS.exam (the single source of truth).
   Authored by Professor Rizwan Virani.
   ============================================================================ */
/* linux+ :: XK0-006 Domain 1 question bank (100 items, inline). Populates LINUXPLUS.questions. */
window.LINUXPLUS = window.LINUXPLUS || {}; LINUXPLUS.questions = LINUXPLUS.questions || [];
LINUXPLUS.questions.push(
{ id:"D1-001", domain:1, obj:"1.3", diff:"medium", q:"An administrator added a new 500 GB disk and must extend the existing /data logical volume without downtime. Which sequence is correct?", options:["mkfs.xfs then mount","fdisk then reboot","pvcreate, vgextend, lvextend, then xfs_growfs","resize2fs then pvcreate"], answer:2, explain:"<strong>pvcreate, vgextend, lvextend, then xfs_growfs</strong> is the correct LVM growth path: initialize the disk as a physical volume, add it to the volume group, extend the logical volume, then grow the filesystem online.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mkfs.xfs then mount</b>: mkfs creates a new filesystem and would destroy existing data; it does not extend a volume.</span><span class='qd'><b>fdisk then reboot</b>: fdisk edits partition tables and a reboot is unnecessary; neither grows an LV.</span><span class='qd'><b>resize2fs then pvcreate</b>: the order is backwards and resize2fs is for ext filesystems, not XFS.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-002", domain:1, obj:"1.1", diff:"easy", q:"On a UEFI system, which filesystem must the EFI System Partition use so the firmware can read the bootloader?", options:["ext4","XFS","FAT32 (vfat)","Btrfs"], answer:2, explain:"<strong>FAT32 (vfat)</strong> is required for the EFI System Partition because UEFI firmware is specified to read FAT-formatted partitions to locate the .efi bootloader binaries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ext4</b>: UEFI firmware cannot reliably read ext4, so the ESP would not be found at boot.</span><span class='qd'><b>XFS</b>: XFS is not part of the UEFI specification and firmware cannot mount it for booting.</span><span class='qd'><b>Btrfs</b>: Btrfs is unsupported by firmware for the ESP and would prevent loading the bootloader.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-003", domain:1, obj:"1.4", diff:"medium", q:"Using nmcli, which command assigns a static IPv4 address to the connection named eth0 and disables DHCP?", options:["nmcli con up eth0 static","nmcli dev set eth0 dhcp off","nmcli con mod eth0 ipv4.addresses 192.168.1.10/24 ipv4.method manual","ip addr add 192.168.1.10/24 dev eth0"], answer:2, explain:"<strong>nmcli con mod eth0 ipv4.addresses 192.168.1.10/24 ipv4.method manual</strong> sets the static address and switches the method to manual, which disables DHCP for that connection persistently.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nmcli dev set eth0 dhcp off</b>: this is not valid nmcli syntax; DHCP is controlled by ipv4.method, not a dhcp toggle.</span><span class='qd'><b>nmcli con up eth0 static</b>: con up activates a connection; static is not a valid argument and no address is set.</span><span class='qd'><b>ip addr add 192.168.1.10/24 dev eth0</b>: this works only until reboot and does not persist or disable DHCP in NetworkManager.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-004", domain:1, obj:"1.5", diff:"medium", q:"Which command prints only the third colon-delimited field (the UID) of each line in /etc/passwd?", options:["grep ':' /etc/passwd","awk '{print $3}' /etc/passwd","cut -d: -f3 /etc/passwd","sed -n '3p' /etc/passwd"], answer:2, explain:"<strong>cut -d: -f3 /etc/passwd</strong> sets the delimiter to a colon and prints field 3, which is the UID column.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>grep ':' /etc/passwd</b>: grep filters lines containing a colon but prints whole lines, not a single field.</span><span class='qd'><b>awk '{print $3}' /etc/passwd</b>: without -F: awk splits on whitespace, so $3 is not the UID field in a colon-delimited file.</span><span class='qd'><b>sed -n '3p' /etc/passwd</b>: this prints the third line of the file, not the third field of each line.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-005", domain:1, obj:"1.6", diff:"medium", q:"An administrator wants to mirror /srv/www to a remote host while deleting files on the destination that no longer exist on the source. Which rsync command is correct?", options:["rsync -a /srv/www host:/backup/","rsync -z /srv/www host:/backup/","rsync -a --delete /srv/www/ host:/backup/","rsync --inplace /srv/www host:/backup/"], answer:2, explain:"<strong>rsync -a --delete /srv/www/ host:/backup/</strong> performs an archive-mode sync and the --delete flag removes destination files absent from the source, producing a true mirror.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rsync -a /srv/www host:/backup/</b>: without --delete, stale files on the destination are kept, so it is not a mirror.</span><span class='qd'><b>rsync -z /srv/www host:/backup/</b>: -z only enables compression and lacks recursion/preservation and --delete.</span><span class='qd'><b>rsync --inplace /srv/www host:/backup/</b>: --inplace changes how files are written but does not delete stale destination files.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-006", domain:1, obj:"1.7", diff:"medium", q:"Which qemu-img command creates a 40 GB thin-provisioned qcow2 disk image named vm.qcow2?", options:["qemu-img create -f raw vm.qcow2 40G","qemu-img convert vm.qcow2 40G","qemu-img create -f qcow2 vm.qcow2 40G","virsh vol-create vm.qcow2 40G"], answer:2, explain:"<strong>qemu-img create -f qcow2 vm.qcow2 40G</strong> creates a qcow2 image; qcow2 is sparse/thin-provisioned by default, so the file grows only as data is written.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>qemu-img create -f raw vm.qcow2 40G</b>: -f raw makes a raw image (not qcow2) and raw is typically fully allocated, not thin.</span><span class='qd'><b>qemu-img convert vm.qcow2 40G</b>: convert changes the format of an existing image and the syntax shown is invalid.</span><span class='qd'><b>virsh vol-create vm.qcow2 40G</b>: vol-create requires a pool and XML definition; this syntax is not valid.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-007", domain:1, obj:"1.2", diff:"medium", q:"A newly installed PCIe NIC is not working. Which command loads its kernel driver module by name immediately?", options:["insmod e1000e","lsmod e1000e","modprobe e1000e","modinfo e1000e"], answer:2, explain:"<strong>modprobe e1000e</strong> loads the named module and resolves its dependencies automatically, making the driver active.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>lsmod e1000e</b>: lsmod only lists currently loaded modules; it cannot load one and ignores arguments.</span><span class='qd'><b>insmod e1000e</b>: insmod requires a full path to a .ko file and does not resolve dependencies.</span><span class='qd'><b>modinfo e1000e</b>: modinfo only displays metadata about a module; it does not load it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-008", domain:1, obj:"1.3", diff:"medium", q:"In an /etc/fstab entry, which field number specifies the mount options such as defaults,noatime?", options:["The second field","The third field","The fourth field","The sixth field"], answer:2, explain:"<strong>The fourth field</strong> of an fstab line holds the mount options (for example defaults,noatime).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The second field</b>: the second field is the mount point, not the options.</span><span class='qd'><b>The third field</b>: the third field is the filesystem type (such as xfs or ext4).</span><span class='qd'><b>The sixth field</b>: the sixth field is the fsck pass number (the dump field is fifth), not the options.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-009", domain:1, obj:"1.4", diff:"easy", q:"Which dig command queries only the mail exchanger records for example.com?", options:["dig example.com A","dig -x example.com","dig example.com MX","dig example.com NS"], answer:2, explain:"<strong>dig example.com MX</strong> requests the MX (mail exchanger) records, which identify the mail servers for the domain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dig example.com A</b>: A records return IPv4 addresses, not mail exchanger information.</span><span class='qd'><b>dig -x example.com</b>: -x performs a reverse lookup of an IP and is invalid against a hostname.</span><span class='qd'><b>dig example.com NS</b>: NS records list the authoritative name servers, not the mail servers.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-010", domain:1, obj:"1.5", diff:"easy", q:"Which redirection sends both standard output and standard error of a command to the file log.txt?", options:["command > log.txt","command 2> log.txt","command &> log.txt","command | log.txt"], answer:2, explain:"<strong>command &> log.txt</strong> redirects both stdout and stderr to log.txt in Bash.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>command > log.txt</b>: this redirects only stdout; stderr still goes to the terminal.</span><span class='qd'><b>command 2> log.txt</b>: this redirects only stderr (file descriptor 2), leaving stdout on the terminal.</span><span class='qd'><b>command | log.txt</b>: a pipe sends output to another command, and log.txt is not a command.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-011", domain:1, obj:"1.1", diff:"medium", q:"Which file is the primary GRUB2 configuration source that an administrator edits before running grub2-mkconfig?", options:["/boot/grub2/grub.cfg","/etc/grub.conf","/etc/default/grub","/boot/efi/grub"], answer:2, explain:"<strong>/etc/default/grub</strong> holds the user-editable defaults (timeout, kernel cmdline) that grub2-mkconfig reads to generate the final grub.cfg.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/boot/grub2/grub.cfg</b>: this is the generated output and should not be edited by hand.</span><span class='qd'><b>/etc/grub.conf</b>: this was the legacy GRUB1 file and is not used by GRUB2.</span><span class='qd'><b>/boot/efi/grub</b>: this path is not the configuration source for grub2-mkconfig.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-012", domain:1, obj:"1.3", diff:"hard", q:"An administrator needs a software RAID 1 array from /dev/sdb and /dev/sdc. Which mdadm command creates it as /dev/md0?", options:["mdadm --level=5 /dev/md0 /dev/sdb /dev/sdc","mdadm --assemble /dev/md0 /dev/sdb /dev/sdc","mdadm --create /dev/md0 --level=1 --raid-devices=2 /dev/sdb /dev/sdc","mdadm --build /dev/md0 --raid-devices=1"], answer:2, explain:"<strong>mdadm --create /dev/md0 --level=1 --raid-devices=2 /dev/sdb /dev/sdc</strong> creates a new RAID 1 (mirror) array using both devices with proper metadata.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mdadm --assemble /dev/md0 /dev/sdb /dev/sdc</b>: --assemble reactivates an existing array; it does not create a new one.</span><span class='qd'><b>mdadm --level=5 /dev/md0 /dev/sdb /dev/sdc</b>: level 5 is not a mirror and needs at least three devices.</span><span class='qd'><b>mdadm --build /dev/md0 --raid-devices=1</b>: --build creates a legacy array without superblock and one device cannot form RAID 1.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-013", domain:1, obj:"1.4", diff:"medium", q:"On a Netplan-managed Ubuntu server, after editing /etc/netplan/01-netcfg.yaml, which command applies the new configuration?", options:["systemctl restart network","nmcli reload","netplan apply","ifup -a"], answer:2, explain:"<strong>netplan apply</strong> parses the YAML files and applies the resulting configuration through the active renderer (networkd or NetworkManager).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl restart network</b>: there is no network.service on Netplan systems; the unit name is different.</span><span class='qd'><b>nmcli reload</b>: nmcli reloads NetworkManager connection files, not Netplan YAML definitions.</span><span class='qd'><b>ifup -a</b>: ifup is part of the legacy ifupdown stack, which Netplan replaces.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-014", domain:1, obj:"1.5", diff:"medium", q:"Which sed command replaces every occurrence of the word http with https on each line of urls.txt and prints the result?", options:["sed 's/http/https/' urls.txt","sed -n '/http/p' urls.txt","sed 's/http/https/g' urls.txt","sed 'g/http/https' urls.txt"], answer:2, explain:"<strong>sed 's/http/https/g' urls.txt</strong> substitutes http with https globally on every line; the trailing g flag handles multiple matches per line.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sed 's/http/https/' urls.txt</b>: without g it replaces only the first match on each line.</span><span class='qd'><b>sed -n '/http/p' urls.txt</b>: this only prints lines containing http; it performs no substitution.</span><span class='qd'><b>sed 'g/http/https' urls.txt</b>: this is invalid sed syntax and would produce an error.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-015", domain:1, obj:"1.6", diff:"easy", q:"Which tar command extracts the gzip-compressed archive backup.tar.gz into the current directory?", options:["tar -czf backup.tar.gz","tar -tf backup.tar.gz","tar -xzf backup.tar.gz","tar -cf backup.tar.gz"], answer:2, explain:"<strong>tar -xzf backup.tar.gz</strong> extracts (-x), decompresses gzip (-z), and reads the named file (-f).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tar -czf backup.tar.gz</b>: -c creates a new archive rather than extracting one.</span><span class='qd'><b>tar -tf backup.tar.gz</b>: -t only lists the contents and does not extract files.</span><span class='qd'><b>tar -cf backup.tar.gz</b>: -c creates an archive and omits the gzip flag for this compressed file.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-016", domain:1, obj:"1.7", diff:"medium", q:"Which virsh command lists all virtual machines, including those that are currently powered off?", options:["virsh list","virsh dominfo","virsh list --all","virsh domstate"], answer:2, explain:"<strong>virsh list --all</strong> shows every defined domain regardless of state, including shut-off VMs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>virsh list</b>: without --all it shows only running domains.</span><span class='qd'><b>virsh dominfo</b>: dominfo reports details about a single named domain, not a full list.</span><span class='qd'><b>virsh domstate</b>: domstate returns the state of one named domain, not a list of all VMs.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-017", domain:1, obj:"1.3", diff:"medium", q:"Which command displays a tree of block devices showing disks, partitions, and their mount points?", options:["df -h","blkid","lsblk","fdisk -l"], answer:2, explain:"<strong>lsblk</strong> lists block devices in a tree format with their sizes, types, and mount points.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>df -h</b>: df shows mounted filesystem usage, not the full block-device tree including unmounted partitions.</span><span class='qd'><b>blkid</b>: blkid prints UUIDs and filesystem types but not a hierarchical device tree with mount points.</span><span class='qd'><b>fdisk -l</b>: fdisk -l lists partition tables but does not show mount points or a clean tree view.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-018", domain:1, obj:"1.4", diff:"medium", q:"A server can ping IP addresses but cannot resolve hostnames. Which file should the administrator check first?", options:["/etc/hosts.allow","/etc/nsswitch.deny","/etc/resolv.conf","/etc/network/dns"], answer:2, explain:"<strong>/etc/resolv.conf</strong> defines the DNS nameservers the resolver uses; a missing or wrong nameserver entry explains working IP connectivity but failing name resolution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/hosts.allow</b>: this controls TCP wrapper access rules, not DNS resolution.</span><span class='qd'><b>/etc/nsswitch.deny</b>: this file does not exist; the relevant file is /etc/nsswitch.conf for lookup order.</span><span class='qd'><b>/etc/network/dns</b>: this is not a standard Linux file for resolver configuration.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-019", domain:1, obj:"1.5", diff:"easy", q:"Which shell construct exports a variable named API_KEY so that child processes inherit it?", options:["set API_KEY=abc123","API_KEY==abc123","export API_KEY=abc123","local API_KEY=abc123"], answer:2, explain:"<strong>export API_KEY=abc123</strong> marks the variable for export so that child processes spawned by the shell inherit it in their environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>set API_KEY=abc123</b>: set in Bash manipulates shell options/positional parameters, not exported environment variables.</span><span class='qd'><b>API_KEY==abc123</b>: the double equals is a syntax error for assignment.</span><span class='qd'><b>local API_KEY=abc123</b>: local restricts a variable to a function scope and is not exported.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-020", domain:1, obj:"1.1", diff:"medium", q:"Per the Filesystem Hierarchy Standard, where should an administrator place a third-party application installed manually from source under /usr/local conventions?", options:["/bin","/var/run","/usr/local","/etc/opt"], answer:2, explain:"<strong>/usr/local</strong> is reserved by the FHS for software the local administrator installs, keeping it separate from distribution-managed files in /usr.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/bin</b>: /bin holds essential system binaries needed in single-user mode, not locally compiled apps.</span><span class='qd'><b>/var/run</b>: /var/run (now /run) stores runtime data like PID files, not installed programs.</span><span class='qd'><b>/etc/opt</b>: /etc/opt stores configuration for add-on packages in /opt, not the programs themselves.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-021", domain:1, obj:"1.3", diff:"hard", q:"After running lvextend -L +10G /dev/vg0/lvdata on an XFS filesystem, the mounted size is unchanged. What is the missing step?", options:["resize2fs /dev/vg0/lvdata","mkfs.xfs /dev/vg0/lvdata","xfs_growfs /data","umount and fsck"], answer:2, explain:"<strong>xfs_growfs /data</strong> grows the XFS filesystem online to fill the now-larger logical volume; lvextend only enlarges the LV, not the filesystem.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>resize2fs /dev/vg0/lvdata</b>: resize2fs works on ext2/3/4, not XFS, and would fail here.</span><span class='qd'><b>mkfs.xfs /dev/vg0/lvdata</b>: mkfs would reformat and destroy all existing data.</span><span class='qd'><b>umount and fsck</b>: XFS grows while mounted; unmounting and fsck do not change the filesystem size.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-022", domain:1, obj:"1.4", diff:"medium", q:"Which ip command shows the kernel routing table including the default gateway?", options:["ip addr show","ip link show","ip route show","ip neigh show"], answer:2, explain:"<strong>ip route show</strong> displays the routing table, including the default route and its gateway.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ip addr show</b>: this lists IP addresses assigned to interfaces, not routes.</span><span class='qd'><b>ip link show</b>: this shows link-layer interface state, not routing entries.</span><span class='qd'><b>ip neigh show</b>: this displays the ARP/neighbor cache, not the routing table.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-023", domain:1, obj:"1.5", diff:"medium", q:"In vim, which command-mode entry saves the current file and quits the editor?", options:[":q!",":x!",":w",":wq"], answer:3, explain:"<strong>:wq</strong> writes (saves) the file and then quits vim.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>:q!</b>: this quits without saving and discards changes.</span><span class='qd'><b>:w</b>: this saves the file but does not quit.</span><span class='qd'><b>:x!</b>: the exclamation is not valid with :x; :x alone saves and quits but only writes if changes exist.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-024", domain:1, obj:"1.6", diff:"medium", q:"An administrator must clone an entire 100 GB disk /dev/sda to /dev/sdb block-for-block. Which command is appropriate?", options:["cp /dev/sda /dev/sdb","tar -cf /dev/sdb /dev/sda","rsync /dev/sda /dev/sdb","dd if=/dev/sda of=/dev/sdb bs=4M status=progress"], answer:3, explain:"<strong>dd if=/dev/sda of=/dev/sdb bs=4M status=progress</strong> copies the disk block-for-block, including partition table and filesystems, with a sensible block size and progress output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cp /dev/sda /dev/sdb</b>: cp is not designed for raw block copying of whole disks and may not duplicate structures correctly.</span><span class='qd'><b>rsync /dev/sda /dev/sdb</b>: rsync syncs files, not raw block devices, so it cannot clone a disk.</span><span class='qd'><b>tar -cf /dev/sdb /dev/sda</b>: tar archives files and would not produce a usable cloned disk.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-025", domain:1, obj:"1.7", diff:"medium", q:"Which paravirtualized driver type should be used for VM disks and NICs under KVM to maximize I/O performance?", options:["IDE","e1000","SATA","VirtIO"], answer:3, explain:"<strong>VirtIO</strong> drivers are paravirtualized and communicate efficiently with the KVM hypervisor, giving far better disk and network throughput than emulated hardware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>IDE</b>: IDE is fully emulated legacy hardware with poor performance compared to VirtIO.</span><span class='qd'><b>SATA</b>: emulated SATA is faster than IDE but still slower than paravirtualized VirtIO.</span><span class='qd'><b>e1000</b>: e1000 is an emulated NIC; the virtio-net driver outperforms it for virtualized workloads.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-026", domain:1, obj:"1.1", diff:"easy", q:"Which package format and primary package manager are native to Red Hat Enterprise Linux and its derivatives?", options:["DEB packages with apt","TAR packages with pacman","Snap packages with snapd","RPM packages with dnf"], answer:3, explain:"<strong>RPM packages with dnf</strong> are native to RHEL, Fedora, and derivatives; dnf is the modern front end to the RPM system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DEB packages with apt</b>: DEB and apt are native to Debian and Ubuntu, not RHEL.</span><span class='qd'><b>Snap packages with snapd</b>: Snap is a universal package format, not the native RPM system of RHEL.</span><span class='qd'><b>TAR packages with pacman</b>: pacman is the Arch Linux manager, and RHEL does not use it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-027", domain:1, obj:"1.3", diff:"medium", q:"An administrator wants to mount an NFS export server:/exports/data at /mnt/data automatically at boot. Which fstab type field is correct?", options:["xfs","ext4","cifs","nfs"], answer:3, explain:"<strong>nfs</strong> is the correct filesystem type in fstab for mounting an NFS export so it is mounted at boot via the NFS client.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>xfs</b>: xfs is a local on-disk filesystem and cannot mount a remote NFS export.</span><span class='qd'><b>cifs</b>: cifs is for SMB/Windows shares, not NFS exports.</span><span class='qd'><b>ext4</b>: ext4 is a local filesystem type and does not apply to network mounts.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-028", domain:1, obj:"1.4", diff:"medium", q:"Which command shows all listening TCP ports along with the owning process, using the modern replacement for netstat?", options:["traceroute -T","arp -a","ss -tlnp","route -n"], answer:2, explain:"<strong>ss -tlnp</strong> lists TCP (-t) listening (-l) sockets numerically (-n) with the process (-p), replacing the older netstat tool.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>arp -a</b>: arp displays the neighbor/MAC cache, not listening ports.</span><span class='qd'><b>traceroute -T</b>: traceroute maps the path to a host and does not list local ports.</span><span class='qd'><b>route -n</b>: route shows the routing table, not socket or port state.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-029", domain:1, obj:"1.5", diff:"medium", q:"Which awk command prints lines from access.log where the ninth field (HTTP status) equals 404?", options:["awk '{print 404}' access.log","awk '/404/' access.log","awk '$9==404' access.log","awk -F404 access.log"], answer:2, explain:"<strong>awk '$9==404' access.log</strong> evaluates the ninth whitespace-delimited field and prints the line only when it equals 404.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>awk '/404/' access.log</b>: this matches 404 anywhere in the line, including URLs and byte counts, not just the status field.</span><span class='qd'><b>awk '{print 404}' access.log</b>: this prints the literal number 404 for every line rather than filtering.</span><span class='qd'><b>awk -F404 access.log</b>: -F sets the field separator to 404 and provides no program, so it does not filter by status.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-030", domain:1, obj:"1.6", diff:"hard", q:"A backup strategy performs a full backup Sunday and on each weekday backs up only files changed since the previous day. What backup type are the weekday jobs?", options:["Full","Synthetic","Differential","Incremental"], answer:3, explain:"<strong>Incremental</strong> backups capture only data changed since the previous backup (full or incremental), which matches backing up changes since the prior day.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Full</b>: a full backup copies everything each time, not just the prior day changes.</span><span class='qd'><b>Differential</b>: a differential backs up all changes since the last full backup, not just since the previous day.</span><span class='qd'><b>Synthetic</b>: a synthetic backup is assembled from existing fulls and increments, not a daily change capture.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-031", domain:1, obj:"1.7", diff:"medium", q:"Which file format is used by libvirt to define a virtual machine domain such as CPU, memory, and disks?", options:["INI","JSON","YAML","XML"], answer:3, explain:"<strong>XML</strong> is the format libvirt uses for domain definitions, edited via virsh edit and applied to a VM.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>INI</b>: libvirt does not store domain definitions in INI format.</span><span class='qd'><b>YAML</b>: YAML is used by tools like cloud-init and Netplan, not libvirt domain XML.</span><span class='qd'><b>JSON</b>: while QEMU uses JSON for some interfaces, libvirt domain definitions are XML.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-032", domain:1, obj:"1.3", diff:"medium", q:"Which command generates the persistent UUID-based fstab reference for a formatted XFS partition?", options:["lsblk -f","du -sh /dev/sdb1","df -i","blkid /dev/sdb1"], answer:3, explain:"<strong>blkid /dev/sdb1</strong> prints the UUID and filesystem type of the partition, which is the value typically used in fstab for stable device references.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>lsblk -f</b>: lsblk -f shows filesystem info and UUIDs in a tree, but blkid is the direct tool for a single device UUID; here lsblk -f is acceptable visually yet the canonical UUID source is blkid.</span><span class='qd'><b>df -i</b>: df -i reports inode usage of mounted filesystems, not UUIDs.</span><span class='qd'><b>du -sh /dev/sdb1</b>: du measures directory size and does not report a partition UUID.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-033", domain:1, obj:"1.4", diff:"easy", q:"Which command tests reachability and round-trip time to the host 10.0.0.1 by sending ICMP echo requests?", options:["ss 10.0.0.1","dig 10.0.0.1","nmcli 10.0.0.1","ping 10.0.0.1"], answer:3, explain:"<strong>ping 10.0.0.1</strong> sends ICMP echo requests and reports reachability and round-trip latency.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dig 10.0.0.1</b>: dig performs DNS queries, not ICMP reachability tests.</span><span class='qd'><b>nmcli 10.0.0.1</b>: nmcli manages NetworkManager connections and does not ping a host.</span><span class='qd'><b>ss 10.0.0.1</b>: ss inspects local sockets and does not test remote reachability.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-034", domain:1, obj:"1.5", diff:"medium", q:"Which command counts the number of lines in a file named report.txt?", options:["wc -c report.txt","grep -c report.txt","wc -w report.txt","wc -l report.txt"], answer:3, explain:"<strong>wc -l report.txt</strong> prints the line count of the file.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>wc -c report.txt</b>: -c counts bytes, not lines.</span><span class='qd'><b>wc -w report.txt</b>: -w counts words, not lines.</span><span class='qd'><b>grep -c report.txt</b>: grep -c with only a filename treats report.txt as the pattern and has no file to search.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-035", domain:1, obj:"1.1", diff:"hard", q:"A GRUB2 menu does not appear and the system boots directly to the default entry. Which /etc/default/grub setting most likely causes the menu to be hidden, and should be changed?", options:["GRUB_DEFAULT=0","GRUB_CMDLINE_LINUX=quiet","GRUB_DISABLE_OS_PROBER=true","GRUB_TIMEOUT=0"], answer:3, explain:"<strong>GRUB_TIMEOUT=0</strong> makes GRUB boot the default entry immediately without displaying the menu; raising the timeout restores the menu.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GRUB_DEFAULT=0</b>: this only selects which entry is default; it does not hide the menu.</span><span class='qd'><b>GRUB_DISABLE_OS_PROBER=true</b>: this only stops detecting other operating systems and does not hide the menu.</span><span class='qd'><b>GRUB_CMDLINE_LINUX=quiet</b>: this passes kernel boot parameters and does not control menu visibility.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-036", domain:1, obj:"1.3", diff:"medium", q:"Which command formats a partition /dev/sdb1 with the ext4 filesystem?", options:["tune2fs /dev/sdb1","mke2fs.xfs /dev/sdb1","mkswap /dev/sdb1","mkfs.ext4 /dev/sdb1"], answer:3, explain:"<strong>mkfs.ext4 /dev/sdb1</strong> creates an ext4 filesystem on the partition.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mke2fs.xfs /dev/sdb1</b>: this command does not exist; XFS uses mkfs.xfs and ext uses mke2fs/mkfs.ext4.</span><span class='qd'><b>mkswap /dev/sdb1</b>: mkswap prepares a swap area, not an ext4 filesystem.</span><span class='qd'><b>tune2fs /dev/sdb1</b>: tune2fs adjusts parameters of an existing ext filesystem; it does not create one.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-037", domain:1, obj:"1.4", diff:"medium", q:"Which nmcli command displays the active connections and their associated devices?", options:["nmcli dev disconnect","nmcli radio all","nmcli general status","nmcli con show --active"], answer:3, explain:"<strong>nmcli con show --active</strong> lists the currently active connection profiles and the devices they are bound to.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nmcli radio all</b>: this shows the state of WiFi and WWAN radios, not active connections.</span><span class='qd'><b>nmcli general status</b>: this gives an overall NetworkManager summary, not a per-connection device list.</span><span class='qd'><b>nmcli dev disconnect</b>: this disconnects a device rather than displaying active connections.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-038", domain:1, obj:"1.5", diff:"easy", q:"Which command searches recursively through /var/log for lines containing the word error, case-insensitively?", options:["cat /var/log | error","grep error /var/log","find /var/log error","grep -ri error /var/log"], answer:3, explain:"<strong>grep -ri error /var/log</strong> recursively (-r) and case-insensitively (-i) searches all files under the directory for error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>grep error /var/log</b>: without -r, grep cannot search a directory and reports an error.</span><span class='qd'><b>find /var/log error</b>: find searches by filename attributes, not file contents.</span><span class='qd'><b>cat /var/log | error</b>: cat cannot read a directory and error is not a command.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-039", domain:1, obj:"1.6", diff:"medium", q:"Which compression tool generally produces the smallest archive at the cost of the most CPU time and is invoked with tar -cJf?", options:["gzip","bzip2","xz","lz4"], answer:2, explain:"<strong>xz</strong> typically yields the highest compression ratio (smallest files) but uses the most CPU; tar -cJf selects xz compression.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>gzip</b>: gzip (tar -czf) is fast but compresses less than xz.</span><span class='qd'><b>bzip2</b>: bzip2 (tar -cjf) compresses better than gzip but generally less than xz.</span><span class='qd'><b>lz4</b>: lz4 is optimized for speed with a low compression ratio, the opposite of xz.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-040", domain:1, obj:"1.7", diff:"hard", q:"An administrator must reduce a 50 GB qcow2 image to reclaim unused space after deleting data inside the guest. Which approach reclaims host space?", options:["qemu-img resize vm.qcow2 +0","dd if=/dev/zero of=vm.qcow2","virsh start vm","qemu-img convert -O qcow2 vm.qcow2 vm-new.qcow2"], answer:3, explain:"<strong>qemu-img convert -O qcow2 vm.qcow2 vm-new.qcow2</strong> rewrites the image, dropping unreferenced clusters and producing a smaller compacted file on the host.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>qemu-img resize vm.qcow2 +0</b>: resize changes the virtual size and +0 does nothing; it does not compact the file.</span><span class='qd'><b>virsh start vm</b>: starting the VM does not shrink the qcow2 file on disk.</span><span class='qd'><b>dd if=/dev/zero of=vm.qcow2</b>: this overwrites the image with zeros and destroys the disk.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-041", domain:1, obj:"1.2", diff:"medium", q:"Which command lists all PCI devices on the system, useful for identifying hardware that needs a driver?", options:["lsusb","lsblk","lscpu","lspci"], answer:3, explain:"<strong>lspci</strong> enumerates devices on the PCI bus, helping identify network cards, GPUs, and controllers and their kernel drivers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>lsusb</b>: lsusb lists USB devices, not PCI devices.</span><span class='qd'><b>lscpu</b>: lscpu reports CPU architecture details, not PCI hardware.</span><span class='qd'><b>lsblk</b>: lsblk lists block storage devices, not the PCI bus.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-042", domain:1, obj:"1.3", diff:"medium", q:"An administrator must persist a kernel module blacklist so a driver does not load at boot. Where should the blacklist line be placed?", options:["/etc/fstab","/boot/grub2/grub.cfg","/etc/sysctl.conf","/etc/modprobe.d/blacklist.conf"], answer:3, explain:"<strong>/etc/modprobe.d/blacklist.conf</strong> is read by modprobe and the proper location for blacklist directives that prevent a module from auto-loading.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/fstab</b>: fstab defines filesystem mounts, not module loading behavior.</span><span class='qd'><b>/etc/sysctl.conf</b>: sysctl.conf sets kernel runtime parameters, not module blacklists.</span><span class='qd'><b>/boot/grub2/grub.cfg</b>: this is the generated GRUB config and is not the proper place for modprobe blacklists.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-043", domain:1, obj:"1.4", diff:"medium", q:"Which command traces the network path and intermediate hops between the local host and example.com?", options:["tcpdump example.com","ifconfig example.com","hostnamectl example.com","traceroute example.com"], answer:3, explain:"<strong>traceroute example.com</strong> reveals each router hop along the path to the destination and the latency at each hop.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ifconfig example.com</b>: ifconfig configures or shows interfaces and does not trace a path.</span><span class='qd'><b>hostnamectl example.com</b>: hostnamectl manages the system hostname, unrelated to path tracing.</span><span class='qd'><b>tcpdump example.com</b>: tcpdump captures packets on an interface; it does not enumerate hops by itself.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-044", domain:1, obj:"1.5", diff:"medium", q:"Which command appends the output of a command to an existing file without overwriting it?", options:["command > file","command 2> file","command < file","command >> file"], answer:3, explain:"<strong>command >> file</strong> appends stdout to the file, preserving existing contents.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>command > file</b>: a single > truncates the file and overwrites its contents.</span><span class='qd'><b>command < file</b>: this redirects the file as input to the command, not output to the file.</span><span class='qd'><b>command 2> file</b>: this redirects stderr to the file and truncates it, not append stdout.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-045", domain:1, obj:"1.1", diff:"easy", q:"Which directory in the FHS holds variable data such as logs, spool files, and caches?", options:["/etc","/boot","/usr","/var"], answer:3, explain:"<strong>/var</strong> contains variable data including /var/log, /var/spool, and caches that change during normal operation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc</b>: /etc holds system configuration files, not variable runtime data.</span><span class='qd'><b>/usr</b>: /usr holds read-only user programs and libraries, not changing data.</span><span class='qd'><b>/boot</b>: /boot stores kernel and bootloader files, not logs or spools.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-046", domain:1, obj:"1.3", diff:"hard", q:"A volume group vg0 shows 0 free extents and the administrator needs to grow lvdata. Which command both adds capacity and is the prerequisite to lvextend?", options:["lvextend -l +100%FREE /dev/vg0/lvdata","vgreduce vg0 /dev/sdc1","pvremove /dev/sdd1","vgextend vg0 /dev/sdd1"], answer:3, explain:"<strong>vgextend vg0 /dev/sdd1</strong> adds a new physical volume to the volume group, providing free extents that lvextend can then allocate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>lvextend -l +100%FREE /dev/vg0/lvdata</b>: with 0 free extents there is nothing to allocate until the VG is extended first.</span><span class='qd'><b>pvremove /dev/sdd1</b>: pvremove destroys PV metadata and removes capacity rather than adding it.</span><span class='qd'><b>vgreduce vg0 /dev/sdc1</b>: vgreduce removes a PV from the VG, shrinking available space.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-047", domain:1, obj:"1.4", diff:"medium", q:"Which file maps static hostname-to-IP entries that are consulted before DNS when nsswitch lists files first?", options:["/etc/hosts","/etc/hostname","/etc/resolv.conf","/etc/networks"], answer:0, explain:"<strong>/etc/hosts</strong> provides static hostname-to-IP mappings consulted by the resolver before DNS when nsswitch.conf lists files first for hosts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/hostname</b>: this stores the local system hostname, not mapping entries.</span><span class='qd'><b>/etc/resolv.conf</b>: this lists DNS servers and search domains, not static host mappings.</span><span class='qd'><b>/etc/networks</b>: this maps network names to network numbers, not host-to-IP entries.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-048", domain:1, obj:"1.5", diff:"medium", q:"Which command pipes the output of ps aux into grep to show only processes containing the string nginx?", options:["ps aux > grep nginx","grep nginx < ps aux","ps aux & grep nginx","ps aux | grep nginx"], answer:3, explain:"<strong>ps aux | grep nginx</strong> uses a pipe to feed the process list into grep, which filters lines containing nginx.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ps aux > grep nginx</b>: this redirects output into a file literally named grep, not into the grep command.</span><span class='qd'><b>ps aux & grep nginx</b>: the & backgrounds ps and runs grep with no input from it.</span><span class='qd'><b>grep nginx < ps aux</b>: this tries to read a file named ps with argument aux, which is invalid here.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-049", domain:1, obj:"1.6", diff:"medium", q:"Which command creates a gzip-compressed tar archive of /etc named etc-backup.tar.gz while preserving permissions?", options:["tar -xzf etc-backup.tar.gz /etc","tar -tf etc-backup.tar.gz /etc","gzip -r /etc","tar -czpf etc-backup.tar.gz /etc"], answer:3, explain:"<strong>tar -czpf etc-backup.tar.gz /etc</strong> creates (-c) a gzip (-z) archive (-f) of /etc and preserves permissions (-p).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tar -xzf etc-backup.tar.gz /etc</b>: -x extracts rather than creates an archive.</span><span class='qd'><b>gzip -r /etc</b>: gzip -r compresses individual files in place; it does not create a single archive.</span><span class='qd'><b>tar -tf etc-backup.tar.gz /etc</b>: -t lists contents and does not create the archive.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-050", domain:1, obj:"1.7", diff:"medium", q:"Which command gracefully shuts down a running libvirt VM named web01 by sending an ACPI signal to the guest?", options:["virsh destroy web01","virsh suspend web01","virsh undefine web01","virsh shutdown web01"], answer:3, explain:"<strong>virsh shutdown web01</strong> sends an ACPI shutdown request so the guest OS powers off cleanly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>virsh destroy web01</b>: destroy forcibly terminates the VM like pulling power, risking data loss.</span><span class='qd'><b>virsh undefine web01</b>: undefine removes the VM definition but does not shut down a running guest.</span><span class='qd'><b>virsh suspend web01</b>: suspend pauses the VM in memory rather than shutting it down.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-051", domain:1, obj:"1.3", diff:"medium", q:"After editing /etc/fstab to add a new mount, which command mounts all entries to verify there are no errors without rebooting?", options:["mount -a","mount -o remount","umount -a","systemctl daemon-reload"], answer:0, explain:"<strong>mount -a</strong> attempts to mount all filesystems listed in fstab (that are not noauto), letting the administrator catch syntax or device errors immediately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mount -o remount</b>: remount changes options on an already mounted filesystem and needs a target; it does not process all of fstab.</span><span class='qd'><b>umount -a</b>: this unmounts filesystems rather than mounting new fstab entries.</span><span class='qd'><b>systemctl daemon-reload</b>: this reloads systemd units; it does not directly mount fstab entries for verification.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-052", domain:1, obj:"1.4", diff:"medium", q:"Which sysctl parameter must be set to 1 to enable IPv4 packet forwarding so a Linux host can route between networks?", options:["net.ipv4.tcp_syncookies","net.ipv4.icmp_echo_ignore_all","net.core.somaxconn","net.ipv4.ip_forward"], answer:3, explain:"<strong>net.ipv4.ip_forward</strong> set to 1 enables the kernel to forward IPv4 packets between interfaces, which is required for routing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>net.ipv4.tcp_syncookies</b>: this mitigates SYN flood attacks and does not enable forwarding.</span><span class='qd'><b>net.core.somaxconn</b>: this sets the maximum socket listen backlog, unrelated to routing.</span><span class='qd'><b>net.ipv4.icmp_echo_ignore_all</b>: this controls whether the host replies to pings, not packet forwarding.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-053", domain:1, obj:"1.5", diff:"hard", q:"Which command sequence stores the count of .conf files in /etc into a variable named n using command substitution?", options:["n=$(ls /etc/*.conf | wc -l)","n=`wc -l /etc/*.conf`","n==count /etc/*.conf","set n ls /etc/*.conf"], answer:0, explain:"<strong>n=$(ls /etc/*.conf | wc -l)</strong> uses command substitution to capture the line count of matching files into the variable n.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>n=`wc -l /etc/*.conf`</b>: wc -l on multiple files counts lines inside each file, not the number of files, and prints a total line plus per-file counts.</span><span class='qd'><b>n==count /etc/*.conf</b>: == is a comparison operator and count is not a command, so this fails.</span><span class='qd'><b>set n ls /etc/*.conf</b>: set assigns positional parameters and does not run ls into a variable.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-054", domain:1, obj:"1.1", diff:"medium", q:"On a Debian or Ubuntu system, which command updates the local package index from the configured repositories?", options:["apt upgrade","apt update","dpkg -i","apt autoremove"], answer:1, explain:"<strong>apt update</strong> refreshes the local package index so apt knows about available package versions before installing or upgrading.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>apt upgrade</b>: upgrade installs newer versions of installed packages but relies on an already-updated index.</span><span class='qd'><b>dpkg -i</b>: dpkg -i installs a local .deb file and does not refresh repository indexes.</span><span class='qd'><b>apt autoremove</b>: autoremove deletes orphaned dependencies, not index updates.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-055", domain:1, obj:"1.3", diff:"medium", q:"Which command activates all swap devices and files listed in /etc/fstab?", options:["swapon -a","mkswap -a","free -m","swapoff -a"], answer:0, explain:"<strong>swapon -a</strong> enables all swap entries defined in /etc/fstab.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mkswap -a</b>: mkswap formats a device as swap and does not take -a to activate fstab entries.</span><span class='qd'><b>free -m</b>: free reports memory and swap usage but does not activate swap.</span><span class='qd'><b>swapoff -a</b>: swapoff -a disables swap rather than activating it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-056", domain:1, obj:"1.4", diff:"medium", q:"Which command queries a specific DNS server 8.8.8.8 for the A record of host.example.com using dig?", options:["dig host.example.com @8.8.8.8","dig 8.8.8.8 host.example.com","dig -s 8.8.8.8 host.example.com","dig host.example.com server=8.8.8.8"], answer:0, explain:"<strong>dig host.example.com @8.8.8.8</strong> directs the query to the server specified after the @ symbol.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dig 8.8.8.8 host.example.com</b>: this treats 8.8.8.8 as the name to look up, not the server.</span><span class='qd'><b>dig -s 8.8.8.8 host.example.com</b>: dig has no -s flag for server selection; the @ syntax is used.</span><span class='qd'><b>dig host.example.com server=8.8.8.8</b>: server= is not valid dig command-line syntax.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-057", domain:1, obj:"1.5", diff:"easy", q:"Which command displays the value of the PATH environment variable in the current shell?", options:["echo $PATH","cat PATH","export PATH","set PATH"], answer:0, explain:"<strong>echo $PATH</strong> expands the PATH variable and prints its value.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cat PATH</b>: cat tries to read a file named PATH and does not expand the variable.</span><span class='qd'><b>export PATH</b>: export marks PATH for export but does not print its value.</span><span class='qd'><b>set PATH</b>: set lists all shell variables or sets options; it does not cleanly print PATH alone.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-058", domain:1, obj:"1.6", diff:"medium", q:"Which rsync option preserves symbolic links, permissions, timestamps, and ownership in a single combined flag?", options:["-z","-a","-v","-n"], answer:1, explain:"<strong>-a</strong> (archive mode) is a combined flag that preserves symlinks, permissions, timestamps, ownership, and recurses into directories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>-z</b>: -z only enables compression during transfer.</span><span class='qd'><b>-v</b>: -v only increases verbosity of the output.</span><span class='qd'><b>-n</b>: -n performs a dry run without preserving anything or transferring files.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-059", domain:1, obj:"1.7", diff:"hard", q:"An administrator must convert a VMware vmdk disk to qcow2 for use under KVM. Which command performs the conversion?", options:["qemu-img info disk.vmdk","qemu-img convert -O qcow2 disk.vmdk disk.qcow2","virsh attach-disk disk.vmdk","qemu-img create -f qcow2 disk.vmdk"], answer:1, explain:"<strong>qemu-img convert -O qcow2 disk.vmdk disk.qcow2</strong> reads the VMDK source and writes a qcow2 output image suitable for KVM.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>qemu-img info disk.vmdk</b>: info only reports metadata about the image and performs no conversion.</span><span class='qd'><b>virsh attach-disk disk.vmdk</b>: attach-disk connects a disk to a domain but does not convert formats.</span><span class='qd'><b>qemu-img create -f qcow2 disk.vmdk</b>: create makes a new empty image and would not convert existing data.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-060", domain:1, obj:"1.2", diff:"medium", q:"Which command shows detailed information about the kernel module ext4, including its parameters and dependencies?", options:["modprobe ext4","modinfo ext4","rmmod ext4","depmod ext4"], answer:1, explain:"<strong>modinfo ext4</strong> prints module metadata such as description, version, parameters, and dependencies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>modprobe ext4</b>: modprobe loads the module; it does not display its detailed metadata.</span><span class='qd'><b>rmmod ext4</b>: rmmod unloads a module and shows no information.</span><span class='qd'><b>depmod ext4</b>: depmod rebuilds module dependency maps rather than showing one module's info.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-061", domain:1, obj:"1.3", diff:"medium", q:"Which command checks and repairs an unmounted ext4 filesystem on /dev/sdb1?", options:["fsck.ext4 /dev/sdb1","xfs_repair /dev/sdb1","mkfs.ext4 /dev/sdb1","mount /dev/sdb1"], answer:0, explain:"<strong>fsck.ext4 /dev/sdb1</strong> checks and repairs an ext4 filesystem that should be unmounted before running.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>xfs_repair /dev/sdb1</b>: xfs_repair is for XFS filesystems, not ext4.</span><span class='qd'><b>mkfs.ext4 /dev/sdb1</b>: mkfs reformats and destroys data rather than repairing.</span><span class='qd'><b>mount /dev/sdb1</b>: mounting a corrupt filesystem can worsen damage and does not repair it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-062", domain:1, obj:"1.4", diff:"easy", q:"Which command brings the interface eth0 administratively up using the iproute2 suite?", options:["ifconfig eth0 up","ip link set eth0 up","nmcli eth0 up","ip addr eth0 enable"], answer:1, explain:"<strong>ip link set eth0 up</strong> changes the link state of eth0 to up using iproute2.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ifconfig eth0 up</b>: ifconfig is the deprecated net-tools command, not the iproute2 suite.</span><span class='qd'><b>nmcli eth0 up</b>: nmcli activates a connection profile, not a raw link, and the syntax is incomplete.</span><span class='qd'><b>ip addr eth0 enable</b>: ip addr manages addresses, and enable is not valid syntax.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-063", domain:1, obj:"1.5", diff:"medium", q:"Which command displays only lines 10 through 20 of a file named data.log?", options:["head -20 data.log","sed -n '10,20p' data.log","tail -10 data.log","cut -c10-20 data.log"], answer:1, explain:"<strong>sed -n '10,20p' data.log</strong> suppresses default output and prints only lines 10 through 20.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>head -20 data.log</b>: head shows the first 20 lines starting at line 1, not lines 10 through 20.</span><span class='qd'><b>tail -10 data.log</b>: tail shows the last 10 lines, not a specific middle range.</span><span class='qd'><b>cut -c10-20 data.log</b>: cut -c selects character columns 10-20 of every line, not a range of lines.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-064", domain:1, obj:"1.1", diff:"hard", q:"A system using systemd-boot rather than GRUB needs a new kernel boot entry. In which directory are systemd-boot loader entries defined?", options:["/etc/grub.d","/boot/loader/entries","/etc/systemd/system","/boot/grub2"], answer:1, explain:"<strong>/boot/loader/entries</strong> holds the .conf files that define each boot entry for systemd-boot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/grub.d</b>: this directory contains GRUB2 generator scripts, not systemd-boot entries.</span><span class='qd'><b>/etc/systemd/system</b>: this holds systemd unit files for services, not boot loader entries.</span><span class='qd'><b>/boot/grub2</b>: this is the GRUB2 configuration directory, unrelated to systemd-boot.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-065", domain:1, obj:"1.3", diff:"medium", q:"Which mount option in fstab makes a filesystem mount as read-only?", options:["rw","ro","noexec","sync"], answer:1, explain:"<strong>ro</strong> mounts the filesystem read-only, preventing any writes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rw</b>: rw mounts the filesystem read-write, the opposite of read-only.</span><span class='qd'><b>noexec</b>: noexec blocks execution of binaries but still allows writes.</span><span class='qd'><b>sync</b>: sync forces synchronous I/O but does not make the mount read-only.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-066", domain:1, obj:"1.4", diff:"medium", q:"Which command captures packets on interface eth0 and writes them to a file for later analysis?", options:["tcpdump -i eth0 -w capture.pcap","ss -i eth0 -w capture.pcap","ping -i eth0 capture.pcap","ip monitor eth0"], answer:0, explain:"<strong>tcpdump -i eth0 -w capture.pcap</strong> captures traffic on eth0 and writes raw packets to a pcap file for tools like Wireshark.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ss -i eth0 -w capture.pcap</b>: ss inspects sockets and cannot write packet captures.</span><span class='qd'><b>ping -i eth0 capture.pcap</b>: ping -i sets the interval and ping does not capture packets to a file.</span><span class='qd'><b>ip monitor eth0</b>: ip monitor watches netlink events, not raw packet captures.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-067", domain:1, obj:"1.5", diff:"medium", q:"Which command finds all files under /home larger than 100 MB?", options:["find /home -size +100M","find /home -name +100M","ls -lh /home +100M","du /home > 100M"], answer:0, explain:"<strong>find /home -size +100M</strong> searches recursively for files whose size exceeds 100 megabytes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>find /home -name +100M</b>: -name matches filenames, so +100M would be treated as a name pattern, not a size.</span><span class='qd'><b>ls -lh /home +100M</b>: ls cannot filter by size and +100M is an invalid argument.</span><span class='qd'><b>du /home > 100M</b>: this redirects du output to a file named 100M and does not filter by size.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-068", domain:1, obj:"1.6", diff:"hard", q:"A differential backup is restored after a disaster. Which combination of backups must be applied to fully restore the data?", options:["The most recent differential only","The last full backup plus the most recent differential","Every differential since the last full","The last full plus every incremental"], answer:1, explain:"<strong>The last full backup plus the most recent differential</strong> is sufficient because each differential contains all changes since the last full, so only the newest one is needed alongside the full.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The most recent differential only</b>: a differential alone lacks the base full backup data.</span><span class='qd'><b>Every differential since the last full</b>: differentials are cumulative, so only the latest one is needed, not all of them.</span><span class='qd'><b>The last full plus every incremental</b>: this describes incremental restore, not differential.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-069", domain:1, obj:"1.7", diff:"medium", q:"Which command edits the XML definition of an existing libvirt domain named db01?", options:["virsh define db01","virsh edit db01","virsh dumpxml db01","virsh create db01"], answer:1, explain:"<strong>virsh edit db01</strong> opens the domain's XML in an editor and validates and applies the changes on save.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>virsh define db01</b>: define registers a domain from an XML file argument; it does not open an editor for an existing one by name.</span><span class='qd'><b>virsh dumpxml db01</b>: dumpxml only prints the XML and does not edit it.</span><span class='qd'><b>virsh create db01</b>: create starts a transient domain from an XML file and does not edit a defined one.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-070", domain:1, obj:"1.3", diff:"medium", q:"Which command displays human-readable disk space usage of all mounted filesystems?", options:["du -a","df -h","lsblk -a","free -h"], answer:1, explain:"<strong>df -h</strong> reports used and available space per mounted filesystem in human-readable units.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>du -a</b>: du measures the size of files and directories, not filesystem capacity and free space.</span><span class='qd'><b>lsblk -a</b>: lsblk lists block devices but does not show used/available space per filesystem.</span><span class='qd'><b>free -h</b>: free reports RAM and swap usage, not disk space.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-071", domain:1, obj:"1.4", diff:"hard", q:"A host has two default routes and traffic is leaving the wrong interface. Which command removes a specific default route via gateway 192.168.1.1?", options:["ip route del default via 192.168.1.1","ip route flush all","ip route add default via 192.168.1.1","route delete default"], answer:0, explain:"<strong>ip route del default via 192.168.1.1</strong> deletes only the default route that uses that specific gateway, leaving the correct one in place.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ip route flush all</b>: this removes every route, which would break all connectivity.</span><span class='qd'><b>ip route add default via 192.168.1.1</b>: add creates a route rather than removing the unwanted one.</span><span class='qd'><b>route delete default</b>: this legacy command removes a default route but without specifying the gateway it may delete the wrong one and is deprecated.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-072", domain:1, obj:"1.5", diff:"medium", q:"Which command sorts the file ages.txt numerically and removes duplicate lines?", options:["sort ages.txt | uniq","sort -n ages.txt | uniq","uniq ages.txt | sort","sort -r ages.txt"], answer:1, explain:"<strong>sort -n ages.txt | uniq</strong> sorts numerically and then uniq removes adjacent duplicates, which works because the input is sorted first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sort ages.txt | uniq</b>: without -n this sorts lexically, so 10 comes before 9, which is incorrect for numbers.</span><span class='qd'><b>uniq ages.txt | sort</b>: uniq only removes adjacent duplicates, so running it before sorting misses non-adjacent ones.</span><span class='qd'><b>sort -r ages.txt</b>: -r sorts in reverse and does not remove duplicates.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-073", domain:1, obj:"1.1", diff:"medium", q:"Which command on a systemd-based RHEL system installs a package named httpd along with its dependencies?", options:["rpm -i httpd","dnf install httpd","yum remove httpd","dpkg -i httpd"], answer:1, explain:"<strong>dnf install httpd</strong> resolves and installs the package and all required dependencies from configured repositories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rpm -i httpd</b>: rpm -i installs a local package file and does not resolve dependencies from repositories.</span><span class='qd'><b>yum remove httpd</b>: remove uninstalls a package rather than installing it.</span><span class='qd'><b>dpkg -i httpd</b>: dpkg is for Debian-based systems, not RHEL.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-074", domain:1, obj:"1.3", diff:"hard", q:"An administrator wants a striped LVM logical volume across two PVs for performance. Which lvcreate option creates a striped LV with 2 stripes?", options:["lvcreate -L 20G -i 2 -n lvfast vg0","lvcreate -L 20G -m 1 -n lvfast vg0","lvcreate -L 20G -s -n lvfast vg0","lvcreate -L 20G -T -n lvfast vg0"], answer:0, explain:"<strong>lvcreate -L 20G -i 2 -n lvfast vg0</strong> uses -i 2 to stripe the logical volume across two physical volumes for higher throughput.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>lvcreate -L 20G -m 1 -n lvfast vg0</b>: -m 1 creates a mirror for redundancy, not a stripe for performance.</span><span class='qd'><b>lvcreate -L 20G -s -n lvfast vg0</b>: -s creates a snapshot, not a striped volume.</span><span class='qd'><b>lvcreate -L 20G -T -n lvfast vg0</b>: -T creates a thin pool, not a striped LV.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-075", domain:1, obj:"1.4", diff:"medium", q:"Which command performs a DNS lookup and is often used interactively, though dig is generally preferred for scripting?", options:["nslookup example.com","ss example.com","ethtool example.com","mtr example.com"], answer:0, explain:"<strong>nslookup example.com</strong> queries DNS for the host and can run interactively; dig is favored for scriptable, detailed output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ss example.com</b>: ss inspects local sockets and does not perform DNS lookups.</span><span class='qd'><b>ethtool example.com</b>: ethtool queries NIC driver settings, not DNS.</span><span class='qd'><b>mtr example.com</b>: mtr combines ping and traceroute for path analysis, not a simple DNS record lookup.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-076", domain:1, obj:"1.5", diff:"easy", q:"Which operator runs the second command only if the first command succeeds (returns exit status 0)?", options:["cmd1 || cmd2","cmd1 && cmd2","cmd1 ; cmd2","cmd1 | cmd2"], answer:1, explain:"<strong>cmd1 &amp;&amp; cmd2</strong> runs cmd2 only when cmd1 exits successfully with status 0.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cmd1 || cmd2</b>: the || operator runs cmd2 only if cmd1 fails.</span><span class='qd'><b>cmd1 ; cmd2</b>: the semicolon runs cmd2 unconditionally regardless of cmd1's result.</span><span class='qd'><b>cmd1 | cmd2</b>: the pipe feeds cmd1's output to cmd2 and does not condition on exit status.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-077", domain:1, obj:"1.6", diff:"medium", q:"Which command writes an ISO image ubuntu.iso to a USB device /dev/sdc as a bootable disk?", options:["cp ubuntu.iso /dev/sdc","dd if=ubuntu.iso of=/dev/sdc bs=4M status=progress","tar -xf ubuntu.iso -C /dev/sdc","mount ubuntu.iso /dev/sdc"], answer:1, explain:"<strong>dd if=ubuntu.iso of=/dev/sdc bs=4M status=progress</strong> writes the hybrid ISO directly to the USB device, producing a bootable drive.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cp ubuntu.iso /dev/sdc</b>: cp may not write the image structure correctly for booting and is unreliable for raw devices.</span><span class='qd'><b>tar -xf ubuntu.iso -C /dev/sdc</b>: an ISO is not a tar archive and the device is not a directory.</span><span class='qd'><b>mount ubuntu.iso /dev/sdc</b>: mount makes the ISO accessible but does not create a bootable USB.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-078", domain:1, obj:"1.7", diff:"medium", q:"Which command displays the host's CPU support for hardware virtualization extensions needed by KVM?", options:["grep -E 'vmx|svm' /proc/cpuinfo","lsmod | grep kvm_enabled","virsh capabilities --check","modprobe vmx"], answer:0, explain:"<strong>grep -E 'vmx|svm' /proc/cpuinfo</strong> checks for the Intel vmx or AMD svm flags that indicate hardware virtualization support.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>lsmod | grep kvm_enabled</b>: there is no kvm_enabled module; lsmod shows loaded modules like kvm and kvm_intel.</span><span class='qd'><b>virsh capabilities --check</b>: virsh capabilities prints host capabilities but --check is not a valid flag for this purpose.</span><span class='qd'><b>modprobe vmx</b>: vmx is a CPU flag, not a loadable module name.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-079", domain:1, obj:"1.2", diff:"hard", q:"After updating a kernel module's source path, modprobe still cannot find a dependency. Which command rebuilds the module dependency database?", options:["depmod -a","modinfo -a","insmod -f","modprobe -r"], answer:0, explain:"<strong>depmod -a</strong> scans modules and rebuilds modules.dep so modprobe can resolve dependencies correctly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>modinfo -a</b>: modinfo only prints the author field with -a and does not rebuild dependencies.</span><span class='qd'><b>insmod -f</b>: insmod -f forces loading a single module and ignores dependencies entirely.</span><span class='qd'><b>modprobe -r</b>: modprobe -r removes a module rather than rebuilding the dependency database.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-080", domain:1, obj:"1.3", diff:"medium", q:"Which command nondestructively grows an ext4 filesystem to fill its enlarged partition?", options:["xfs_growfs /mnt","resize2fs /dev/sdb1","mkfs.ext4 /dev/sdb1","e2label /dev/sdb1"], answer:1, explain:"<strong>resize2fs /dev/sdb1</strong> grows an ext2/3/4 filesystem to use the available space without destroying data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>xfs_growfs /mnt</b>: xfs_growfs works only on XFS filesystems, not ext4.</span><span class='qd'><b>mkfs.ext4 /dev/sdb1</b>: mkfs reformats the partition and erases all data.</span><span class='qd'><b>e2label /dev/sdb1</b>: e2label only sets or reads the filesystem label and does not resize it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-081", domain:1, obj:"1.4", diff:"medium", q:"Which Netplan renderer key value tells Netplan to hand interface management to NetworkManager?", options:["renderer: networkd","renderer: NetworkManager","renderer: ifupdown","renderer: systemd"], answer:1, explain:"<strong>renderer: NetworkManager</strong> instructs Netplan to generate configuration for and delegate control to NetworkManager.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>renderer: networkd</b>: this delegates to systemd-networkd, not NetworkManager.</span><span class='qd'><b>renderer: ifupdown</b>: ifupdown is not a valid Netplan renderer value.</span><span class='qd'><b>renderer: systemd</b>: the correct backend name is networkd; systemd alone is not a valid renderer.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-082", domain:1, obj:"1.5", diff:"medium", q:"Which command replaces tabs with commas in fields.txt by translating the tab character to a comma?", options:["tr '\\t' ',' < fields.txt","sed 's/,/\\t/' fields.txt","cut -d',' fields.txt","awk -F, fields.txt"], answer:0, explain:"<strong>tr '\\t' ',' &lt; fields.txt</strong> translates every tab character to a comma as the file streams through tr.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sed 's/,/\\t/' fields.txt</b>: this converts commas to tabs, the reverse of what is needed.</span><span class='qd'><b>cut -d',' fields.txt</b>: cut selects fields by delimiter and does not translate characters.</span><span class='qd'><b>awk -F, fields.txt</b>: setting the field separator alone does not translate or print anything.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-083", domain:1, obj:"1.1", diff:"medium", q:"Which command shows the current default systemd target (the equivalent of the old runlevel)?", options:["systemctl get-default","runlevel set","systemctl isolate","init q"], answer:0, explain:"<strong>systemctl get-default</strong> prints the default target such as multi-user.target or graphical.target.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>runlevel set</b>: runlevel reports current and previous runlevels and has no set subcommand.</span><span class='qd'><b>systemctl isolate</b>: isolate switches to a target now but does not report the default.</span><span class='qd'><b>init q</b>: init q reloads inittab on SysV systems and does not show the systemd default target.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-084", domain:1, obj:"1.3", diff:"easy", q:"Which command unmounts the filesystem mounted at /mnt/usb?", options:["mount /mnt/usb","umount /mnt/usb","unmount /mnt/usb","eject /mnt/usb"], answer:1, explain:"<strong>umount /mnt/usb</strong> unmounts the filesystem at that mount point.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mount /mnt/usb</b>: mount attaches a filesystem rather than detaching it.</span><span class='qd'><b>unmount /mnt/usb</b>: the command is spelled umount, not unmount.</span><span class='qd'><b>eject /mnt/usb</b>: eject is for removable media devices and is not the standard unmount command for a mount point.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-085", domain:1, obj:"1.4", diff:"medium", q:"Which command shows the link speed and duplex negotiated by the NIC eth0?", options:["ethtool eth0","ip addr show eth0","dig eth0","nmcli eth0 speed"], answer:0, explain:"<strong>ethtool eth0</strong> reports the negotiated speed, duplex, and link status of the interface.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ip addr show eth0</b>: this shows assigned IP addresses, not speed or duplex.</span><span class='qd'><b>dig eth0</b>: dig performs DNS queries and is unrelated to NIC link settings.</span><span class='qd'><b>nmcli eth0 speed</b>: this is not valid nmcli syntax for reporting link speed.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-086", domain:1, obj:"1.5", diff:"hard", q:"Which here-document construct feeds multiple lines into the cat command terminated by the word EOF?", options:["cat << EOF\nline1\nline2\nEOF","cat < EOF line1 line2 EOF","cat >> EOF","cat | EOF"], answer:0, explain:"<strong>cat &lt;&lt; EOF (with line1 and line2 followed by EOF)</strong> uses a here-document so all lines until the EOF delimiter are passed as input to cat.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cat < EOF line1 line2 EOF</b>: a single < redirects a file named EOF as input, not a here-document.</span><span class='qd'><b>cat >> EOF</b>: >> appends output to a file named EOF and does not create a here-document.</span><span class='qd'><b>cat | EOF</b>: this pipes cat into a nonexistent command EOF.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-087", domain:1, obj:"1.6", diff:"medium", q:"Which command compresses a single file report.log into report.log.gz while removing the original?", options:["gzip report.log","gzip -k report.log","gunzip report.log","tar report.log"], answer:0, explain:"<strong>gzip report.log</strong> compresses the file in place, producing report.log.gz and deleting the original by default.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>gzip -k report.log</b>: -k keeps the original file, so it does not remove it.</span><span class='qd'><b>gunzip report.log</b>: gunzip decompresses rather than compresses.</span><span class='qd'><b>tar report.log</b>: tar without action flags does not compress a single file into a .gz.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-088", domain:1, obj:"1.7", diff:"hard", q:"A KVM guest needs to attach a second virtual disk dynamically while running. Which virsh command attaches a qcow2 disk as vdb without rebooting?", options:["virsh attach-disk vm /var/lib/libvirt/images/data.qcow2 vdb --live","virsh edit vm","virsh setvcpus vm 2","virsh snapshot-create vm"], answer:0, explain:"<strong>virsh attach-disk vm /var/lib/libvirt/images/data.qcow2 vdb --live</strong> hotplugs the disk into the running VM as vdb without a reboot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>virsh edit vm</b>: editing the XML changes the persistent config but typically requires a restart to take effect for new disks.</span><span class='qd'><b>virsh setvcpus vm 2</b>: this changes the CPU count, not disks.</span><span class='qd'><b>virsh snapshot-create vm</b>: this creates a snapshot rather than attaching a new disk.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-089", domain:1, obj:"1.2", diff:"medium", q:"Which file or directory lets an administrator pass options to a kernel module at load time, such as setting a parameter for the i915 driver?", options:["/etc/modules-load.d/","/etc/modprobe.d/i915.conf","/proc/modules","/sys/module/list"], answer:1, explain:"<strong>/etc/modprobe.d/i915.conf</strong> can contain an options line that passes parameters to the module when modprobe loads it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/modules-load.d/</b>: this lists modules to load at boot but does not set their parameters.</span><span class='qd'><b>/proc/modules</b>: this is a read-only view of loaded modules and cannot set options.</span><span class='qd'><b>/sys/module/list</b>: this path does not exist; module info lives under /sys/module/&lt;name&gt;.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-090", domain:1, obj:"1.3", diff:"medium", q:"Which command creates a new GPT partition table on /dev/sdb interactively using a modern partitioning tool?", options:["fdisk /dev/sdb with the g command","mkfs.gpt /dev/sdb","parted /dev/sdb print","blkid -g /dev/sdb"], answer:0, explain:"<strong>fdisk /dev/sdb with the g command</strong> creates a new empty GPT partition table; modern fdisk supports GPT via the g command.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mkfs.gpt /dev/sdb</b>: there is no mkfs.gpt; GPT is a partition table, not a filesystem.</span><span class='qd'><b>parted /dev/sdb print</b>: print only displays the current table and does not create a GPT.</span><span class='qd'><b>blkid -g /dev/sdb</b>: blkid -g garbage-collects the cache and does not create partition tables.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-091", domain:1, obj:"1.4", diff:"medium", q:"Which command displays the current hostname and allows setting it persistently on a systemd system?", options:["hostname -p","hostnamectl","uname -n","getent hosts"], answer:1, explain:"<strong>hostnamectl</strong> shows the current hostname and, with set-hostname, persists changes via systemd.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>hostname -p</b>: -p is not a valid flag and hostname alone does not persist changes across reboots.</span><span class='qd'><b>uname -n</b>: uname -n prints the node name but cannot set the hostname.</span><span class='qd'><b>getent hosts</b>: getent queries name service databases and does not manage the hostname.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-092", domain:1, obj:"1.5", diff:"medium", q:"Which command shows the last 20 lines of /var/log/syslog and continues to display new lines as they are written?", options:["head -n 20 -f /var/log/syslog","tail -n 20 -f /var/log/syslog","cat -f /var/log/syslog","less +F /var/log/syslog -n 20"], answer:1, explain:"<strong>tail -n 20 -f /var/log/syslog</strong> prints the last 20 lines and follows the file (-f) to stream new entries in real time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>head -n 20 -f /var/log/syslog</b>: head shows the first lines and does not support live following.</span><span class='qd'><b>cat -f /var/log/syslog</b>: cat has no -f follow option and prints the whole file once.</span><span class='qd'><b>less +F /var/log/syslog -n 20</b>: less +F follows the file but the -n 20 line-limit syntax shown is not how less restricts to the last 20 lines.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-093", domain:1, obj:"1.1", diff:"hard", q:"A system fails to boot with a kernel panic citing an unknown root device. Which GRUB kernel parameter most directly specifies the root filesystem to use?", options:["init=/bin/bash","root=/dev/mapper/vg0-root","quiet splash","selinux=0"], answer:1, explain:"<strong>root=/dev/mapper/vg0-root</strong> tells the kernel which device to mount as the root filesystem, resolving an unknown root device panic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>init=/bin/bash</b>: this changes the init process for recovery but does not specify the root device.</span><span class='qd'><b>quiet splash</b>: these only affect boot verbosity and the splash screen.</span><span class='qd'><b>selinux=0</b>: this disables SELinux and is unrelated to locating the root filesystem.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-094", domain:1, obj:"1.3", diff:"medium", q:"An NFS client mount hangs when the server is down. Which mount option allows the mount to fail and return an error instead of blocking indefinitely?", options:["hard","soft","sync","ro"], answer:1, explain:"<strong>soft</strong> causes NFS operations to time out and return an error rather than retrying forever, preventing indefinite hangs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>hard</b>: hard mounts retry indefinitely until the server responds, which is the hanging behavior.</span><span class='qd'><b>sync</b>: sync controls write caching behavior, not timeout handling.</span><span class='qd'><b>ro</b>: ro mounts read-only and does not affect how the client handles an unreachable server.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-095", domain:1, obj:"1.4", diff:"easy", q:"Which command displays the system's current IP addresses and interface state using iproute2?", options:["ip addr show","route print","dig -a","netstat -r"], answer:0, explain:"<strong>ip addr show</strong> lists each interface with its assigned IP addresses and state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>route print</b>: route print is a Windows command and not used on Linux.</span><span class='qd'><b>dig -a</b>: dig performs DNS queries and -a is not a valid address-listing flag.</span><span class='qd'><b>netstat -r</b>: netstat -r shows the routing table, not interface IP addresses.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-096", domain:1, obj:"1.6", diff:"hard", q:"An administrator schedules rsync backups but wants only files changed in the last 24 hours to transfer, regardless of timestamps differing. Which rsync option compares file content via checksums instead of mtime and size?", options:["--checksum","--size-only","--update","--ignore-times"], answer:0, explain:"<strong>--checksum</strong> forces rsync to compute and compare checksums to decide which files differ, instead of relying on modification time and size.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>--size-only</b>: this skips files whose size matches, ignoring content differences, the opposite of checksum comparison.</span><span class='qd'><b>--update</b>: this only skips files newer on the destination and still uses mtime, not checksums.</span><span class='qd'><b>--ignore-times</b>: this transfers all files regardless of times but does not compare by checksum.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-097", domain:1, obj:"1.2", diff:"medium", q:"Which command safely removes the loaded kernel module usb_storage along with checking dependencies?", options:["rmmod usb_storage","modprobe -r usb_storage","insmod -r usb_storage","depmod usb_storage"], answer:1, explain:"<strong>modprobe -r usb_storage</strong> unloads the module and also unloads unused dependencies, which is safer than rmmod.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rmmod usb_storage</b>: rmmod removes the module but does not consider dependent modules automatically.</span><span class='qd'><b>insmod -r usb_storage</b>: insmod loads modules and has no -r removal mode.</span><span class='qd'><b>depmod usb_storage</b>: depmod rebuilds dependency maps and does not unload a module.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-098", domain:1, obj:"1.5", diff:"medium", q:"Which command extracts and prints just the IP addresses (first field) from a space-delimited log using awk?", options:["awk '{print $1}' access.log","awk -F: '{print $1}' access.log","cut -f1 access.log","grep -o '$1' access.log"], answer:0, explain:"<strong>awk '{print $1}' access.log</strong> prints the first whitespace-delimited field of each line, which is the client IP in a typical access log.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>awk -F: '{print $1}' access.log</b>: -F: splits on colons, so $1 would not be the space-delimited IP field.</span><span class='qd'><b>cut -f1 access.log</b>: cut -f defaults to a tab delimiter, so it fails on a space-delimited log.</span><span class='qd'><b>grep -o '$1' access.log</b>: grep -o matches a literal pattern, not a positional field, and $1 is not a field reference here.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-099", domain:1, obj:"1.1", diff:"medium", q:"Which command reinstalls the GRUB2 bootloader to the disk /dev/sda after a repair on a BIOS (non-UEFI) system?", options:["grub2-mkconfig /dev/sda","grub2-install /dev/sda","update-grub /dev/sda","efibootmgr /dev/sda"], answer:1, explain:"<strong>grub2-install /dev/sda</strong> writes the GRUB2 boot code to the MBR of the disk on a BIOS system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>grub2-mkconfig /dev/sda</b>: mkconfig generates the grub.cfg menu file and does not install boot code to a disk.</span><span class='qd'><b>update-grub /dev/sda</b>: update-grub regenerates config (Debian wrapper) and does not install to the MBR with a device argument.</span><span class='qd'><b>efibootmgr /dev/sda</b>: efibootmgr manages UEFI boot entries and is irrelevant on a BIOS system.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D1-100", domain:1, obj:"1.7", diff:"medium", q:"Which command lists the storage pools that libvirt knows about?", options:["virsh pool-list --all","virsh vol-list default","qemu-img list","virsh net-list"], answer:0, explain:"<strong>virsh pool-list --all</strong> shows all defined storage pools, including inactive ones, that libvirt manages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>virsh vol-list default</b>: vol-list shows volumes within a single named pool, not the pools themselves.</span><span class='qd'><b>qemu-img list</b>: qemu-img has no list subcommand for libvirt pools.</span><span class='qd'><b>virsh net-list</b>: net-list shows virtual networks, not storage pools.</span>" }
);

/* linux+ :: XK0-006 Domain 2 question bank (100 items, inline). Populates LINUXPLUS.questions. */
window.LINUXPLUS = window.LINUXPLUS || {}; LINUXPLUS.questions = LINUXPLUS.questions || [];
LINUXPLUS.questions.push(
{ id:"D2-001", domain:2, obj:"2.1", diff:"medium", q:"A web app reads its config from /etc/app/config.yaml, but the ops team wants to keep the authoritative file in /opt/app/releases/v3/config.yaml so it changes when they switch releases. They need /etc/app/config.yaml to always point at the current release file across filesystems. Which command achieves this?", options:["ln -s /opt/app/releases/v3/config.yaml /etc/app/config.yaml","ln /opt/app/releases/v3/config.yaml /etc/app/config.yaml","cp -p /opt/app/releases/v3/config.yaml /etc/app/config.yaml","mv /opt/app/releases/v3/config.yaml /etc/app/config.yaml"], answer:0, explain:"<strong>A symbolic link is required across filesystems.</strong> Hard links cannot span filesystem boundaries (separate inode tables), and /opt and /etc may be different mounts. A symlink stores a path, so updating the link to point at a new release path keeps /etc/app/config.yaml current.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ln /opt/app/releases/v3/config.yaml /etc/app/config.yaml</b>: a hard link cannot cross filesystems and shares the inode, so it would not follow release switches cleanly.</span><span class='qd'><b>cp -p /opt/app/releases/v3/config.yaml /etc/app/config.yaml</b>: copying creates an independent file that does not track later changes to the release file.</span><span class='qd'><b>mv /opt/app/releases/v3/config.yaml /etc/app/config.yaml</b>: moving removes the file from the release directory, breaking the release layout.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-002", domain:2, obj:"2.1", diff:"medium", q:"You must find every file under /var/log larger than 100 MB that has not been modified in the last 30 days, to archive them. Which command lists them?", options:["find /var/log -size +100M -mtime -30","find /var/log -size -100M -mtime +30","find /var/log -size +100k -atime +30","find /var/log -size +100M -mtime +30"], answer:3, explain:"<strong>-size +100M selects files larger than 100 MB and -mtime +30 selects files modified more than 30 days ago.</strong> The plus signs mean 'greater than' for size and 'older than' for modification time, exactly matching the requirement.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>find /var/log -size +100M -mtime -30</b>: -mtime -30 matches files modified within the last 30 days, the opposite of what is wanted.</span><span class='qd'><b>find /var/log -size -100M -mtime +30</b>: -size -100M matches files smaller than 100 MB.</span><span class='qd'><b>find /var/log -size +100k -atime +30</b>: +100k is 100 kilobytes, and -atime tests access time, not modification time.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-003", domain:2, obj:"2.1", diff:"easy", q:"A junior admin ran 'rm *' inside /data while intending to be in a scratch directory and now wants to understand what the current and parent directory entries shown by 'ls -a' mean. What do the '.' and '..' entries represent?", options:["Hidden backup copies created by the editor","Symbolic links to /root and /home","Temporary lock files used by the shell","The current directory and the parent directory"], answer:3, explain:"<strong>'.' refers to the current directory and '..' refers to the parent directory.</strong> These special entries exist in every directory and are the basis for relative path navigation such as cd .. or ./script.sh.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hidden backup copies created by the editor</b>: editor backups are normal files like file~, not the . and .. entries.</span><span class='qd'><b>Symbolic links to /root and /home</b>: they are not links to those paths; they are directory self/parent references.</span><span class='qd'><b>Temporary lock files used by the shell</b>: the shell does not create . and ..; the filesystem provides them.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-004", domain:2, obj:"2.1", diff:"medium", q:"A backup script must copy /srv/data to /backup preserving symlinks as links, ownership, timestamps, and permissions, and it should recurse into subdirectories. Which single cp invocation is most appropriate?", options:["cp -a /srv/data /backup","cp -r /srv/data /backup","cp -u /srv/data /backup","cp -L /srv/data /backup"], answer:0, explain:"<strong>cp -a (archive) recurses and preserves symlinks, ownership, timestamps, and permissions.</strong> It is equivalent to -dR --preserve=all, exactly matching the stated requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cp -r /srv/data /backup</b>: -r recurses but does not preserve ownership, timestamps, or treat symlinks specially by default.</span><span class='qd'><b>cp -u /srv/data /backup</b>: -u only copies when source is newer and does not preserve metadata or recurse on its own.</span><span class='qd'><b>cp -L /srv/data /backup</b>: -L dereferences symlinks, copying their targets instead of preserving them as links.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-005", domain:2, obj:"2.1", diff:"medium", q:"A developer reports that 'cat /etc/app.conf' shows the file, but a hard link they created with 'ln /etc/app.conf ~/app.conf' still shows old content after they edited the original with sed -i. What explains the behavior they should expect from a hard link?", options:["Hard links always lag behind because they cache content","Hard links only update when the inode link count changes","Both names point to the same inode, so edits via either name are seen by both","Hard links are read-only copies that never reflect edits"], answer:2, explain:"<strong>A hard link is just another name for the same inode, so content is shared.</strong> However, sed -i typically writes a new file and renames it over the original, which creates a new inode and breaks the hard link association, so the link keeps the old content. The expected hard-link behavior itself is that both names reference one inode.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hard links always lag behind because they cache content</b>: hard links do not cache; they share the inode directly.</span><span class='qd'><b>Hard links only update when the inode link count changes</b>: visibility of edits has nothing to do with link count.</span><span class='qd'><b>Hard links are read-only copies that never reflect edits</b>: hard links are not copies and are not read-only.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-006", domain:2, obj:"2.1", diff:"hard", q:"You need to recursively find all *.tmp files under /home older than 7 days and delete them efficiently in a single command without spawning one process per file. Which is best?", options:["find /home -name '*.tmp' -mtime +7 -exec rm {} \\;","find /home -name '*.tmp' -mtime +7 | rm","find /home -name '*.tmp' -mtime +7 -delete","find /home -name '*.tmp' -mtime +7 -exec rm {} +"], answer:2, explain:"<strong>-delete removes matched files using find's built-in action, with no extra processes.</strong> It is efficient and avoids the overhead and quoting pitfalls of spawning rm. (-exec rm {} + is also efficient but -delete is the most direct single-tool answer.)<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>find /home -name '*.tmp' -mtime +7 -exec rm {} \\;</b>: the \\; form spawns one rm per file, which is exactly the inefficiency to avoid.</span><span class='qd'><b>find /home -name '*.tmp' -mtime +7 | rm</b>: rm does not read filenames from stdin, so this deletes nothing.</span><span class='qd'><b>find /home -name '*.tmp' -mtime +7 -exec rm {} +</b>: this works and is efficient, but among the options -delete is the cleaner single-tool deletion; the + form still launches rm rather than using find's own action.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-007", domain:2, obj:"2.1", diff:"medium", q:"An admin wants to display only the lines of /var/log/secure that contain 'Failed password', then count them. Which pipeline is correct?", options:["grep -v 'Failed password' /var/log/secure | wc -l","wc -l 'Failed password' /var/log/secure","grep 'Failed password' /var/log/secure | wc -l","grep 'Failed password' /var/log/secure | wc -c"], answer:2, explain:"<strong>grep filters matching lines and wc -l counts them.</strong> This returns the number of lines containing 'Failed password', which is what is requested.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>grep -v 'Failed password' /var/log/secure | wc -l</b>: -v inverts the match, counting lines that do not contain the phrase.</span><span class='qd'><b>wc -l 'Failed password' /var/log/secure</b>: wc treats the arguments as filenames, so it errors and does not filter.</span><span class='qd'><b>grep 'Failed password' /var/log/secure | wc -c</b>: -c counts characters/bytes, not lines.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-008", domain:2, obj:"2.1", diff:"easy", q:"A user is in /home/jdoe/projects/web and wants to move to /home/jdoe using a relative path in one step. Which command does this?", options:["cd ..","cd ~web","cd ../..","cd ./jdoe"], answer:2, explain:"<strong>cd ../.. moves up two levels: from web to projects, then to jdoe.</strong> Relative paths use .. for each parent directory level, and two levels up from .../projects/web lands in /home/jdoe.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cd ..</b>: this goes up only one level, to /home/jdoe/projects.</span><span class='qd'><b>cd ~web</b>: ~web tries to expand to the home directory of a user named web, not a parent directory.</span><span class='qd'><b>cd ./jdoe</b>: ./jdoe looks for a subdirectory named jdoe under web, which does not exist.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-009", domain:2, obj:"2.1", diff:"medium", q:"You need to view the last 50 lines of a growing log file and keep watching for new lines in real time. Which command is correct?", options:["head -n 50 -f /var/log/app.log","tail -n 50 -f /var/log/app.log","cat -50 /var/log/app.log","less +F -n 50 /var/log/app.log"], answer:1, explain:"<strong>tail -n 50 -f prints the last 50 lines and then follows the file for new output.</strong> The -f flag keeps tail attached to the file, streaming appended lines as they arrive.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>head -n 50 -f /var/log/app.log</b>: head shows the beginning of a file and does not support follow mode.</span><span class='qd'><b>cat -50 /var/log/app.log</b>: cat has no -50 option and cannot follow a file.</span><span class='qd'><b>less +F -n 50 /var/log/app.log</b>: less +F follows a file but -n in less sets line numbering off, not a 50-line tail.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-010", domain:2, obj:"2.1", diff:"medium", q:"A script must create a nested directory tree /srv/sites/blog/2026/06 in one command, creating any missing parent directories without error if some already exist. Which command is correct?", options:["mkdir /srv/sites/blog/2026/06","mkdir -p /srv/sites/blog/2026/06","mkdir -r /srv/sites/blog/2026/06","install -d /srv /sites /blog"], answer:1, explain:"<strong>mkdir -p creates the full path, making intermediate directories as needed and not failing if they already exist.</strong> This is the standard way to safely create a deep directory tree.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mkdir /srv/sites/blog/2026/06</b>: without -p this fails if any parent directory does not yet exist.</span><span class='qd'><b>mkdir -r /srv/sites/blog/2026/06</b>: mkdir has no -r option; that flag is for commands like rm or cp.</span><span class='qd'><b>install -d /srv /sites /blog</b>: this creates three separate top-level directories, not the nested path requested.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-011", domain:2, obj:"2.1", diff:"hard", q:"Across a build directory you must find every regular file that contains the literal string 'TODO' and print the filenames only, recursively. Which command is the most direct?", options:["grep -r 'TODO' . -c","find . -name TODO","grep -rL 'TODO' .","grep -rl 'TODO' ."], answer:3, explain:"<strong>grep -rl recurses and lists only the names of files that contain the match.</strong> -r recurses into subdirectories and -l prints matching filenames once each, exactly the requested output.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>grep -r 'TODO' . -c</b>: -c prints per-file match counts including zero counts, not a clean filename-only list.</span><span class='qd'><b>find . -name TODO</b>: this finds files literally named TODO, not files containing the string.</span><span class='qd'><b>grep -rL 'TODO' .</b>: uppercase -L lists files that do NOT contain the match, the inverse of what is wanted.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-012", domain:2, obj:"2.1", diff:"medium", q:"You want to determine the file type of an unknown file named 'payload' that has no extension, to decide how to open it safely. Which command reports its type by inspecting content?", options:["stat payload","type payload","wc payload","file payload"], answer:3, explain:"<strong>file inspects magic bytes and content to report a file's type.</strong> It tells you whether 'payload' is, for example, an ELF executable, a gzip archive, ASCII text, or an image, regardless of extension.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>stat payload</b>: stat reports inode metadata such as size and timestamps, not content type.</span><span class='qd'><b>type payload</b>: type is a shell builtin that tells whether a name is a command, alias, or builtin.</span><span class='qd'><b>wc payload</b>: wc counts lines, words, and bytes; it does not identify file type.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-013", domain:2, obj:"2.1", diff:"medium", q:"A symlink /usr/local/bin/python points to a Python version that was uninstalled, so it is now a dangling link. Which command lets you confirm a symlink is broken by showing where it points and that the target is missing?", options:["ls -l /usr/local/bin/python","cat /usr/local/bin/python","chmod +x /usr/local/bin/python","du /usr/local/bin/python"], answer:0, explain:"<strong>ls -l shows the symlink and its target with the -> notation.</strong> When the target no longer exists, the listing reveals the path it points to so you can see the missing destination; tools like ls --color also highlight broken links.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cat /usr/local/bin/python</b>: cat tries to read through the link and just errors that the target does not exist, without showing the link path.</span><span class='qd'><b>chmod +x /usr/local/bin/python</b>: changing permissions does not reveal or fix a broken target.</span><span class='qd'><b>du /usr/local/bin/python</b>: du reports disk usage and does not display the symlink target.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-014", domain:2, obj:"2.1", diff:"easy", q:"You need to copy file report.csv into the current directory under a new name backup.csv. Which command does this?", options:["cp report.csv backup.csv","mv report.csv backup.csv","ln report.csv backup.csv","cat report.csv > backup.csv && rm report.csv"], answer:0, explain:"<strong>cp report.csv backup.csv copies the file to a new name, leaving the original in place.</strong> This satisfies 'copy ... under a new name' without removing the source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mv report.csv backup.csv</b>: mv renames/moves the file, so the original name no longer exists.</span><span class='qd'><b>ln report.csv backup.csv</b>: ln creates a hard link, not an independent copy.</span><span class='qd'><b>cat report.csv > backup.csv && rm report.csv</b>: this deletes the original, so it is a move, not a copy.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-015", domain:2, obj:"2.1", diff:"medium", q:"You must search /etc recursively for files containing 'PermitRootLogin' but want to ignore case and also see the line numbers. Which command is correct?", options:["grep -rv 'PermitRootLogin' /etc","grep -wo 'PermitRootLogin' /etc","grep -rc 'PermitRootLogin' /etc","grep -rin 'PermitRootLogin' /etc"], answer:3, explain:"<strong>grep -rin combines recursive search (-r), case-insensitive matching (-i), and line numbers (-n).</strong> This finds the directive regardless of capitalization and shows where it appears.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>grep -rv 'PermitRootLogin' /etc</b>: -v inverts the match, listing lines that do not contain the string.</span><span class='qd'><b>grep -wo 'PermitRootLogin' /etc</b>: this lacks -r so it does not recurse, and -o prints only the matched text without line numbers.</span><span class='qd'><b>grep -rc 'PermitRootLogin' /etc</b>: -c gives counts per file, not the matching lines or their line numbers.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-016", domain:2, obj:"2.1", diff:"medium", q:"You want a quick way to jump back to the directory you were in before your last cd, without typing the full path. Which command does this?", options:["cd ~-","cd -","popd","cd $OLDPWD/.."], answer:1, explain:"<strong>cd - switches to the previous working directory stored in $OLDPWD.</strong> It is the standard shortcut for toggling between two directories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cd ~-</b>: while ~- also expands to $OLDPWD in bash, it is less standard and not the canonical toggle shortcut taught here.</span><span class='qd'><b>popd</b>: popd only works if you previously used pushd to build a directory stack.</span><span class='qd'><b>cd $OLDPWD/..</b>: this goes to the parent of the previous directory, not the previous directory itself.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-017", domain:2, obj:"2.1", diff:"hard", q:"You need to find files under /data modified in the last 10 minutes AND owned by user 'app', then list them in long format. Which find command is correct?", options:["find /data -mmin +10 -user app -ls","find /data -cmin -10 -group app -ls","find /data -mmin -10 -uid app -ls","find /data -mmin -10 -user app -ls"], answer:3, explain:"<strong>-mmin -10 matches modification within the last 10 minutes, -user app filters by owner, and -ls produces a long listing.</strong> All three conditions are combined with implicit AND.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>find /data -mmin +10 -user app -ls</b>: +10 matches files modified more than 10 minutes ago, the opposite window.</span><span class='qd'><b>find /data -cmin -10 -group app -ls</b>: -cmin tests inode change time and -group filters by group, not owner.</span><span class='qd'><b>find /data -mmin -10 -uid app -ls</b>: -uid expects a numeric UID, not a username like app.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-018", domain:2, obj:"2.1", diff:"medium", q:"A log analysis task needs the unique set of source IPs from a column of an access log, sorted. The IPs are in field 1 of a space-delimited file. Which pipeline produces a sorted unique list?", options:["cut -d' ' -f1 access.log | uniq | sort","cut -d' ' -f1 access.log | sort | uniq","awk '{print $1}' access.log | uniq -c","sort access.log | cut -d' ' -f1"], answer:1, explain:"<strong>cut extracts field 1, sort orders the lines, and uniq collapses adjacent duplicates.</strong> uniq only removes adjacent duplicates, so sorting first is required to get a true unique set.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cut -d' ' -f1 access.log | uniq | sort</b>: running uniq before sort fails to remove non-adjacent duplicates.</span><span class='qd'><b>awk '{print $1}' access.log | uniq -c</b>: this counts adjacent duplicates without sorting first, giving wrong counts and no clean unique list.</span><span class='qd'><b>sort access.log | cut -d' ' -f1</b>: sorting whole lines then cutting can leave duplicate IPs because identical IPs may have different trailing fields.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-019", domain:2, obj:"2.2", diff:"medium", q:"You must create a service account 'backupsvc' that has no login shell and no home directory, used only to own files for a backup daemon. Which command best fits?", options:["useradd -r -s /usr/sbin/nologin -M backupsvc","useradd -m -s /bin/bash backupsvc","useradd -s /bin/bash -d /home/backupsvc backupsvc","useradd -p backupsvc backupsvc"], answer:0, explain:"<strong>-r creates a system account, -s /usr/sbin/nologin prevents interactive login, and -M skips creating a home directory.</strong> This matches a non-login service account used only for file ownership.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>useradd -m -s /bin/bash backupsvc</b>: -m creates a home directory and /bin/bash grants an interactive shell, both unwanted for a service account.</span><span class='qd'><b>useradd -s /bin/bash -d /home/backupsvc backupsvc</b>: this gives a login shell and a home directory.</span><span class='qd'><b>useradd -p backupsvc backupsvc</b>: -p sets an encrypted password (and here a plaintext one), but does nothing to disable login or skip the home directory.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-020", domain:2, obj:"2.2", diff:"medium", q:"A new policy requires user 'kara' to change her password at her next login. Which command forces a password change on next login without otherwise altering the account?", options:["passwd -l kara","usermod -L kara","passwd -d kara","chage -d 0 kara"], answer:3, explain:"<strong>chage -d 0 sets the last-password-change date to the epoch, which the system treats as expired, forcing a change at next login.</strong> It does not lock or remove the password.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>passwd -l kara</b>: -l locks the account by disabling the password, preventing login rather than prompting a change.</span><span class='qd'><b>usermod -L kara</b>: -L also locks the password, blocking login.</span><span class='qd'><b>passwd -d kara</b>: -d deletes the password entirely, allowing passwordless login on many configurations.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-021", domain:2, obj:"2.2", diff:"medium", q:"You need to add existing user 'mike' to the supplementary group 'docker' without removing him from any of his current supplementary groups. Which command is correct?", options:["usermod -G docker mike","usermod -g docker mike","gpasswd -d mike docker","usermod -aG docker mike"], answer:3, explain:"<strong>usermod -aG appends the user to the named supplementary group.</strong> The -a (append) flag is essential; without it, -G replaces the entire supplementary group list.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>usermod -G docker mike</b>: without -a, -G replaces all of mike's supplementary groups with just docker.</span><span class='qd'><b>usermod -g docker mike</b>: lowercase -g changes the primary group, not supplementary membership.</span><span class='qd'><b>gpasswd -d mike docker</b>: -d removes mike from the docker group, the opposite of the goal.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-022", domain:2, obj:"2.2", diff:"hard", q:"While auditing /etc/shadow you see the line 'svc:!:19000:0:99999:7:::'. What does the single '!' in the password field indicate?", options:["The account is locked and cannot authenticate by password","The account password never expires","The password is stored in plaintext","The account uses an empty password and logs in freely"], answer:0, explain:"<strong>A '!' (or '*' or '!!') in the shadow password field means the password is locked, so password authentication cannot succeed.</strong> This is common for service accounts that should never log in interactively.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The account password never expires</b>: expiry is governed by the aging fields, not the password hash field.</span><span class='qd'><b>The password is stored in plaintext</b>: shadow stores hashes; a bare '!' is not a hash at all.</span><span class='qd'><b>The account uses an empty password and logs in freely</b>: an empty field means no password, but '!' specifically denotes a locked password.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-023", domain:2, obj:"2.2", diff:"medium", q:"You want to view password aging information for user 'lara', including last change date and expiration, in a readable format. Which command shows this?", options:["passwd -S lara","id lara","chage -l lara","getent shadow lara"], answer:2, explain:"<strong>chage -l lists the password aging settings for a user in human-readable form.</strong> It shows last change, minimum/maximum age, warning period, and account/password expiration dates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>passwd -S lara</b>: -S prints a short one-line status (locked/usable and some aging numbers) but not the full readable aging report.</span><span class='qd'><b>id lara</b>: id shows UID, GID, and group memberships, not password aging.</span><span class='qd'><b>getent shadow lara</b>: this dumps the raw shadow fields as numbers, which is not the readable aging summary requested.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-024", domain:2, obj:"2.2", diff:"medium", q:"A user 'dev1' left the company. You must disable login immediately but keep the account and its files for later review, leaving the password hash intact so it can be restored. Which command is best?", options:["usermod -L dev1","userdel dev1","passwd -d dev1","userdel -r dev1"], answer:0, explain:"<strong>usermod -L locks the password by prefixing a '!' to the hash, blocking password login while preserving the account and the original hash.</strong> It can be reversed later with usermod -U.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>userdel dev1</b>: this deletes the account entirely, not merely disabling it.</span><span class='qd'><b>passwd -d dev1</b>: -d removes the password rather than preserving the hash, and may allow passwordless access.</span><span class='qd'><b>userdel -r dev1</b>: this removes the account and the home directory, destroying the files you wanted to keep.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-025", domain:2, obj:"2.2", diff:"easy", q:"Which file stores the encrypted password hashes and password aging fields for local users, readable only by root?", options:["/etc/passwd","/etc/group","/etc/login.defs","/etc/shadow"], answer:3, explain:"<strong>/etc/shadow holds the hashed passwords and aging fields and is restricted to root.</strong> Separating hashes from the world-readable /etc/passwd protects credentials.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/passwd</b>: this lists account info (name, UID, GID, home, shell) and is world-readable, with an 'x' placeholder instead of the hash.</span><span class='qd'><b>/etc/group</b>: this defines groups and their members, not passwords.</span><span class='qd'><b>/etc/login.defs</b>: this sets default policy values like password aging defaults, not per-user hashes.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-026", domain:2, obj:"2.2", diff:"medium", q:"Default password aging policy must change so new users get a maximum password age of 90 days. Which file should you edit to set PASS_MAX_DAYS for newly created accounts?", options:["/etc/shadow","/etc/passwd","/etc/login.defs","/etc/default/useradd"], answer:2, explain:"<strong>/etc/login.defs defines defaults such as PASS_MAX_DAYS that apply to accounts created afterward.</strong> Setting PASS_MAX_DAYS 90 there governs new users' maximum password age.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/shadow</b>: shadow holds per-user values, not the global defaults for new accounts.</span><span class='qd'><b>/etc/passwd</b>: passwd has no password aging fields.</span><span class='qd'><b>/etc/default/useradd</b>: this sets defaults like default group, home base, and shell, but not PASS_MAX_DAYS aging policy.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-027", domain:2, obj:"2.2", diff:"medium", q:"You created group 'analysts' and need to designate user 'rosa' as a group administrator who can add and remove members with gpasswd. Which command grants rosa that administrative role?", options:["usermod -aG analysts rosa","gpasswd -a rosa analysts","gpasswd -A rosa analysts","groupmod -A rosa analysts"], answer:2, explain:"<strong>gpasswd -A sets the group administrators list, letting rosa manage membership.</strong> Group admins can then add or remove members with gpasswd -a/-d.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>usermod -aG analysts rosa</b>: this only makes rosa a member, not an administrator of the group.</span><span class='qd'><b>gpasswd -a rosa analysts</b>: lowercase -a adds rosa as a member, not as an administrator.</span><span class='qd'><b>groupmod -A rosa analysts</b>: groupmod has no -A option for assigning administrators.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-028", domain:2, obj:"2.2", diff:"hard", q:"An /etc/passwd entry reads 'tomcat:x:991:991::/opt/tomcat:/sbin/nologin'. A teammate asks why tomcat cannot get a shell even though the account exists. What is the reason?", options:["The UID 991 is below 1000 so the kernel blocks shells","The shell field is /sbin/nologin, which refuses interactive login","The password field 'x' means the account is disabled","The empty GECOS field prevents login"], answer:1, explain:"<strong>The login shell /sbin/nologin politely refuses interactive sessions and exits.</strong> Setting a service account's shell to nologin is the standard way to prevent shell access while keeping the account usable for running a daemon.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The UID 991 is below 1000 so the kernel blocks shells</b>: low UIDs mark system accounts by convention but the kernel does not block shells based on UID.</span><span class='qd'><b>The password field 'x' means the account is disabled</b>: 'x' simply indicates the hash is in /etc/shadow, not that the account is disabled.</span><span class='qd'><b>The empty GECOS field prevents login</b>: the GECOS (comment) field has no effect on login ability.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-029", domain:2, obj:"2.2", diff:"medium", q:"You must change the login shell for user 'sam' from bash to zsh after zsh was installed. Which command updates the shell field cleanly?", options:["usermod -d /bin/zsh sam","passwd -s /bin/zsh sam","usermod -s /bin/zsh sam","useradd -s /bin/zsh sam"], answer:2, explain:"<strong>usermod -s sets the login shell in /etc/passwd.</strong> Pointing it at /bin/zsh changes sam's default shell for future logins.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>usermod -d /bin/zsh sam</b>: -d changes the home directory, not the shell.</span><span class='qd'><b>passwd -s /bin/zsh sam</b>: passwd has no -s flag to set a shell path; -S only reports status.</span><span class='qd'><b>useradd -s /bin/zsh sam</b>: useradd creates a new account and would fail because sam already exists.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-030", domain:2, obj:"2.2", diff:"medium", q:"You want to verify the effective UID, primary group, and all supplementary groups for the currently logged-in user. Which command shows all of these at once?", options:["whoami","groups root","id","getent passwd"], answer:2, explain:"<strong>id prints the UID, primary GID, and the list of supplementary groups for the current user.</strong> It is the most complete single command for that information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>whoami</b>: whoami prints only the username, not UID or group details.</span><span class='qd'><b>groups root</b>: this lists groups for root specifically, not the current user, and omits UID.</span><span class='qd'><b>getent passwd</b>: this dumps the full passwd database rather than summarizing the current user's identity and groups.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-031", domain:2, obj:"2.2", diff:"hard", q:"You must set user 'erin' so her account itself expires (becomes unusable) on 2026-12-31, independent of password aging. Which command sets the account expiration date?", options:["chage -E 2026-12-31 erin","chage -M 365 erin","usermod -e 365 erin","passwd -x 2026-12-31 erin"], answer:0, explain:"<strong>chage -E sets the account expiration date, after which the account is disabled regardless of password state.</strong> The date format YYYY-MM-DD is accepted directly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chage -M 365 erin</b>: -M sets the maximum password age in days, which is password aging, not account expiration.</span><span class='qd'><b>usermod -e 365 erin</b>: usermod -e expects a date (or days since epoch); '365' would be interpreted as day 365 after the epoch, not 2026-12-31.</span><span class='qd'><b>passwd -x 2026-12-31 erin</b>: passwd -x sets maximum password-age days and expects a number, not a calendar date.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-032", domain:2, obj:"2.2", diff:"medium", q:"A script must look up an account using NSS so it works whether the user is local or comes from LDAP. Which command queries the passwd database through NSS for user 'svcacct'?", options:["getent passwd svcacct","cat /etc/passwd | grep svcacct","id -u svcacct","grep svcacct /etc/shadow"], answer:0, explain:"<strong>getent queries the configured NSS sources, so it returns the entry whether it lives in /etc/passwd or in LDAP.</strong> This makes scripts work uniformly across local and directory accounts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cat /etc/passwd | grep svcacct</b>: this only searches the local file and misses LDAP-provided accounts.</span><span class='qd'><b>id -u svcacct</b>: id does resolve via NSS but returns only the numeric UID, not the full passwd entry the script needs.</span><span class='qd'><b>grep svcacct /etc/shadow</b>: shadow holds password data, not the passwd account entry, and is local-only.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-033", domain:2, obj:"2.2", diff:"medium", q:"You changed user 'ivan' primary group from 'ivan' to 'developers'. New files he creates should now be group-owned by developers. Which command sets his primary group?", options:["usermod -aG developers ivan","usermod -g developers ivan","gpasswd -a ivan developers","newgrp developers"], answer:1, explain:"<strong>usermod -g sets the primary group, which becomes the default group ownership for new files.</strong> Lowercase -g specifically changes the primary group entry in /etc/passwd.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>usermod -aG developers ivan</b>: -aG adds a supplementary group; it does not change the primary group used for new files.</span><span class='qd'><b>gpasswd -a ivan developers</b>: this adds ivan as a supplementary member, not as primary.</span><span class='qd'><b>newgrp developers</b>: newgrp only changes the group for the current shell session, not the persistent primary group.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-034", domain:2, obj:"2.2", diff:"easy", q:"Which command interactively sets or changes the password for the current user when run without arguments?", options:["passwd","chage","useradd","chpasswd"], answer:0, explain:"<strong>passwd with no arguments prompts the invoking user to change their own password.</strong> Root can pass a username to change someone else's password.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chage</b>: chage manages password aging, not the password value itself.</span><span class='qd'><b>useradd</b>: useradd creates new accounts and does not interactively set the current user's password.</span><span class='qd'><b>chpasswd</b>: chpasswd reads user:password pairs from stdin for batch updates, not an interactive single-user change.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-035", domain:2, obj:"2.2", diff:"medium", q:"A teammate ran 'useradd jane' on a system where useradd does not create home directories by default, and now jane has no home directory. Which single command creates the missing home directory and populates it from /etc/skel for the existing user?", options:["mkdir /home/jane","useradd -m jane","usermod -m -d /home/jane jane","cp -r /etc/skel /home/jane"], answer:2, explain:"<strong>usermod -m -d /home/jane moves/creates the home directory for the existing user and -m ensures contents (including skel-based files if newly created) are handled.</strong> In practice combined with skel population, this is the supported way to fix an existing account's home directory path.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mkdir /home/jane</b>: this creates an empty directory but does not update the account, set ownership, or copy skel files.</span><span class='qd'><b>useradd -m jane</b>: useradd fails because jane already exists.</span><span class='qd'><b>cp -r /etc/skel /home/jane</b>: this copies skel files but leaves ownership as root and does not register the home path for the account.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-036", domain:2, obj:"2.3", diff:"medium", q:"A runaway process named 'render' is consuming CPU. You found its PID is 4821 and a normal termination request did not stop it after 20 seconds. Which command forcibly kills it?", options:["kill -1 4821","kill -9 4821","kill -15 4821","kill -HUP 4821"], answer:1, explain:"<strong>kill -9 sends SIGKILL, which the kernel enforces immediately and a process cannot catch or ignore.</strong> After a graceful SIGTERM failed, SIGKILL is the forcible stop.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>kill -1 4821</b>: signal 1 is SIGHUP, often used to reload config, not to forcibly kill.</span><span class='qd'><b>kill -15 4821</b>: signal 15 is SIGTERM, the graceful request that already failed.</span><span class='qd'><b>kill -HUP 4821</b>: SIGHUP is the same as -1 and does not guarantee termination.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-037", domain:2, obj:"2.3", diff:"medium", q:"You need a recurring job that runs /usr/local/bin/cleanup.sh every day at 02:30. Which crontab line schedules it correctly?", options:["30 2 * * * /usr/local/bin/cleanup.sh","2 30 * * * /usr/local/bin/cleanup.sh","* * 30 2 * /usr/local/bin/cleanup.sh","30 2 * * 0 /usr/local/bin/cleanup.sh"], answer:0, explain:"<strong>The cron fields are minute hour day-of-month month day-of-week, so '30 2 * * *' means 02:30 every day.</strong> Minute 30 and hour 2 with wildcards for the rest gives a daily 2:30 AM run.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>2 30 * * * /usr/local/bin/cleanup.sh</b>: this sets minute 2 and hour 30, but hour 30 is invalid.</span><span class='qd'><b>* * 30 2 * /usr/local/bin/cleanup.sh</b>: this runs every minute on day-of-month 30 in February, not daily at 2:30.</span><span class='qd'><b>30 2 * * 0 /usr/local/bin/cleanup.sh</b>: the trailing 0 restricts it to Sundays only.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-038", domain:2, obj:"2.3", diff:"medium", q:"A long backup must run once tonight at 11 PM, not on a recurring schedule. Which tool is designed for a single future execution?", options:["cron","systemd timer","at","nohup"], answer:2, explain:"<strong>at schedules a command to run once at a specified future time.</strong> 'at 23:00' queues the job for a single execution tonight.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cron</b>: cron is built for recurring schedules, not one-off runs.</span><span class='qd'><b>systemd timer</b>: timers are typically used for recurring or boot-relative scheduling and require unit files, more than a one-shot needs.</span><span class='qd'><b>nohup</b>: nohup just keeps a command running after logout; it does not schedule a future start time.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-039", domain:2, obj:"2.3", diff:"medium", q:"You want a real-time, continuously updating view of CPU and memory usage per process to spot what is loading the system. Which command provides this interactive view?", options:["ps aux","uptime","vmstat 1","top"], answer:3, explain:"<strong>top gives a live, self-refreshing table of processes sorted by resource usage.</strong> It updates continuously and lets you sort and kill interactively.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ps aux</b>: ps prints a one-time snapshot, not a continuously updating view.</span><span class='qd'><b>uptime</b>: uptime shows load averages and time, not per-process usage.</span><span class='qd'><b>vmstat 1</b>: vmstat reports system-wide stats each second but not per-process CPU/memory breakdowns.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-040", domain:2, obj:"2.3", diff:"hard", q:"You want to start a CPU-intensive compression job at a lowered scheduling priority so it does not impact interactive work. Which command launches it with a higher (less favorable) nice value?", options:["nice -n -10 tar czf big.tgz /data","renice 10 tar","ionice -c3 tar czf big.tgz /data","nice -n 10 tar czf big.tgz /data"], answer:3, explain:"<strong>nice -n 10 starts the process with a positive nice value, lowering its CPU scheduling priority so interactive tasks win.</strong> Higher nice numbers mean nicer (lower priority).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nice -n -10 tar czf big.tgz /data</b>: a negative nice value raises priority, the opposite of what is wanted, and requires root.</span><span class='qd'><b>renice 10 tar</b>: renice operates on an existing PID or matched process, not on launching a new command by name like this.</span><span class='qd'><b>ionice -c3 tar czf big.tgz /data</b>: ionice changes I/O scheduling class, not CPU nice value.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-041", domain:2, obj:"2.3", diff:"medium", q:"A process started in the foreground is now blocking your terminal. You press Ctrl+Z, then want it to continue running in the background. Which sequence is correct?", options:["Ctrl+Z then 'fg'","Ctrl+Z then 'bg'","Ctrl+C then 'bg'","'kill -CONT %1' only"], answer:1, explain:"<strong>Ctrl+Z suspends the job with SIGTSTP, and bg resumes it in the background.</strong> The process then runs without holding the terminal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ctrl+Z then 'fg'</b>: fg resumes the job in the foreground, again blocking the terminal.</span><span class='qd'><b>Ctrl+C then 'bg'</b>: Ctrl+C sends SIGINT which usually terminates the job, so there is nothing left to background.</span><span class='qd'><b>'kill -CONT %1' only</b>: sending SIGCONT without bg resumes it but may still be tied to the terminal as a stopped-then-continued foreground job depending on state; bg is the correct shell action.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-042", domain:2, obj:"2.3", diff:"medium", q:"You need to find the PID of all processes whose command name is exactly 'nginx' to inspect them. Which command returns those PIDs?", options:["pkill nginx","pidof -s nginx","pgrep nginx","ps nginx"], answer:2, explain:"<strong>pgrep searches the process table by name and prints matching PIDs.</strong> 'pgrep nginx' lists every PID whose command matches, which is what you need to inspect them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>pkill nginx</b>: pkill sends a signal (default SIGTERM) to matching processes rather than just listing PIDs.</span><span class='qd'><b>pidof -s nginx</b>: -s returns only a single PID, not all of them.</span><span class='qd'><b>ps nginx</b>: ps does not accept a process name as a positional selector like that; it would misinterpret the argument.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-043", domain:2, obj:"2.3", diff:"hard", q:"A web server master process holds PID 1200. After editing its config you want it to reload configuration gracefully without a full restart, and you know it handles SIGHUP for reloads. Which command sends that signal?", options:["kill -HUP 1200","kill -9 1200","kill -STOP 1200","kill -INT 1200"], answer:0, explain:"<strong>kill -HUP sends SIGHUP, which many daemons interpret as a request to reload their configuration.</strong> This avoids dropping connections that a full restart would cause.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>kill -9 1200</b>: SIGKILL forcibly terminates the process instead of reloading it.</span><span class='qd'><b>kill -STOP 1200</b>: SIGSTOP pauses the process rather than reloading config.</span><span class='qd'><b>kill -INT 1200</b>: SIGINT typically interrupts/terminates and is not the conventional reload signal.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-044", domain:2, obj:"2.3", diff:"medium", q:"You ran a command with '&' and then closed your SSH session, and the job died. Next time you want a command to survive disconnection. Which approach prevents the SIGHUP from killing it on logout?", options:["Run it with 'nice command &'","Run it with 'time command &'","Run it with 'nohup command &'","Run it with 'exec command'"], answer:2, explain:"<strong>nohup makes the command ignore SIGHUP, so closing the terminal does not kill it.</strong> Combined with & to background it, the job keeps running after logout.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Run it with 'nice command &'</b>: nice only changes scheduling priority and does not block SIGHUP.</span><span class='qd'><b>Run it with 'time command &'</b>: time just measures duration and offers no SIGHUP protection.</span><span class='qd'><b>Run it with 'exec command'</b>: exec replaces the shell with the command, which would die with the terminal just the same.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-045", domain:2, obj:"2.3", diff:"medium", q:"A user 'bob' has a personal cron job that is misbehaving. As root you need to view bob's crontab to inspect it. Which command displays it?", options:["crontab -l -u bob","crontab -e bob","cat /etc/crontab","crontab -r -u bob"], answer:0, explain:"<strong>crontab -l -u bob lists the crontab belonging to user bob.</strong> The -u flag selects the target user and -l lists the entries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>crontab -e bob</b>: -e opens an editor to modify (risking changes) and the username should follow -u.</span><span class='qd'><b>cat /etc/crontab</b>: this shows the system-wide crontab, not bob's personal user crontab.</span><span class='qd'><b>crontab -r -u bob</b>: -r removes bob's crontab entirely, which is destructive.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-046", domain:2, obj:"2.3", diff:"medium", q:"You see a process stuck in state 'Z' in top output and want to understand it. What does a zombie (Z) process indicate?", options:["A process actively using 100% CPU","A process swapped entirely to disk","A process waiting on disk I/O uninterruptibly","A terminated child whose exit status has not yet been reaped by its parent"], answer:3, explain:"<strong>A zombie is a finished child process whose parent has not yet called wait() to collect its exit status.</strong> It holds only a process table entry and consumes no CPU or memory beyond that slot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A process actively using 100% CPU</b>: a running CPU-bound process shows state R, not Z.</span><span class='qd'><b>A process swapped entirely to disk</b>: swapping relates to memory residency, not the zombie state.</span><span class='qd'><b>A process waiting on disk I/O uninterruptibly</b>: that is state D (uninterruptible sleep), not Z.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-047", domain:2, obj:"2.3", diff:"medium", q:"You want to change the priority of an already-running process with PID 3300 to a nicer value of 15 to reduce its CPU contention. Which command does this?", options:["nice -n 15 3300","renice -n 15 -p 3300","renice 15 nice","nice 15 -p 3300"], answer:1, explain:"<strong>renice adjusts the nice value of an existing process by PID.</strong> 'renice -n 15 -p 3300' sets PID 3300 to nice 15, lowering its scheduling priority.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nice -n 15 3300</b>: nice launches a new command; 3300 would be treated as a command name, not a PID.</span><span class='qd'><b>renice 15 nice</b>: 'nice' here is not a PID and the syntax is malformed.</span><span class='qd'><b>nice 15 -p 3300</b>: nice does not take -p; renice is the tool for existing PIDs.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-048", domain:2, obj:"2.3", diff:"hard", q:"You scheduled 'at 16:00' earlier and now want to list pending at jobs and then remove job number 3. Which two commands accomplish this?", options:["at -l, then at -d job3","atq, then atrm 3","crontab -l, then crontab -r 3","jobs, then kill %3"], answer:1, explain:"<strong>atq lists the pending at jobs with their numbers, and atrm 3 deletes job number 3.</strong> These are the standard at queue management commands.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>at -l, then at -d job3</b>: while at -l aliases atq and at -d aliases atrm, the argument should be the bare job number (3), not 'job3'.</span><span class='qd'><b>crontab -l, then crontab -r 3</b>: crontab manages cron, not the at queue.</span><span class='qd'><b>jobs, then kill %3</b>: jobs lists shell job-control jobs in the current shell, not queued at jobs.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-049", domain:2, obj:"2.3", diff:"medium", q:"You need a snapshot of all processes system-wide, including those without a controlling terminal, in BSD-style output. Which command is correct?", options:["ps -e --forest","ps T","ps aux","ps l"], answer:2, explain:"<strong>ps aux uses BSD-style options to list all processes for all users, including those without a controlling terminal.</strong> 'a' and 'x' together show everything, with 'u' adding user-oriented columns.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ps -e --forest</b>: -e is UNIX-style (not BSD) and --forest draws a tree, which is a different output style than requested.</span><span class='qd'><b>ps T</b>: T restricts to processes associated with the current terminal, the opposite of including terminal-less ones.</span><span class='qd'><b>ps l</b>: l gives a long BSD format but without 'a' and 'x' it does not list all processes for all users.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-050", domain:2, obj:"2.3", diff:"easy", q:"A job is running in the foreground and you simply want to terminate it immediately from the keyboard. Which key combination sends SIGINT to stop it?", options:["Ctrl+C","Ctrl+Z","Ctrl+D","Ctrl+\\"], answer:0, explain:"<strong>Ctrl+C sends SIGINT to the foreground process, requesting it to terminate.</strong> Most programs exit on SIGINT, making it the standard interrupt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ctrl+Z</b>: Ctrl+Z sends SIGTSTP, which suspends the job rather than terminating it.</span><span class='qd'><b>Ctrl+D</b>: Ctrl+D signals end-of-input (EOF), not a termination signal.</span><span class='qd'><b>Ctrl+\\</b>: Ctrl+\\ sends SIGQUIT, which terminates and dumps core, not the standard SIGINT requested.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-051", domain:2, obj:"2.4", diff:"medium", q:"On a Rocky Linux 9 system you must install the 'httpd' package and automatically pull in its dependencies from configured repositories. Which command is correct?", options:["rpm -i httpd","dnf install httpd","dpkg -i httpd","yum localinstall httpd.rpm"], answer:1, explain:"<strong>dnf install resolves and installs dependencies from the configured repositories.</strong> On modern RHEL-family systems dnf is the high-level package manager that handles dependency resolution automatically.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rpm -i httpd</b>: rpm installs a local .rpm file and does not resolve or fetch dependencies from repos.</span><span class='qd'><b>dpkg -i httpd</b>: dpkg is for Debian-based systems, not RHEL/Rocky.</span><span class='qd'><b>yum localinstall httpd.rpm</b>: localinstall targets a local file, not a named package pulled from a repo, and assumes you already have the rpm.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-052", domain:2, obj:"2.4", diff:"medium", q:"On Ubuntu you need to refresh the package index from all repositories before upgrading anything. Which command updates the local package lists only?", options:["apt upgrade","apt update","apt install --refresh","apt full-upgrade"], answer:1, explain:"<strong>apt update downloads the latest package lists from the repositories.</strong> It refreshes metadata so subsequent installs and upgrades see current versions, without changing installed packages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>apt upgrade</b>: upgrade installs newer versions of already-installed packages; it does not just refresh the index.</span><span class='qd'><b>apt install --refresh</b>: this is not a valid way to refresh only the package lists.</span><span class='qd'><b>apt full-upgrade</b>: full-upgrade upgrades packages and may remove some to satisfy dependencies, again not a metadata-only refresh.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-053", domain:2, obj:"2.4", diff:"medium", q:"You downloaded 'monitoring-agent-2.1.x86_64.rpm' to a RHEL host that has no network repo access. You must install just this local file along with its already-present dependencies. Which command is appropriate?", options:["dnf download monitoring-agent","rpm -q monitoring-agent-2.1.x86_64.rpm","apt install ./monitoring-agent-2.1.x86_64.rpm","dnf install ./monitoring-agent-2.1.x86_64.rpm"], answer:3, explain:"<strong>dnf install with a path to a local .rpm installs the file and still resolves dependencies, using local files or repos as available.</strong> Pointing dnf at the file path is the modern way to install a downloaded rpm with dependency handling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dnf download monitoring-agent</b>: download only fetches the package; it does not install it.</span><span class='qd'><b>rpm -q monitoring-agent-2.1.x86_64.rpm</b>: -q queries whether a package is installed; it does not install anything.</span><span class='qd'><b>apt install ./monitoring-agent-2.1.x86_64.rpm</b>: apt is for Debian systems and cannot install rpm packages.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-054", domain:2, obj:"2.4", diff:"hard", q:"You suspect a stray file on disk belongs to an installed RPM package and want to discover which package owns /usr/sbin/sshd. Which command answers this?", options:["rpm -ql sshd","rpm -qf /usr/sbin/sshd","rpm -V sshd","dnf list /usr/sbin/sshd"], answer:1, explain:"<strong>rpm -qf queries which package owns a given file.</strong> 'rpm -qf /usr/sbin/sshd' returns the openssh-server package that provides that binary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rpm -ql sshd</b>: -ql lists the files a named package owns, the reverse of finding the owner of a file path.</span><span class='qd'><b>rpm -V sshd</b>: -V verifies a package against its metadata, not file ownership lookup.</span><span class='qd'><b>dnf list /usr/sbin/sshd</b>: dnf list expects package name patterns, not arbitrary file paths.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-055", domain:2, obj:"2.4", diff:"medium", q:"On a Debian server you must completely remove the 'apache2' package including its configuration files so a clean reinstall starts fresh. Which command removes the package and its config?", options:["apt remove apache2","apt purge apache2","dpkg -r apache2","apt autoremove apache2"], answer:1, explain:"<strong>apt purge removes the package and its configuration files.</strong> Plain remove leaves config behind, so purge is required for a fully clean state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>apt remove apache2</b>: remove deletes the package binaries but leaves configuration files in place.</span><span class='qd'><b>dpkg -r apache2</b>: dpkg -r removes the package but, like remove, keeps config files (purge is dpkg -P).</span><span class='qd'><b>apt autoremove apache2</b>: autoremove targets unused dependencies and does not purge the named package's config.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-056", domain:2, obj:"2.4", diff:"medium", q:"A Python project needs the 'requests' library installed only for the current user without touching system packages or requiring root. Which command best fits?", options:["sudo dnf install python3-requests","rpm -i requests","pip install --user requests","apt install python3-requests"], answer:2, explain:"<strong>pip install --user installs the package into the user's home directory, needing no root and not affecting system packages.</strong> This isolates the dependency to the current user.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sudo dnf install python3-requests</b>: this installs system-wide as root, the opposite of a user-only install.</span><span class='qd'><b>rpm -i requests</b>: rpm installs OS packages, not PyPI libraries, and 'requests' is not an rpm file here.</span><span class='qd'><b>apt install python3-requests</b>: apt installs a system package with root, again not a user-scoped pip install.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-057", domain:2, obj:"2.4", diff:"medium", q:"You need to add a new third-party DNF repository by placing a definition so dnf will use it. Where should the .repo file be created on a RHEL-family system?", options:["/etc/apt/sources.list.d/","/var/lib/dnf/repos/","/usr/share/dnf/","/etc/yum.repos.d/"], answer:3, explain:"<strong>DNF and YUM read repository definitions from .repo files in /etc/yum.repos.d/.</strong> Dropping a properly formatted file there makes the repo available.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/apt/sources.list.d/</b>: that directory is for APT on Debian-based systems, not DNF.</span><span class='qd'><b>/var/lib/dnf/repos/</b>: /var/lib/dnf holds state and cache data, not user-defined repo configs.</span><span class='qd'><b>/usr/share/dnf/</b>: this is for dnf program data, not repository configuration files.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-058", domain:2, obj:"2.4", diff:"hard", q:"After installing a package you want to verify that none of its installed files have been altered from what the RPM database expects. Which command checks file integrity for package 'coreutils'?", options:["rpm -qa coreutils","rpm -qi coreutils","rpm --rebuilddb","rpm -V coreutils"], answer:3, explain:"<strong>rpm -V verifies installed files against the package metadata, reporting size, checksum, permission, or ownership changes.</strong> This is exactly an integrity check of the package's files.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rpm -qa coreutils</b>: -qa lists installed packages matching the name; it does not verify file integrity.</span><span class='qd'><b>rpm -qi coreutils</b>: -qi shows package information like version and license, not integrity status.</span><span class='qd'><b>rpm --rebuilddb</b>: this rebuilds the RPM database indexes and does not verify any package's files.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-059", domain:2, obj:"2.4", diff:"medium", q:"You want to search the configured repositories for any available package whose name or summary mentions 'nginx' before deciding what to install on a RHEL system. Which command searches repos?", options:["dnf list installed | grep nginx","rpm -qa | grep nginx","dnf search nginx","dnf info nginx"], answer:2, explain:"<strong>dnf search queries repository metadata for packages whose name or summary matches the term.</strong> This helps discover available packages before installing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dnf list installed | grep nginx</b>: this only shows packages already installed, not what is available to install.</span><span class='qd'><b>rpm -qa | grep nginx</b>: rpm -qa also lists only installed packages, not repository contents.</span><span class='qd'><b>dnf info nginx</b>: info shows details for an exact package name; it does not search by keyword across packages.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-060", domain:2, obj:"2.4", diff:"medium", q:"A desktop user wants to install the sandboxed GIMP application from Flathub without affecting system libraries. Which command installs the Flatpak app?", options:["dnf install flatpak-gimp","flatpak install flathub org.gimp.GIMP","snap install gimp --classic","apt install org.gimp.GIMP"], answer:1, explain:"<strong>flatpak install flathub org.gimp.GIMP installs the sandboxed app from the Flathub remote.</strong> Flatpak bundles dependencies, isolating the app from system libraries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dnf install flatpak-gimp</b>: there is no such dnf package; flatpak apps are installed via the flatpak command, not dnf.</span><span class='qd'><b>snap install gimp --classic</b>: that is Snap, a different packaging system, not Flatpak as requested.</span><span class='qd'><b>apt install org.gimp.GIMP</b>: apt does not use Flatpak application IDs and cannot install Flathub apps.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-061", domain:2, obj:"2.4", diff:"medium", q:"You must list every file installed by the already-installed RPM package 'bash' to find where its docs live. Which command lists those files?", options:["rpm -qf bash","dpkg -L bash","rpm -qa bash","rpm -ql bash"], answer:3, explain:"<strong>rpm -ql lists all files contained in an installed package.</strong> 'rpm -ql bash' enumerates every path the bash package owns, including documentation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rpm -qf bash</b>: -qf finds the package owning a file path, not the files in a package.</span><span class='qd'><b>dpkg -L bash</b>: dpkg is for Debian systems; on an RPM host it is not the right tool.</span><span class='qd'><b>rpm -qa bash</b>: -qa lists installed package names matching the pattern, not the files within them.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-062", domain:2, obj:"2.4", diff:"hard", q:"On Ubuntu you installed a .deb manually with 'dpkg -i app.deb' but it failed because of missing dependencies and is now half-configured. Which command resolves and installs the missing dependencies to fix the broken state?", options:["dpkg --configure app","apt install -f","apt purge app","dpkg -r app"], answer:1, explain:"<strong>apt install -f (fix-broken) downloads and installs the missing dependencies to complete the configuration.</strong> It repairs the broken state left by a dpkg install that lacked dependencies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dpkg --configure app</b>: this retries configuration but still fails because the dependencies themselves are not installed.</span><span class='qd'><b>apt purge app</b>: purging removes the package rather than fixing the dependency problem.</span><span class='qd'><b>dpkg -r app</b>: removing the package abandons the install instead of completing it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-063", domain:2, obj:"2.4", diff:"medium", q:"After enabling a new repository you want dnf to refresh its cached metadata so the latest package data is used. Which command forces a metadata cache refresh?", options:["dnf update","dnf reinstall","dnf clean all && dnf makecache","dnf history undo last"], answer:2, explain:"<strong>dnf clean all clears cached metadata and dnf makecache rebuilds it from the repositories.</strong> Together they ensure dnf reads current repo data, which is useful after changing repos.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dnf update</b>: update upgrades installed packages and refreshes metadata as a side effect, but it also changes the system rather than just refreshing the cache.</span><span class='qd'><b>dnf reinstall</b>: reinstall reinstalls packages and does not specifically clear and rebuild metadata cache.</span><span class='qd'><b>dnf history undo last</b>: this reverts the last transaction, unrelated to metadata caching.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-064", domain:2, obj:"2.4", diff:"easy", q:"On a Debian-based system, which low-level tool installs, removes, and queries individual .deb packages but does not automatically resolve dependencies from repositories?", options:["apt","rpm","dpkg","dnf"], answer:2, explain:"<strong>dpkg is the low-level Debian package tool that handles individual .deb files without resolving repository dependencies.</strong> apt sits on top of dpkg to add dependency resolution.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>apt</b>: apt is the high-level tool that does resolve dependencies, so it does not match 'does not automatically resolve'.</span><span class='qd'><b>rpm</b>: rpm is the low-level tool for RPM-based distributions, not Debian.</span><span class='qd'><b>dnf</b>: dnf is the high-level RPM-family manager, not a Debian .deb tool.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-065", domain:2, obj:"2.4", diff:"medium", q:"You need to see detailed information about an available package 'vim-enhanced' (version, size, summary, license) from the repos without installing it. Which command shows this?", options:["dnf list vim-enhanced","rpm -ql vim-enhanced","dnf provides vim-enhanced","dnf info vim-enhanced"], answer:3, explain:"<strong>dnf info displays detailed metadata such as version, architecture, size, license, and description for a package.</strong> It works for available packages without installing them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dnf list vim-enhanced</b>: list shows name, version, and repo in a brief line, not the full detailed info.</span><span class='qd'><b>rpm -ql vim-enhanced</b>: -ql lists files of an installed package and fails if it is not installed.</span><span class='qd'><b>dnf provides vim-enhanced</b>: provides finds which package supplies a file or capability, not package details.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-066", domain:2, obj:"2.4", diff:"hard", q:"A dnf update introduced a regression and you need to roll back to the state before that transaction. You found the transaction ID is 42. Which command reverts it?", options:["dnf downgrade","dnf rollback 42","dnf history redo 42","dnf history undo 42"], answer:3, explain:"<strong>dnf history undo 42 reverses the actions performed in transaction 42, restoring the prior package versions.</strong> dnf records each transaction so it can be undone by ID.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dnf downgrade</b>: downgrade without a target only steps one package back and does not revert a whole transaction by ID.</span><span class='qd'><b>dnf rollback 42</b>: dnf does not use a 'rollback' subcommand; the correct verb is history undo.</span><span class='qd'><b>dnf history redo 42</b>: redo re-applies a transaction, which would reintroduce the regression.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-067", domain:2, obj:"2.5", diff:"medium", q:"You deployed a new web service unit and need it to start now AND start automatically on every boot. Which single systemctl command accomplishes both?", options:["systemctl enable --now webapp.service","systemctl start webapp.service","systemctl restart webapp.service","systemctl reload webapp.service"], answer:0, explain:"<strong>systemctl enable --now both enables the unit for boot and starts it immediately.</strong> The --now flag combines enable with an immediate start in one command.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl start webapp.service</b>: start runs it now but does not enable it for boot.</span><span class='qd'><b>systemctl restart webapp.service</b>: restart stops and starts the running service but does not configure boot-time start.</span><span class='qd'><b>systemctl reload webapp.service</b>: reload re-reads config of a running service and does not affect boot enablement.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-068", domain:2, obj:"2.5", diff:"medium", q:"A service named 'api' failed to start. You need to see the most recent log entries specifically for that unit to diagnose it. Which command shows them?", options:["journalctl -u api.service","journalctl -k","journalctl -f /var/log/api","systemctl cat api.service"], answer:0, explain:"<strong>journalctl -u api.service filters the journal to entries from the api unit.</strong> The -u flag scopes output to that service so you see only its messages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>journalctl -k</b>: -k shows kernel ring buffer messages, not a specific service's logs.</span><span class='qd'><b>journalctl -f /var/log/api</b>: journalctl reads the systemd journal, not arbitrary log file paths, so this is invalid usage.</span><span class='qd'><b>systemctl cat api.service</b>: cat displays the unit file contents, not its runtime logs.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-069", domain:2, obj:"2.5", diff:"hard", q:"You edited /etc/systemd/system/myapp.service to change its ExecStart line. The change is not taking effect on restart. What must you run before restarting so systemd picks up the modified unit file?", options:["systemctl reload myapp.service","systemctl reset-failed myapp.service","systemctl mask myapp.service","systemctl daemon-reload"], answer:3, explain:"<strong>systemctl daemon-reload reloads systemd's view of unit files after you edit them on disk.</strong> Without it, systemd keeps using the cached old unit definition even when you restart.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl reload myapp.service</b>: reload signals the service to re-read its own app config, not systemd to re-read the unit file.</span><span class='qd'><b>systemctl reset-failed myapp.service</b>: reset-failed only clears the failed state counter, not the unit cache.</span><span class='qd'><b>systemctl mask myapp.service</b>: mask makes the unit unstartable, which is the opposite of what you want.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-070", domain:2, obj:"2.5", diff:"medium", q:"You want to confirm whether the 'chronyd' service is currently active (running) and see a short status with the most recent log lines. Which command is most appropriate?", options:["systemctl status chronyd","systemctl is-enabled chronyd","systemctl list-units --all","journalctl --disk-usage"], answer:0, explain:"<strong>systemctl status shows whether the unit is active, its main PID, and recent log lines.</strong> It is the standard one-stop view of a service's current state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl is-enabled chronyd</b>: is-enabled reports only boot enablement, not whether it is currently running.</span><span class='qd'><b>systemctl list-units --all</b>: this lists many units and is not a focused status of chronyd.</span><span class='qd'><b>journalctl --disk-usage</b>: this reports how much space the journal uses, unrelated to service status.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-071", domain:2, obj:"2.5", diff:"medium", q:"A maintenance window requires that the 'bluetooth' service never start, even if another package tries to enable or start it. Which command makes it impossible to start until reversed?", options:["systemctl mask bluetooth","systemctl disable bluetooth","systemctl stop bluetooth","systemctl reload bluetooth"], answer:0, explain:"<strong>systemctl mask links the unit to /dev/null so it cannot be started by any means until unmasked.</strong> This is stronger than disable, which only removes boot links.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl disable bluetooth</b>: disable stops it from starting at boot but it can still be started manually or as a dependency.</span><span class='qd'><b>systemctl stop bluetooth</b>: stop halts it now but does not prevent future starts.</span><span class='qd'><b>systemctl reload bluetooth</b>: reload just re-reads config and has no effect on preventing starts.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-072", domain:2, obj:"2.5", diff:"medium", q:"You want to follow new journal messages in real time across the whole system as they are written, similar to tail -f. Which command does this?", options:["journalctl -f","journalctl -r","journalctl --since today","journalctl -b -1"], answer:0, explain:"<strong>journalctl -f follows the journal, printing new entries live as they arrive.</strong> It is the journal equivalent of tail -f.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>journalctl -r</b>: -r shows entries in reverse (newest first) but does not stream new ones.</span><span class='qd'><b>journalctl --since today</b>: this shows everything from today, then exits, without following.</span><span class='qd'><b>journalctl -b -1</b>: -b -1 shows logs from the previous boot, a historical view, not live follow.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-073", domain:2, obj:"2.5", diff:"hard", q:"You need a recurring task managed by systemd that runs a maintenance script 15 minutes after every boot and then daily. You created maintenance.service. What additional unit type do you create to schedule it the systemd-native way?", options:["A maintenance.timer unit","A maintenance.path unit","A maintenance.socket unit","A cron entry referencing the service"], answer:0, explain:"<strong>A .timer unit schedules an associated .service, supporting calendar and boot-relative triggers like OnBootSec and OnCalendar.</strong> This is the systemd-native alternative to cron.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A maintenance.path unit</b>: path units trigger on filesystem changes, not time schedules.</span><span class='qd'><b>A maintenance.socket unit</b>: socket units activate services on network/socket connections, not on a schedule.</span><span class='qd'><b>A cron entry referencing the service</b>: while possible, the question asks for the systemd-native scheduling mechanism, which is a timer.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-074", domain:2, obj:"2.5", diff:"medium", q:"The journal is consuming too much disk space. You want to retain only the most recent 500 MB of journal data and discard older entries now. Which command does this?", options:["journalctl --rotate","journalctl --vacuum-size=500M","journalctl --flush","journalctl --vacuum-time=500M"], answer:1, explain:"<strong>journalctl --vacuum-size=500M deletes old archived journal files until the journal is under 500 MB.</strong> It immediately reclaims space by trimming the oldest data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>journalctl --rotate</b>: rotate starts a new journal file but does not delete old data to a size target.</span><span class='qd'><b>journalctl --flush</b>: flush moves runtime journal data to persistent storage, not a cleanup.</span><span class='qd'><b>journalctl --vacuum-time=500M</b>: vacuum-time expects a time value (like 2weeks), not a size like 500M.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-075", domain:2, obj:"2.5", diff:"medium", q:"On a headless server you want to ensure the system boots to a non-graphical multi-user state rather than a graphical desktop. Which command sets the default target to multi-user?", options:["systemctl set-default multi-user.target","systemctl isolate graphical.target","systemctl set-default graphical.target","systemctl get-default"], answer:0, explain:"<strong>systemctl set-default multi-user.target makes the system boot into the non-graphical multi-user state.</strong> This is the systemd equivalent of the old runlevel 3.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl isolate graphical.target</b>: isolate switches the current session and to the graphical target at that, not the persistent default.</span><span class='qd'><b>systemctl set-default graphical.target</b>: this sets the graphical (desktop) target, the opposite of what is wanted.</span><span class='qd'><b>systemctl get-default</b>: get-default only reports the current default; it does not change it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-076", domain:2, obj:"2.5", diff:"medium", q:"A service shows as 'failed' in systemctl. After fixing the underlying issue and restarting it, the unit still appears in the failed list. Which command clears the failed state so monitoring sees it clean?", options:["systemctl daemon-reload","systemctl reset-failed myservice","systemctl disable myservice","systemctl kill myservice"], answer:1, explain:"<strong>systemctl reset-failed clears the recorded failed state for the unit.</strong> After a genuine recovery this removes the stale failed marker.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl daemon-reload</b>: daemon-reload reloads unit files but does not clear a unit's failed state.</span><span class='qd'><b>systemctl disable myservice</b>: disable affects boot enablement, not the failed-state flag.</span><span class='qd'><b>systemctl kill myservice</b>: kill sends a signal to the service processes and would not clear a failed marker.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-077", domain:2, obj:"2.5", diff:"hard", q:"You want to view only error-priority and worse messages from the current boot to triage problems quickly. Which journalctl command filters by priority?", options:["journalctl -b -n err","journalctl -p 7 -b","journalctl --priority=info","journalctl -b -p err"], answer:3, explain:"<strong>journalctl -b limits to the current boot and -p err shows messages at error priority and higher (more severe).</strong> Priority filtering with -p err surfaces err, crit, alert, and emerg.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>journalctl -b -n err</b>: -n expects a number of lines, not a priority name, so 'err' is invalid here.</span><span class='qd'><b>journalctl -p 7 -b</b>: priority 7 is debug, the least severe, which floods output rather than filtering to errors.</span><span class='qd'><b>journalctl --priority=info</b>: info-level includes a lot of non-error noise, not just errors and worse.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-078", domain:2, obj:"2.5", diff:"medium", q:"You created a custom unit by placing a file in /etc/systemd/system/backup.service and want to confirm exactly which unit file systemd will use, including any drop-ins. Which command displays the effective unit file and its overrides?", options:["systemctl show backup.service","cat /lib/systemd/system/backup.service","systemctl cat backup.service","systemctl list-unit-files"], answer:2, explain:"<strong>systemctl cat shows the unit file content and any drop-in override files that apply.</strong> It reveals the effective configuration, including which paths contribute.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl show backup.service</b>: show dumps resolved property key=value pairs, not the readable unit file with drop-ins.</span><span class='qd'><b>cat /lib/systemd/system/backup.service</b>: this only reads one possible location and misses the /etc override and drop-ins.</span><span class='qd'><b>systemctl list-unit-files</b>: this lists units and their enablement state, not file contents.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-079", domain:2, obj:"2.5", diff:"medium", q:"You need to immediately switch the running system to rescue (single-user) mode for emergency maintenance without rebooting. Which command does this?", options:["systemctl set-default rescue.target","systemctl isolate rescue.target","systemctl enable rescue.target","systemctl start multi-user.target"], answer:1, explain:"<strong>systemctl isolate rescue.target transitions the running system to rescue mode now, stopping units not part of that target.</strong> isolate changes the active state immediately.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl set-default rescue.target</b>: set-default only changes what boots next time, not the running state.</span><span class='qd'><b>systemctl enable rescue.target</b>: enable manages dependencies for boot, not an immediate switch.</span><span class='qd'><b>systemctl start multi-user.target</b>: this starts the multi-user target's units but does not isolate into rescue mode.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-080", domain:2, obj:"2.5", diff:"easy", q:"Which command lists all currently loaded service units along with their active and sub states?", options:["systemctl --version","journalctl -u all","systemctl list-units --type=service","systemctl poweroff"], answer:2, explain:"<strong>systemctl list-units --type=service shows loaded service units with LOAD, ACTIVE, and SUB columns.</strong> It is the standard way to enumerate running and loaded services.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl --version</b>: this prints the systemd version, not a unit list.</span><span class='qd'><b>journalctl -u all</b>: journalctl filters logs by unit; 'all' is not a valid way to list service states.</span><span class='qd'><b>systemctl poweroff</b>: this shuts the machine down rather than listing units.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-081", domain:2, obj:"2.6", diff:"medium", q:"Using Podman you must run an nginx container in the background and map host port 8080 to container port 80. Which command is correct?", options:["podman run -d -p 8080:80 nginx","podman run -it nginx","podman run -p 80:8080 -d nginx","podman exec -d -p 8080:80 nginx"], answer:0, explain:"<strong>-d runs the container detached and -p 8080:80 maps host 8080 to container 80.</strong> The host port comes first in the host:container mapping.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman run -it nginx</b>: -it runs interactively in the foreground with no port mapping.</span><span class='qd'><b>podman run -p 80:8080 -d nginx</b>: this maps host 80 to container 8080, reversing the intended ports.</span><span class='qd'><b>podman exec -d -p 8080:80 nginx</b>: exec runs a command in an existing container and does not start a new one or accept -p.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-082", domain:2, obj:"2.6", diff:"medium", q:"You need to list all containers, including those that have exited, to clean up stopped ones. Which command shows every container regardless of state?", options:["podman ps -a","podman ps","podman images","podman ps -q"], answer:0, explain:"<strong>podman ps -a lists all containers, both running and stopped.</strong> By default ps shows only running containers, so -a (all) reveals exited ones too.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman ps</b>: without -a this shows only currently running containers.</span><span class='qd'><b>podman images</b>: images lists container images, not containers.</span><span class='qd'><b>podman ps -q</b>: -q lists only running container IDs and still omits stopped containers without -a.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-083", domain:2, obj:"2.6", diff:"hard", q:"In a Dockerfile you want each build to start from the official Python 3.12 slim image and set the working directory to /app before copying code. Which two instructions accomplish this in order?", options:["RUN python:3.12-slim then DIR /app","IMAGE python:3.12-slim then CD /app","BASE python:3.12-slim then WORKDIR /app","FROM python:3.12-slim then WORKDIR /app"], answer:3, explain:"<strong>FROM sets the base image and WORKDIR sets and creates the working directory for subsequent instructions.</strong> 'FROM python:3.12-slim' then 'WORKDIR /app' is the correct Dockerfile syntax.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>RUN python:3.12-slim then DIR /app</b>: RUN executes a shell command and DIR is not a Dockerfile instruction.</span><span class='qd'><b>IMAGE python:3.12-slim then CD /app</b>: IMAGE and CD are not valid Dockerfile instructions.</span><span class='qd'><b>BASE python:3.12-slim then WORKDIR /app</b>: BASE is not a Dockerfile instruction; the base image keyword is FROM.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-084", domain:2, obj:"2.6", diff:"medium", q:"You want to build an image from a Dockerfile in the current directory and tag it as 'myapp:1.0' using Podman. Which command is correct?", options:["podman run -t myapp:1.0 .","podman create myapp:1.0","podman build -t myapp:1.0 .","podman pull myapp:1.0"], answer:2, explain:"<strong>podman build -t myapp:1.0 . builds from the Dockerfile in the current directory (the build context) and tags the result.</strong> -t sets the name and tag, and the trailing dot is the context.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman run -t myapp:1.0 .</b>: run starts a container from an existing image; it does not build one.</span><span class='qd'><b>podman create myapp:1.0</b>: create makes a container from an existing image rather than building an image.</span><span class='qd'><b>podman pull myapp:1.0</b>: pull downloads an existing image from a registry, not a local build.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-085", domain:2, obj:"2.6", diff:"medium", q:"A running container named 'web' is misbehaving and you need an interactive shell inside it to investigate while it keeps running. Which command opens a shell in the existing container?", options:["podman run -it web /bin/bash","podman attach web","podman exec -it web /bin/bash","podman start web /bin/bash"], answer:2, explain:"<strong>podman exec -it web /bin/bash starts a new interactive shell process inside the already-running container.</strong> exec targets an existing container without restarting it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman run -it web /bin/bash</b>: run treats 'web' as an image and creates a new container, not a shell in the existing one.</span><span class='qd'><b>podman attach web</b>: attach connects to the container's main process stdio, not a fresh shell, and can disrupt the running app.</span><span class='qd'><b>podman start web /bin/bash</b>: start cannot launch an arbitrary command in an already-running container this way.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-086", domain:2, obj:"2.6", diff:"hard", q:"You need a PostgreSQL container to keep its data across restarts and recreation by storing /var/lib/postgresql/data on a named volume 'pgdata'. Which run option does this?", options:["podman run -d --tmpfs /var/lib/postgresql/data postgres","podman run -d -v pgdata:/var/lib/postgresql/data postgres","podman run -d -p pgdata:/var/lib/postgresql/data postgres","podman run -d --rm -v /var/lib/postgresql/data postgres"], answer:1, explain:"<strong>-v pgdata:/var/lib/postgresql/data mounts the named volume 'pgdata' at the data directory, persisting it independently of the container.</strong> Named volumes survive container removal and recreation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman run -d --tmpfs /var/lib/postgresql/data postgres</b>: tmpfs is in-memory and is lost on restart, the opposite of persistence.</span><span class='qd'><b>podman run -d -p pgdata:/var/lib/postgresql/data postgres</b>: -p maps network ports, not volumes.</span><span class='qd'><b>podman run -d --rm -v /var/lib/postgresql/data postgres</b>: --rm deletes the container on exit and an anonymous -v without a name is harder to persist intentionally.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-087", domain:2, obj:"2.6", diff:"medium", q:"You want to remove a container image 'old-app:0.9' that is no longer used to reclaim disk space, after confirming no containers use it. Which command removes the image?", options:["podman rmi old-app:0.9","podman rm old-app:0.9","podman stop old-app:0.9","podman prune old-app:0.9"], answer:0, explain:"<strong>podman rmi removes an image by name or ID.</strong> 'podman rmi old-app:0.9' deletes that image to reclaim space once no container references it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman rm old-app:0.9</b>: rm removes containers, not images.</span><span class='qd'><b>podman stop old-app:0.9</b>: stop halts a running container and does not delete an image.</span><span class='qd'><b>podman prune old-app:0.9</b>: prune does not take a single image name like that; it bulk-removes unused objects.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-088", domain:2, obj:"2.6", diff:"medium", q:"You need to download the official 'redis' image from a registry to your local machine without running it yet. Which command pulls the image?", options:["podman run redis","podman pull redis","podman push redis","podman load redis"], answer:1, explain:"<strong>podman pull redis downloads the image from the configured registry to local storage.</strong> Pulling stages the image so a later run starts quickly without fetching it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman run redis</b>: run would pull if needed but also immediately starts a container, which the task says not to do yet.</span><span class='qd'><b>podman push redis</b>: push uploads a local image to a registry, the opposite direction.</span><span class='qd'><b>podman load redis</b>: load imports an image from a tar archive file, not from a registry.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-089", domain:2, obj:"2.6", diff:"hard", q:"Two containers must talk to each other by name on an isolated network you control. You first create a user-defined network 'appnet', then run each container attached to it. Which command creates that network in Podman?", options:["podman network connect appnet","podman run --net appnet","podman volume create appnet","podman network create appnet"], answer:3, explain:"<strong>podman network create appnet defines a user network that provides DNS-based name resolution between attached containers.</strong> Containers run with --network appnet can then reach each other by name.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman network connect appnet</b>: connect attaches an existing container to an existing network; it does not create the network.</span><span class='qd'><b>podman run --net appnet</b>: this tries to use a network that does not exist yet because it has not been created.</span><span class='qd'><b>podman volume create appnet</b>: this creates a storage volume, not a network.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-090", domain:2, obj:"2.6", diff:"medium", q:"A container 'worker' is running and you must stop it gracefully, allowing it to finish in-flight work before being killed. Which command sends the graceful stop?", options:["podman kill worker","podman stop worker","podman rm -f worker","podman pause worker"], answer:1, explain:"<strong>podman stop sends SIGTERM and waits a grace period before forcing termination, allowing cleanup.</strong> This is the graceful shutdown path for a container.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman kill worker</b>: kill sends SIGKILL by default, terminating abruptly without graceful cleanup.</span><span class='qd'><b>podman rm -f worker</b>: -f force-removes the container, killing it immediately.</span><span class='qd'><b>podman pause worker</b>: pause freezes processes rather than stopping the container.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-091", domain:2, obj:"2.6", diff:"medium", q:"In a Dockerfile you must declare that the container listens on port 8080 and define the default command to launch the app. Which pair of instructions is correct?", options:["EXPOSE 8080 and CMD [\"python\", \"app.py\"]","PORT 8080 and START python app.py","LISTEN 8080 and RUN python app.py","OPEN 8080 and ENTRY python app.py"], answer:0, explain:"<strong>EXPOSE documents the listening port and CMD sets the default command run when the container starts.</strong> EXPOSE 8080 with CMD specifying the program is the standard pattern.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PORT 8080 and START python app.py</b>: PORT and START are not valid Dockerfile instructions.</span><span class='qd'><b>LISTEN 8080 and RUN python app.py</b>: LISTEN is invalid, and RUN executes at build time rather than setting the default runtime command.</span><span class='qd'><b>OPEN 8080 and ENTRY python app.py</b>: OPEN and ENTRY are not valid instructions (the entrypoint keyword is ENTRYPOINT).</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-092", domain:2, obj:"2.6", diff:"medium", q:"You want to see the live resource usage (CPU, memory, network I/O) of all running containers in a continuously updating display. Which command provides this?", options:["podman top","podman inspect","podman stats","podman logs"], answer:2, explain:"<strong>podman stats shows a live, updating table of per-container CPU, memory, and I/O usage.</strong> It is the container equivalent of top for resource monitoring.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman top</b>: top lists the processes inside a single container, not aggregate resource stats across containers.</span><span class='qd'><b>podman inspect</b>: inspect dumps static configuration and state JSON, not live usage.</span><span class='qd'><b>podman logs</b>: logs shows a container's stdout/stderr output, not resource metrics.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-093", domain:2, obj:"2.6", diff:"hard", q:"You need to inspect the IP address and full configuration of a running container 'db' in machine-readable JSON. Which command outputs this detail?", options:["podman logs db","podman inspect db","podman ps db","podman diff db"], answer:1, explain:"<strong>podman inspect outputs detailed JSON including network settings such as the container's IP address and full config.</strong> It is the canonical way to retrieve low-level container details.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman logs db</b>: logs shows application output, not configuration or IP details.</span><span class='qd'><b>podman ps db</b>: ps lists containers in a summary table and does not accept a name to dump full JSON config.</span><span class='qd'><b>podman diff db</b>: diff shows filesystem changes since the image, not network or config details.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-094", domain:2, obj:"2.6", diff:"medium", q:"You want a container to be automatically removed as soon as it exits, so no stopped container lingers, for a one-off task. Which run flag does this?", options:["podman run -d alpine echo hi","podman run --restart=always alpine echo hi","podman run --rm alpine echo hi","podman run --detach-keys alpine echo hi"], answer:2, explain:"<strong>--rm removes the container automatically when it exits.</strong> This is ideal for one-off commands so no stopped container is left behind.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman run -d alpine echo hi</b>: -d runs detached but leaves the container present after it exits.</span><span class='qd'><b>podman run --restart=always alpine echo hi</b>: --restart keeps restarting it, the opposite of cleanup.</span><span class='qd'><b>podman run --detach-keys alpine echo hi</b>: --detach-keys sets the keystroke to detach, unrelated to auto-removal.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-095", domain:2, obj:"2.1", diff:"medium", q:"You want to count how many regular files (not directories) exist under /etc recursively. Which command gives an accurate count of files only?", options:["find /etc | wc -l","find /etc -type f | wc -l","ls -R /etc | wc -l","find /etc -type d | wc -l"], answer:1, explain:"<strong>find /etc -type f restricts results to regular files, and wc -l counts them.</strong> The -type f filter excludes directories, symlinks, and special files from the count.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>find /etc | wc -l</b>: without -type f this counts directories and other entries too, inflating the number.</span><span class='qd'><b>ls -R /etc | wc -l</b>: ls -R output includes blank lines and directory header lines, producing an inaccurate count.</span><span class='qd'><b>find /etc -type d | wc -l</b>: -type d counts directories, not files.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-096", domain:2, obj:"2.3", diff:"medium", q:"A daily cron job defined in /etc/crontab runs as a specific user. Unlike a user crontab, what extra field must a system-wide /etc/crontab entry include between the time fields and the command?", options:["A nice value","The shell path","The username to run the command as","The job priority number"], answer:2, explain:"<strong>System crontab files like /etc/crontab include a username field after the five time fields and before the command.</strong> This specifies which user runs the job, which user crontabs omit since they always run as their owner.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A nice value</b>: cron does not place a nice value in that position; niceness is set within the command if desired.</span><span class='qd'><b>The shell path</b>: the shell is set via the SHELL variable at the top of the file, not as a per-line field.</span><span class='qd'><b>The job priority number</b>: there is no priority field in the crontab line format.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-097", domain:2, obj:"2.5", diff:"medium", q:"You want to see how long the most recent boot took and which units delayed it. Which command reports boot performance per unit?", options:["systemctl status","uptime -p","journalctl -b","systemd-analyze blame"], answer:3, explain:"<strong>systemd-analyze blame lists units ordered by how long each took to initialize during boot.</strong> It pinpoints the slowest units delaying startup.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl status</b>: status shows overall system or unit state, not per-unit boot timing.</span><span class='qd'><b>uptime -p</b>: uptime shows how long the system has been running, not boot timing breakdown.</span><span class='qd'><b>journalctl -b</b>: -b shows boot logs but does not summarize per-unit initialization times.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-098", domain:2, obj:"2.4", diff:"medium", q:"On Ubuntu you must find which installed package provides the file /usr/bin/curl. Which command answers this for a Debian-based system?", options:["rpm -qf /usr/bin/curl","dpkg -S /usr/bin/curl","apt show curl","dpkg -L curl"], answer:1, explain:"<strong>dpkg -S searches installed packages for the one that owns a given file path.</strong> 'dpkg -S /usr/bin/curl' reports the curl package on Debian-based systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rpm -qf /usr/bin/curl</b>: rpm is for RPM-based distros, not Ubuntu.</span><span class='qd'><b>apt show curl</b>: apt show displays package details but does not map an arbitrary file path to its owner.</span><span class='qd'><b>dpkg -L curl</b>: -L lists files owned by the curl package, the reverse of finding the owner of a file.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-099", domain:2, obj:"2.2", diff:"hard", q:"You must batch-update passwords for several accounts non-interactively from a script, reading lines of the form 'user:password'. Which command consumes that format?", options:["passwd < users.txt","chage < users.txt","newusers --update users.txt","chpasswd < users.txt"], answer:3, explain:"<strong>chpasswd reads user:password pairs from standard input and updates each account's password.</strong> It is designed for non-interactive batch password changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>passwd < users.txt</b>: passwd is interactive per user and does not parse user:password lines from stdin.</span><span class='qd'><b>chage < users.txt</b>: chage manages password aging, not the password values themselves.</span><span class='qd'><b>newusers --update users.txt</b>: newusers creates or updates whole account entries from a richer format, not simple user:password password changes via stdin.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D2-100", domain:2, obj:"2.6", diff:"medium", q:"You finished testing and want to bulk-remove all stopped containers and dangling images to reclaim space in Podman. Which command performs this cleanup?", options:["podman rm -a","podman rmi -a","podman container stop -a","podman system prune"], answer:3, explain:"<strong>podman system prune removes stopped containers, unused networks, and dangling images in one cleanup pass.</strong> It is the broad reclaim-space command for unused resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>podman rm -a</b>: this removes containers only (and fails on running ones without -f), not dangling images.</span><span class='qd'><b>podman rmi -a</b>: this targets images only and would try to remove all images, not just dangling ones, and not stopped containers.</span><span class='qd'><b>podman container stop -a</b>: stop halts running containers but removes nothing.</span>" }
);

