window.LINUXPLUS = window.LINUXPLUS || {}; LINUXPLUS.questions = LINUXPLUS.questions || [];
LINUXPLUS.questions.push(
{ id:"D3-001", domain:3, obj:"3.1", diff:"medium", q:"A new RHEL host must authenticate users against the corporate Active Directory domain while caching credentials for offline laptop use. Which service is the modern recommended choice?", options:["nscd with manual ldap.conf edits","winbind started from rc.local","SSSD configured with an AD provider","pam_ldap pointed at a domain controller"], answer:2, explain:"<strong>SSSD with an AD provider</strong> is the modern recommended approach: it handles Kerberos and LDAP, caches credentials for offline logins, and integrates cleanly with realmd for domain joins.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nscd with manual ldap.conf edits</b>: nscd is a name-service cache, not an authentication broker, and conflicts with SSSD's own caching.</span><span class='qd'><b>winbind started from rc.local</b>: winbind is legacy Samba-based AD integration and rc.local is a fragile startup hack.</span><span class='qd'><b>pam_ldap pointed at a domain controller</b>: pam_ldap is deprecated, provides no offline caching, and does not handle Kerberos tickets.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-002", domain:3, obj:"3.1", diff:"medium", q:"After enabling password complexity, you need PAM to reject passwords shorter than 12 characters and require at least one digit. Which module and file should you edit?", options:["pam_pwquality in /etc/pam.d/system-auth","pam_tally2 in /etc/security/limits.conf","pam_unix in /etc/login.defs","pam_access in /etc/security/access.conf"], answer:0, explain:"<strong>pam_pwquality in /etc/pam.d/system-auth</strong> enforces complexity rules such as minlen and dcredit; its settings live in /etc/security/pwquality.conf but are invoked through the PAM stack.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>pam_tally2 in /etc/security/limits.conf</b>: pam_tally2 counts failed logins for lockout, not complexity, and limits.conf governs resource limits.</span><span class='qd'><b>pam_unix in /etc/login.defs</b>: pam_unix handles the local password database; login.defs sets aging defaults, not complexity rules.</span><span class='qd'><b>pam_access in /etc/security/access.conf</b>: pam_access controls which accounts may log in from where, not password quality.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-003", domain:3, obj:"3.1", diff:"medium", q:"You must confirm that a user's failed-login attempts are being recorded and locate the source IP of a brute-force attempt on a systemd host. Which command shows authentication events?", options:["journalctl -u sshd","dmesg | grep auth","cat /var/log/boot.log","systemctl status network"], answer:0, explain:"<strong>journalctl -u sshd</strong> filters the systemd journal to the SSH daemon unit, surfacing authentication failures and the offending source IPs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dmesg | grep auth</b>: dmesg shows kernel ring-buffer messages, not user authentication events.</span><span class='qd'><b>cat /var/log/boot.log</b>: boot.log records the boot sequence, not ongoing SSH logins.</span><span class='qd'><b>systemctl status network</b>: this reports the network unit's state, not login attempts.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-004", domain:3, obj:"3.1", diff:"hard", q:"Auditd must log every execution of /usr/bin/passwd and tag it for later searching. Which rule is correct?", options:["auditctl -a always,exit -F path=/usr/bin/passwd -F perm=r","auditctl -w /usr/bin/passwd -p rwxa","auditctl -d /usr/bin/passwd -k exec","auditctl -w /usr/bin/passwd -p x -k passwd_exec"], answer:3, explain:"<strong>auditctl -w /usr/bin/passwd -p x -k passwd_exec</strong> sets a watch on the file for execute access and tags matching records with the searchable key passwd_exec.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>auditctl -a always,exit -F path=... -F perm=r</b>: perm=r audits reads, not executions, so it misses the intent.</span><span class='qd'><b>auditctl -w /usr/bin/passwd -p rwxa</b>: this watches all access types and supplies no key, making searches noisy and untagged.</span><span class='qd'><b>auditctl -d /usr/bin/passwd -k exec</b>: -d deletes a rule rather than adding one.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-005", domain:3, obj:"3.1", diff:"medium", q:"Logs from 40 servers must be centralized to a collector over TCP with reliability. Which rsyslog forwarding directive sends to host 10.0.0.5 on port 514 using TCP?", options:["*.* @@10.0.0.5:514","*.* @10.0.0.5:514","*.* >10.0.0.5:514","*.* |10.0.0.5:514"], answer:0, explain:"<strong>*.* @@10.0.0.5:514</strong> uses the double-at syntax in rsyslog to forward all messages over TCP, which provides delivery confirmation suited to reliable aggregation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>*.* @10.0.0.5:514</b>: a single @ forwards over connectionless UDP, which can silently drop messages.</span><span class='qd'><b>*.* >10.0.0.5:514</b>: the > operator is not valid rsyslog forwarding syntax.</span><span class='qd'><b>*.* |10.0.0.5:514</b>: the pipe writes to a named pipe, not a remote host.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-006", domain:3, obj:"3.1", diff:"medium", q:"The journal is consuming too much disk and you want persistent storage capped at 500M. Which journald.conf settings achieve this?", options:["Storage=persistent and SystemMaxUse=500M","Storage=volatile and SystemMaxUse=500M","Storage=none and RuntimeMaxUse=500M","ForwardToSyslog=yes and MaxFileSec=500M"], answer:0, explain:"<strong>Storage=persistent and SystemMaxUse=500M</strong> writes the journal to /var/log/journal across reboots while limiting its on-disk footprint to 500M.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Storage=volatile and SystemMaxUse=500M</b>: volatile keeps logs only in /run memory, so they vanish on reboot.</span><span class='qd'><b>Storage=none and RuntimeMaxUse=500M</b>: none disables journal storage entirely.</span><span class='qd'><b>ForwardToSyslog=yes and MaxFileSec=500M</b>: forwarding does not cap disk use and MaxFileSec is a time rotation, not a size limit.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-007", domain:3, obj:"3.1", diff:"medium", q:"A Kerberos client can obtain a TGT but every service login fails with clock-skew errors. What is the most likely root cause?", options:["The keytab file is missing","Time on the client differs from the KDC by more than five minutes","The user's password expired","DNS reverse lookups are disabled"], answer:1, explain:"<strong>Time differs from the KDC by more than five minutes</strong>: Kerberos relies on synchronized clocks, and the default tolerance is 300 seconds, so skew beyond that rejects tickets. Running chrony/NTP fixes it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The keytab file is missing</b>: a missing keytab breaks service principals, not user TGT acquisition that already succeeded.</span><span class='qd'><b>The user's password expired</b>: an expired password would prevent obtaining the TGT in the first place.</span><span class='qd'><b>DNS reverse lookups are disabled</b>: reverse DNS issues cause name-resolution errors, not clock-skew messages.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-008", domain:3, obj:"3.1", diff:"easy", q:"You need to list the contents of a Kerberos credential cache to confirm a user holds a valid ticket-granting ticket. Which command do you run?", options:["klist","kinit","kdestroy","ktutil"], answer:0, explain:"<strong>klist</strong> displays the tickets currently held in the credential cache, including the TGT and their expiration times.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>kinit</b>: kinit obtains a new ticket; it does not list existing ones.</span><span class='qd'><b>kdestroy</b>: kdestroy purges the cache rather than displaying it.</span><span class='qd'><b>ktutil</b>: ktutil manages keytab files, not the live credential cache.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-009", domain:3, obj:"3.1", diff:"hard", q:"SSSD authenticates users fine, but group-based sudo rules from LDAP are ignored. Which SSSD service must be enabled in the services line of sssd.conf?", options:["sudo","nss","pam","autofs"], answer:0, explain:"<strong>sudo</strong>: SSSD only retrieves sudo rules from the directory when the sudo responder is listed in the services line and configured, otherwise sudoers from LDAP are never consulted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nss</b>: the nss responder resolves names and groups but does not fetch sudo rules.</span><span class='qd'><b>pam</b>: the pam responder handles authentication, not sudo policy retrieval.</span><span class='qd'><b>autofs</b>: the autofs responder serves automount maps, unrelated to sudo.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-010", domain:3, obj:"3.1", diff:"medium", q:"You want auditd to load a persistent rule set at boot. In which file should permanent rules be placed?", options:["/etc/audit/rules.d/audit.rules","/etc/audit/auditd.conf","/var/log/audit/audit.log","/etc/audit/audit.cron"], answer:0, explain:"<strong>/etc/audit/rules.d/audit.rules</strong> holds persistent rules that augenrules compiles into the active set at boot, surviving reboots.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/audit/auditd.conf</b>: this configures the daemon's behavior such as log size, not the rules.</span><span class='qd'><b>/var/log/audit/audit.log</b>: this is the output log, not a rules source.</span><span class='qd'><b>/etc/audit/audit.cron</b>: no such file exists in the audit framework.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-011", domain:3, obj:"3.1", diff:"medium", q:"Security policy requires that all sudo commands be forwarded to a central syslog server in real time. Where do you add the visiblepw or syslog facility directive so sudo logs to syslog?", options:["Defaults logfile in /etc/sudoers","auth.* in /etc/pam.d/sudo","Defaults syslog=authpriv in /etc/sudoers","LogLevel in /etc/ssh/sshd_config"], answer:2, explain:"<strong>Defaults syslog=authpriv in /etc/sudoers</strong> directs sudo events to the authpriv facility, which rsyslog can then forward to the central collector.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Defaults logfile in /etc/sudoers</b>: logfile writes to a local file only and bypasses syslog forwarding.</span><span class='qd'><b>auth.* in /etc/pam.d/sudo</b>: PAM files configure modules, not syslog facility selection for sudo output.</span><span class='qd'><b>LogLevel in /etc/ssh/sshd_config</b>: that controls SSH verbosity, not sudo logging.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-012", domain:3, obj:"3.1", diff:"medium", q:"Account lockout must trigger after five failed SSH logins and auto-unlock after 15 minutes on a modern RHEL system. Which module provides this faillock behavior?", options:["pam_cracklib","pam_limits","pam_faillock","pam_env"], answer:2, explain:"<strong>pam_faillock</strong> tracks failed authentications and enforces deny and unlock_time parameters, the supported replacement for pam_tally2.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>pam_cracklib</b>: cracklib checks password strength, not lockout counts.</span><span class='qd'><b>pam_limits</b>: pam_limits applies ulimit-style resource limits at login.</span><span class='qd'><b>pam_env</b>: pam_env sets environment variables and has nothing to do with lockout.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-013", domain:3, obj:"3.1", diff:"easy", q:"You need a quick way to view only error-priority and worse messages from the current boot in the journal. Which command works?", options:["journalctl --since boot","journalctl -f -u all","journalctl -p err -b","journalctl -k -p info"], answer:2, explain:"<strong>journalctl -p err -b</strong> filters to priority err and higher (crit, alert, emerg) for the current boot via -b.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>journalctl --since boot</b>: 'boot' is not a valid time argument; you would use -b instead.</span><span class='qd'><b>journalctl -f -u all</b>: 'all' is not a valid unit name and -f follows live output rather than filtering by priority.</span><span class='qd'><b>journalctl -k -p info</b>: -k limits to kernel messages and info is a lower priority than requested.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-014", domain:3, obj:"3.1", diff:"hard", q:"An LDAP bind succeeds with anonymous queries but user logins fail. ldapsearch shows entries lack uidNumber and gidNumber attributes. What must be added to make POSIX logins work?", options:["A userCertificate attribute","The posixAccount objectClass and POSIX attributes","The Kerberos krbPrincipalName attribute","An sshPublicKey attribute"], answer:1, explain:"<strong>The posixAccount objectClass and POSIX attributes</strong>: POSIX logins require uidNumber, gidNumber, homeDirectory and loginShell supplied by the posixAccount class, otherwise NSS cannot map the user.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A userCertificate attribute</b>: certificates support TLS client auth, not POSIX identity mapping.</span><span class='qd'><b>The Kerberos krbPrincipalName attribute</b>: that supports Kerberos auth but does not supply UID/GID for NSS.</span><span class='qd'><b>An sshPublicKey attribute</b>: that enables key lookup but does not give the account a numeric identity.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-015", domain:3, obj:"3.1", diff:"medium", q:"You must search the audit logs for all events tagged with the key time-change. Which command is correct?", options:["auditctl -l time-change","ausearch -k time-change","aureport --key time-change","journalctl -k time-change"], answer:1, explain:"<strong>ausearch -k time-change</strong> queries the audit log for records carrying the specified key, returning matching events.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>auditctl -l time-change</b>: auditctl -l lists loaded rules; it does not search logged events by key.</span><span class='qd'><b>aureport --key time-change</b>: aureport summarizes activity but --key is not its selector for filtering by a single key value.</span><span class='qd'><b>journalctl -k time-change</b>: journalctl -k shows kernel messages and does not understand audit keys.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-016", domain:3, obj:"3.1", diff:"medium", q:"After joining a host to a domain with realm join, users authenticate but must type the full user@domain form. Which sssd.conf setting allows short usernames?", options:["case_sensitive = True","enumerate = True","default_shell = /bin/bash","use_fully_qualified_names = False"], answer:3, explain:"<strong>use_fully_qualified_names = False</strong> lets users log in with just their short name instead of the user@domain format.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>case_sensitive = True</b>: this controls case handling, not whether the domain suffix is required.</span><span class='qd'><b>enumerate = True</b>: enumeration lists all users and is discouraged for performance; it does not affect login name format.</span><span class='qd'><b>default_shell = /bin/bash</b>: this only sets the shell, not username formatting.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-017", domain:3, obj:"3.2", diff:"medium", q:"On a firewalld host you must permanently open TCP 8443 in the public zone and apply it immediately. Which command pair is correct?", options:["firewall-cmd --add-port=8443/tcp then firewall-cmd --reload","firewall-cmd --zone=public --add-service=8443","iptables -A INPUT -p tcp --dport 8443 -j ACCEPT","firewall-cmd --permanent --add-port=8443/tcp then firewall-cmd --reload"], answer:3, explain:"<strong>firewall-cmd --permanent --add-port=8443/tcp then firewall-cmd --reload</strong> writes the rule to the permanent config and reload activates it without losing other runtime state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>firewall-cmd --add-port=8443/tcp then --reload</b>: without --permanent the runtime rule is discarded by the reload.</span><span class='qd'><b>firewall-cmd --zone=public --add-service=8443</b>: 8443 is a port, not a defined service name, so this fails.</span><span class='qd'><b>iptables -A INPUT ...</b>: editing iptables directly bypasses firewalld and is overwritten on reload.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-018", domain:3, obj:"3.2", diff:"medium", q:"You need to verify which firewalld zone an interface eth0 is bound to. Which command shows this?", options:["firewall-cmd --get-zone-of-interface=eth0","firewall-cmd --list-all-zones eth0","ip addr show eth0","firewall-cmd --query-interface=eth0"], answer:0, explain:"<strong>firewall-cmd --get-zone-of-interface=eth0</strong> returns the name of the zone the interface is currently assigned to.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>firewall-cmd --list-all-zones eth0</b>: --list-all-zones dumps every zone and does not accept an interface argument.</span><span class='qd'><b>ip addr show eth0</b>: this shows addressing, not firewalld zone membership.</span><span class='qd'><b>firewall-cmd --query-interface=eth0</b>: --query-interface must be paired with a --zone and returns a boolean, not the zone name.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-019", domain:3, obj:"3.2", diff:"hard", q:"A host must forward inbound traffic on its public IP port 80 to an internal web server at 192.168.10.20:8080 using firewalld. Which command configures this?", options:["firewall-cmd --permanent --add-masquerade","firewall-cmd --permanent --add-rich-rule='rule family=ipv4 source address=192.168.10.20 accept'","firewall-cmd --permanent --zone=public --add-forward-port=port=80:proto=tcp:toport=8080:toaddr=192.168.10.20","firewall-cmd --permanent --add-port=80/tcp"], answer:2, explain:"<strong>firewall-cmd --permanent --zone=public --add-forward-port=port=80:proto=tcp:toport=8080:toaddr=192.168.10.20</strong> creates the DNAT redirect to the internal server (masquerade is also typically needed for the return path).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>--add-masquerade</b>: masquerade alone provides SNAT for outbound traffic, not the inbound port redirect.</span><span class='qd'><b>--add-rich-rule ... accept</b>: this merely permits a source address; it performs no forwarding.</span><span class='qd'><b>--add-port=80/tcp</b>: opening port 80 lets traffic reach this host but does not redirect it elsewhere.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-020", domain:3, obj:"3.2", diff:"medium", q:"On an Ubuntu server you must allow SSH and deny everything else by default with ufw. Which command sequence is correct?", options:["ufw default allow incoming then ufw allow ssh","ufw enable then ufw allow all","ufw deny ssh then ufw enable","ufw allow ssh then ufw default deny incoming then ufw enable"], answer:3, explain:"<strong>ufw allow ssh, ufw default deny incoming, ufw enable</strong> permits SSH explicitly, sets a default-deny posture for inbound traffic, then activates the firewall without locking yourself out.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ufw default allow incoming then ufw allow ssh</b>: allowing all incoming defeats the deny-by-default requirement.</span><span class='qd'><b>ufw enable then ufw allow all</b>: 'allow all' is not valid ufw syntax and opens everything.</span><span class='qd'><b>ufw deny ssh then ufw enable</b>: denying SSH would block your own remote access.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-021", domain:3, obj:"3.2", diff:"hard", q:"You are migrating from iptables to nftables. To create a base inet table and an input chain with a default policy of drop, which command is correct?", options:["nft add table inet filter; nft add chain inet filter input { type filter hook input priority 0 \\; policy drop \\; }","nft -F filter input drop","iptables -P INPUT DROP","nft create filter input policy drop"], answer:0, explain:"<strong>nft add table inet filter; nft add chain inet filter input { type filter hook input priority 0 ; policy drop ; }</strong> defines the inet-family table and a base chain hooked at input with a drop policy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nft -F filter input drop</b>: -F flushes rules and this is not valid chain-creation syntax.</span><span class='qd'><b>iptables -P INPUT DROP</b>: that is iptables, the framework you are migrating away from.</span><span class='qd'><b>nft create filter input policy drop</b>: this omits the table family and the required hook/type specification.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-022", domain:3, obj:"3.2", diff:"medium", q:"You need a firewalld rich rule that allows SSH only from the 10.5.0.0/24 subnet and logs the connections. Which rich rule is correct?", options:["rule service name='ssh' reject log","rule family='ipv4' port port='22' accept","rule family='ipv4' source address='10.5.0.0/24' service name='ssh' log accept","rule source address='10.5.0.0/24' drop"], answer:2, explain:"<strong>rule family='ipv4' source address='10.5.0.0/24' service name='ssh' log accept</strong> scopes the allow to the subnet, references the ssh service, logs the match, and accepts it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rule service name='ssh' reject log</b>: this rejects SSH rather than allowing it from the subnet.</span><span class='qd'><b>rule family='ipv4' port port='22' accept</b>: it omits the source restriction, allowing SSH from anywhere.</span><span class='qd'><b>rule source address='10.5.0.0/24' drop</b>: this drops all traffic from the subnet instead of allowing SSH.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-023", domain:3, obj:"3.2", diff:"medium", q:"After adding several runtime firewalld rules during testing, you want to discard them and return to the saved permanent configuration. Which command does this?", options:["firewall-cmd --runtime-to-permanent","firewall-cmd --complete-reload","firewall-cmd --reload","systemctl stop firewalld"], answer:2, explain:"<strong>firewall-cmd --reload</strong> reloads the permanent configuration and drops any runtime-only changes, restoring the saved state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>firewall-cmd --runtime-to-permanent</b>: this saves the runtime rules instead of discarding them.</span><span class='qd'><b>firewall-cmd --complete-reload</b>: this drops active connections and is meant for major changes, not simply reverting runtime edits.</span><span class='qd'><b>systemctl stop firewalld</b>: stopping the service removes all filtering rather than reverting to permanent rules.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-024", domain:3, obj:"3.2", diff:"easy", q:"Which command lists all currently active rules, ports, and services for the default firewalld zone?", options:["firewall-cmd --state","firewall-cmd --list-all","firewall-cmd --get-default-zone","firewall-cmd --reload"], answer:1, explain:"<strong>firewall-cmd --list-all</strong> prints the active zone's complete configuration including interfaces, services, ports, and rich rules.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>firewall-cmd --state</b>: --state only reports whether firewalld is running.</span><span class='qd'><b>firewall-cmd --get-default-zone</b>: this returns just the zone name.</span><span class='qd'><b>firewall-cmd --reload</b>: reload reapplies config and prints no rule listing.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-025", domain:3, obj:"3.2", diff:"hard", q:"A gateway must let internal hosts on 192.168.1.0/24 reach the internet through interface eth1 using legacy iptables NAT. Which rule provides the source translation?", options:["iptables -t nat -A PREROUTING -s 192.168.1.0/24 -j SNAT","iptables -A FORWARD -s 192.168.1.0/24 -j ACCEPT","iptables -t nat -A POSTROUTING -s 192.168.1.0/24 -o eth1 -j MASQUERADE","iptables -t filter -A POSTROUTING -j MASQUERADE"], answer:2, explain:"<strong>iptables -t nat -A POSTROUTING -s 192.168.1.0/24 -o eth1 -j MASQUERADE</strong> rewrites the source address of outbound packets leaving eth1, the standard internet-sharing NAT rule.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>-A PREROUTING -s ... -j SNAT</b>: SNAT belongs in POSTROUTING and PREROUTING is for destination NAT.</span><span class='qd'><b>-A FORWARD -s ... -j ACCEPT</b>: this only permits forwarding; it performs no address translation.</span><span class='qd'><b>-t filter -A POSTROUTING ...</b>: POSTROUTING does not exist in the filter table; MASQUERADE requires the nat table.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-026", domain:3, obj:"3.2", diff:"medium", q:"You want to temporarily block all traffic from a malicious IP 203.0.113.9 on a firewalld host without editing zones. Which approach is fastest and appropriate?", options:["firewall-cmd --panic-on","firewall-cmd --add-rich-rule='rule family=ipv4 source address=203.0.113.9 drop'","firewall-cmd --set-default-zone=drop","firewall-cmd --remove-service=ssh"], answer:1, explain:"<strong>firewall-cmd --add-rich-rule='rule family=ipv4 source address=203.0.113.9 drop'</strong> drops only that single hostile source immediately while leaving normal traffic intact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>firewall-cmd --panic-on</b>: panic mode blocks all traffic, cutting off legitimate users too.</span><span class='qd'><b>firewall-cmd --set-default-zone=drop</b>: switching the whole host to the drop zone is far broader than blocking one IP.</span><span class='qd'><b>firewall-cmd --remove-service=ssh</b>: removing SSH does not block the attacker's other traffic and locks out admins.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-027", domain:3, obj:"3.2", diff:"medium", q:"Your nftables ruleset is in /etc/nftables.conf but rules vanish after reboot. Which step ensures persistence?", options:["Add the rules to /etc/rc.local only","Run nft list ruleset > /etc/nftables.conf and enable the nftables.service","Run iptables-save after every change","Set net.ipv4.ip_forward=1"], answer:1, explain:"<strong>Run nft list ruleset > /etc/nftables.conf and enable the nftables.service</strong>: saving the active ruleset to the config file and enabling the systemd unit reloads it at boot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Add the rules to /etc/rc.local only</b>: rc.local is deprecated and not guaranteed to run on modern systemd hosts.</span><span class='qd'><b>Run iptables-save after every change</b>: iptables-save serializes iptables rules, not nftables, the wrong tooling.</span><span class='qd'><b>Set net.ipv4.ip_forward=1</b>: that enables routing, which does nothing for rule persistence.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-028", domain:3, obj:"3.2", diff:"medium", q:"A web server should allow HTTP and HTTPS using firewalld service names rather than raw ports for clarity. Which command adds both permanently?", options:["firewall-cmd --add-port=80,443","firewall-cmd --permanent --add-service={http,https}","firewall-cmd --permanent --add-rich-rule='http https accept'","firewall-cmd --add-interface=http"], answer:1, explain:"<strong>firewall-cmd --permanent --add-service={http,https}</strong> uses brace expansion to add both predefined services to the permanent configuration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>firewall-cmd --add-port=80,443</b>: --add-port expects a port/proto pair and lacks --permanent here.</span><span class='qd'><b>--add-rich-rule='http https accept'</b>: that is not valid rich-rule syntax.</span><span class='qd'><b>firewall-cmd --add-interface=http</b>: http is a service, not an interface name.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-029", domain:3, obj:"3.2", diff:"easy", q:"Which command displays the chains and rules currently loaded by nftables?", options:["nft show all","nft -L","nftables --dump","nft list ruleset"], answer:3, explain:"<strong>nft list ruleset</strong> outputs every table, chain, and rule currently loaded in nftables.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nft show all</b>: 'show all' is not valid nft syntax.</span><span class='qd'><b>nft -L</b>: -L is an iptables-style flag and is not how nft lists rules.</span><span class='qd'><b>nftables --dump</b>: nftables is the service name, not a command-line tool with a --dump flag.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-030", domain:3, obj:"3.2", diff:"hard", q:"A firewalld masquerading gateway forwards traffic, but return packets from the internal subnet never reach external clients. IP forwarding is enabled. What is the most likely missing piece?", options:["The internal zone lacks the http service","The default zone is set to trusted","Rich rules are disabled globally","Masquerade is not enabled on the outbound (external) zone"], answer:3, explain:"<strong>Masquerade is not enabled on the outbound (external) zone</strong>: without masquerade, the gateway does not rewrite source addresses, so external hosts cannot route replies back to private addresses.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The internal zone lacks the http service</b>: a missing service blocks a specific port, not all return routing.</span><span class='qd'><b>The default zone is set to trusted</b>: a trusted default would permit more traffic, not break NAT return paths.</span><span class='qd'><b>Rich rules are disabled globally</b>: firewalld has no global toggle disabling rich rules, and they are unrelated to masquerade.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-031", domain:3, obj:"3.2", diff:"medium", q:"You must confirm that firewalld, not iptables-services, is the active firewall backend before applying zone changes. Which command verifies the running firewall manager?", options:["firewall-cmd --reload","iptables -L -n","nft flush ruleset","systemctl is-active firewalld"], answer:3, explain:"<strong>systemctl is-active firewalld</strong> confirms the firewalld service is running and managing the firewall, the prerequisite for zone-based commands.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>firewall-cmd --reload</b>: reload assumes firewalld is already active and does not report backend status clearly.</span><span class='qd'><b>iptables -L -n</b>: listing iptables shows rules but not which manager owns them.</span><span class='qd'><b>nft flush ruleset</b>: this destructively clears nftables rules and verifies nothing.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-032", domain:3, obj:"3.2", diff:"medium", q:"To redirect incoming traffic on port 2222 to local port 22 on the same host using nftables NAT, which rule fits in a prerouting chain?", options:["redirect to :22","dnat to 22 prerouting","tcp dport 2222 redirect to :22","accept tcp 2222"], answer:2, explain:"<strong>tcp dport 2222 redirect to :22</strong> matches destination port 2222 and redirects it to local port 22 within an nftables nat prerouting chain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>redirect to :22</b>: without the matching expression it redirects all traffic indiscriminately.</span><span class='qd'><b>dnat to 22 prerouting</b>: dnat needs a destination address:port and 'prerouting' is the chain, not part of the action.</span><span class='qd'><b>accept tcp 2222</b>: accept merely permits the port; it performs no redirection.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-033", domain:3, obj:"3.3", diff:"medium", q:"A shared script at /opt/tools/report.sh must run with the file owner's privileges regardless of who executes it. Which permission bit accomplishes this and how is it set?", options:["chmod u+s /opt/tools/report.sh (SUID)","chmod g+s /opt/tools/report.sh (SGID)","chmod +t /opt/tools/report.sh (sticky)","chmod o+x /opt/tools/report.sh"], answer:0, explain:"<strong>chmod u+s (SUID)</strong> sets the set-user-ID bit so the program runs with the file owner's UID rather than the caller's.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod g+s (SGID)</b>: SGID runs with the group's identity, not the owner's user identity.</span><span class='qd'><b>chmod +t (sticky)</b>: the sticky bit restricts file deletion in shared directories and has no effect on execution identity.</span><span class='qd'><b>chmod o+x</b>: this only grants execute to others; it does not change the effective user.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-034", domain:3, obj:"3.3", diff:"medium", q:"In /shared, multiple users create files but anyone can delete each other's files. Which special permission prevents users from deleting files they do not own?", options:["The sticky bit (chmod +t /shared)","The SUID bit on the directory","Removing group write with chmod g-w","Setting umask 077 globally"], answer:0, explain:"<strong>The sticky bit (chmod +t /shared)</strong> restricts deletion in a world-writable directory so only a file's owner (or root) can remove it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The SUID bit on the directory</b>: SUID has no meaning on directories on Linux.</span><span class='qd'><b>Removing group write with chmod g-w</b>: that would stop legitimate file creation by the group.</span><span class='qd'><b>Setting umask 077 globally</b>: umask affects new file permissions, not who may delete existing files in a shared directory.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-035", domain:3, obj:"3.3", diff:"medium", q:"A developer needs read and write access to /var/data/app.log without changing its owner or group. Which command grants exactly that via an ACL?", options:["setfacl -m u:dev:rw /var/data/app.log","chmod 666 /var/data/app.log","chown dev /var/data/app.log","usermod -aG data dev"], answer:0, explain:"<strong>setfacl -m u:dev:rw /var/data/app.log</strong> adds a named-user ACL entry granting dev read/write while preserving the existing owner and group.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod 666</b>: that grants read/write to everyone, far broader than just dev.</span><span class='qd'><b>chown dev</b>: changing ownership alters the owner, which the requirement forbids.</span><span class='qd'><b>usermod -aG data dev</b>: adding dev to the group depends on group permissions and changes broader access rather than targeting one user.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-036", domain:3, obj:"3.3", diff:"hard", q:"You ran setfacl to grant access, but ls -l now shows a plus sign and effective permissions are narrower than granted because of the mask. Which command resets the mask to allow full rw for named entries?", options:["setfacl -b /path/file","setfacl -m m::rw /path/file","chmod 000 /path/file","getfacl /path/file"], answer:1, explain:"<strong>setfacl -m m::rw /path/file</strong> sets the ACL mask to rw, which is the ceiling that limits named users and groups; raising it restores the intended permissions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>setfacl -b</b>: -b removes all extended ACL entries, discarding the access you configured.</span><span class='qd'><b>chmod 000</b>: that strips all permissions rather than adjusting the mask.</span><span class='qd'><b>getfacl</b>: getfacl only displays the ACL; it makes no changes.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-037", domain:3, obj:"3.3", diff:"medium", q:"A junior admin should be able to restart only the httpd service via sudo and nothing else. Which sudoers entry is correct and least-privilege?", options:["junior ALL=(ALL) ALL","junior ALL=(root) /usr/bin/systemctl restart httpd","junior ALL=(ALL) NOPASSWD: ALL","junior ALL=(root) /usr/bin/systemctl"], answer:1, explain:"<strong>junior ALL=(root) /usr/bin/systemctl restart httpd</strong> permits exactly the one command needed, honoring least privilege.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>junior ALL=(ALL) ALL</b>: that grants full root via sudo, vastly over-privileged.</span><span class='qd'><b>junior ALL=(ALL) NOPASSWD: ALL</b>: this gives passwordless root for everything, the worst option.</span><span class='qd'><b>junior ALL=(root) /usr/bin/systemctl</b>: allowing the whole systemctl binary lets them stop or mask any service, exceeding the requirement.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-038", domain:3, obj:"3.3", diff:"medium", q:"You edited /etc/sudoers directly and fear a syntax error could break sudo. Which tool should you have used to edit it safely?", options:["nano /etc/sudoers","visudo","vi /etc/sudoers","sudoedit -c"], answer:1, explain:"<strong>visudo</strong> locks the file, opens it in an editor, and validates syntax before saving, preventing a broken sudoers that would lock out privilege escalation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nano /etc/sudoers</b>: editing directly performs no validation and risks an unparseable file.</span><span class='qd'><b>vi /etc/sudoers</b>: same problem; direct edits skip the syntax check.</span><span class='qd'><b>sudoedit -c</b>: sudoedit edits files as a target user but is not the dedicated sudoers validator and -c is not its check flag.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-039", domain:3, obj:"3.3", diff:"medium", q:"After copying a web file with cp, SELinux blocks Apache from serving it though permissions look correct. Which command restores the correct SELinux context from the policy?", options:["chcon -t admin_home_t /var/www/html/index.html","setenforce 0","restorecon -v /var/www/html/index.html","chmod 644 /var/www/html/index.html"], answer:2, explain:"<strong>restorecon -v /var/www/html/index.html</strong> resets the file's SELinux context to the default defined by the policy (httpd_sys_content_t), which Apache is allowed to read.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chcon -t admin_home_t ...</b>: admin_home_t is the wrong type and chcon changes are not persistent across relabels.</span><span class='qd'><b>setenforce 0</b>: disabling enforcement masks the problem instead of fixing the label and weakens security.</span><span class='qd'><b>chmod 644</b>: standard permissions are already correct; the issue is the SELinux context.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-040", domain:3, obj:"3.3", diff:"hard", q:"Apache must serve content from a non-default directory /srv/web permanently under SELinux enforcing. Which command set defines and applies the correct context durably?", options:["chcon -R -t httpd_sys_content_t /srv/web only","setsebool -P httpd_enable_homedirs on","semanage fcontext -a -t httpd_sys_content_t '/srv/web(/.*)?' then restorecon -Rv /srv/web","semanage port -a -t http_port_t -p tcp 8080"], answer:2, explain:"<strong>semanage fcontext -a ... then restorecon -Rv /srv/web</strong> records the context rule in policy so it survives relabels, then applies it to the existing files.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chcon -R only</b>: chcon changes are lost on the next restorecon or relabel because they are not recorded in policy.</span><span class='qd'><b>setsebool -P httpd_enable_homedirs on</b>: that toggles a boolean for user home dirs, not arbitrary content paths.</span><span class='qd'><b>semanage port ...</b>: that manages port labels, not file contexts.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-041", domain:3, obj:"3.3", diff:"medium", q:"Apache must be allowed to make outbound network connections (e.g., to a database) under SELinux. Which command enables this persistently?", options:["setsebool -P httpd_can_network_connect on","setenforce 1","semanage login -a httpd","restorecon -R /etc/httpd"], answer:0, explain:"<strong>setsebool -P httpd_can_network_connect on</strong> turns on the boolean that permits the httpd domain to initiate network connections, with -P making it persistent.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>setenforce 1</b>: that simply ensures enforcing mode; it does not grant the network capability.</span><span class='qd'><b>semanage login -a httpd</b>: that maps a Linux user to an SELinux user, irrelevant here.</span><span class='qd'><b>restorecon -R /etc/httpd</b>: relabeling config files does not change the network boolean.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-042", domain:3, obj:"3.3", diff:"easy", q:"Which command shows the SELinux context (security label) of files in the current directory?", options:["ls -l","ls -Z","ls -a","stat -f"], answer:1, explain:"<strong>ls -Z</strong> appends the SELinux security context (user:role:type:level) to the listing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ls -l</b>: the long listing shows mode and ownership but no SELinux label.</span><span class='qd'><b>ls -a</b>: -a only reveals hidden files.</span><span class='qd'><b>stat -f</b>: -f reports filesystem statistics, not per-file SELinux contexts.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-043", domain:3, obj:"3.3", diff:"medium", q:"SSH should run on a non-standard port 2222 under SELinux enforcing, but sshd fails to bind after editing sshd_config. Which command labels the port so SELinux permits it?", options:["firewall-cmd --add-port=2222/tcp","semanage port -a -t ssh_port_t -p tcp 2222","chcon -t ssh_port_t 2222","setsebool -P ssh_port on"], answer:1, explain:"<strong>semanage port -a -t ssh_port_t -p tcp 2222</strong> adds the SELinux port label so the sshd domain is allowed to bind to 2222.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>firewall-cmd --add-port=2222/tcp</b>: opening the firewall is needed too but does not satisfy SELinux's port-type check.</span><span class='qd'><b>chcon -t ssh_port_t 2222</b>: chcon labels files, not ports; 2222 is not a filesystem path.</span><span class='qd'><b>setsebool -P ssh_port on</b>: no such boolean exists; port access is governed by port labels.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-044", domain:3, obj:"3.3", diff:"medium", q:"You want all new files in /project/team to inherit the group teamdev automatically so collaborators share access. Which command configures this?", options:["chmod +t /project/team","chmod g+s /project/team","chown :teamdev /project/team only","umask 002"], answer:1, explain:"<strong>chmod g+s /project/team</strong> sets the SGID bit on the directory so new files and subdirectories inherit the directory's group ownership.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod +t</b>: the sticky bit governs deletion, not group inheritance.</span><span class='qd'><b>chown :teamdev /project/team only</b>: setting the directory group alone does not make new files inherit it without SGID.</span><span class='qd'><b>umask 002</b>: umask affects permission bits on new files, not which group they inherit.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-045", domain:3, obj:"3.3", diff:"hard", q:"A file has mode rw-r--r-- owned by alice:staff. User bob (not in staff) needs read-write via ACL, and the owner permissions must stay unchanged. Which getfacl output line confirms bob's access after setfacl -m u:bob:rw?", options:["user:bob:rw-","group:staff:rw-","other::rw-","mask::r--"], answer:0, explain:"<strong>user:bob:rw-</strong> is the named-user ACL entry that grants bob read-write specifically, separate from the owner and other permissions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>group:staff:rw-</b>: that would alter the group's access, not bob's individual entry.</span><span class='qd'><b>other::rw-</b>: that grants everyone read-write, far broader than intended.</span><span class='qd'><b>mask::r--</b>: a mask of r-- would actually clamp bob's effective permission to read-only, the opposite of the goal.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-046", domain:3, obj:"3.3", diff:"medium", q:"Security hardening requires disabling direct root SSH login while still allowing key-based admin access via sudo. Which sshd_config directive accomplishes the root restriction?", options:["PasswordAuthentication no","AllowUsers root","PermitRootLogin no","PermitRootLogin prohibit-password"], answer:2, explain:"<strong>PermitRootLogin no</strong> blocks all direct root logins over SSH, forcing admins to log in as a normal user and escalate with sudo.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>PasswordAuthentication no</b>: that disables passwords generally but would still allow root via key.</span><span class='qd'><b>AllowUsers root</b>: this explicitly permits root, the opposite of the requirement.</span><span class='qd'><b>PermitRootLogin prohibit-password</b>: that still permits root login via key, which the policy forbids.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-047", domain:3, obj:"3.3", diff:"medium", q:"To enforce SSH key-only authentication and reject passwords entirely, which two sshd_config settings are required?", options:["ChallengeResponseAuthentication yes and UsePAM no","PermitEmptyPasswords yes and PubkeyAuthentication no","X11Forwarding no and AllowTcpForwarding no","PasswordAuthentication no and PubkeyAuthentication yes"], answer:3, explain:"<strong>PasswordAuthentication no and PubkeyAuthentication yes</strong> disables password logins while ensuring public-key authentication remains enabled.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ChallengeResponseAuthentication yes and UsePAM no</b>: enabling challenge-response can reintroduce password-style prompts and disabling PAM breaks account management.</span><span class='qd'><b>PermitEmptyPasswords yes and PubkeyAuthentication no</b>: this allows empty passwords and disables keys, the opposite of secure.</span><span class='qd'><b>X11Forwarding no and AllowTcpForwarding no</b>: these harden forwarding but do nothing about authentication method.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-048", domain:3, obj:"3.3", diff:"easy", q:"A new file shows permissions rw-rw-r--. The system umask is set to which value to produce this for a regular file?", options:["0022","0002","0077","0011"], answer:1, explain:"<strong>0002</strong>: files start from 666; subtracting a umask of 002 removes write for others, yielding 664 (rw-rw-r--).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>0022</b>: that removes group write too, producing 644 (rw-r--r--).</span><span class='qd'><b>0077</b>: that strips all group and other access, producing 600 (rw-------).</span><span class='qd'><b>0011</b>: subtracting execute bits from a file base that lacks execute leaves 666, not 664.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-049", domain:3, obj:"3.3", diff:"medium", q:"You suspect an unauthorized SUID binary was planted. Which command finds all SUID files across the root filesystem?", options:["find / -perm -2000 -type f","ls -lR / | grep s","find / -type f -name '*.suid'","find / -perm -4000 -type f 2>/dev/null"], answer:3, explain:"<strong>find / -perm -4000 -type f 2>/dev/null</strong> locates files with the SUID bit set (mode 4000), the standard hunt for privilege-escalation binaries.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>find / -perm -2000 -type f</b>: 2000 is the SGID bit, not SUID.</span><span class='qd'><b>ls -lR / | grep s</b>: grepping for 's' is unreliable and catches many false positives.</span><span class='qd'><b>find / -type f -name '*.suid'</b>: SUID is a permission bit, not a filename extension.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-050", domain:3, obj:"3.3", diff:"medium", q:"A user reports 'permission denied' writing to a directory even though chmod 777 was applied. ls -Zd shows an unexpected type. The system is SELinux enforcing. What is the first diagnostic step?", options:["Run chmod 7777 on the directory","Check the SELinux audit denials with ausearch -m avc -ts recent","Disable the firewall","Delete and recreate the user account"], answer:1, explain:"<strong>Check SELinux audit denials with ausearch -m avc -ts recent</strong>: when DAC permissions are wide open but access still fails on an enforcing system, SELinux AVC denials are the likely cause and ausearch reveals them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Run chmod 7777</b>: adding special bits does not address an SELinux type mismatch.</span><span class='qd'><b>Disable the firewall</b>: firewalls govern network traffic, not local file writes.</span><span class='qd'><b>Delete and recreate the user account</b>: the account is not the issue; the security context is.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-051", domain:3, obj:"3.3", diff:"medium", q:"You need to switch to the oracle service account to run a maintenance task, loading its full login environment. Which command is correct?", options:["su - oracle","su oracle","sudo oracle","login oracle"], answer:0, explain:"<strong>su - oracle</strong> starts a login shell for oracle, sourcing its profile and setting the proper environment and working directory.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>su oracle</b>: without the dash it keeps the current environment, which can cause path and variable problems.</span><span class='qd'><b>sudo oracle</b>: 'oracle' is not a command sudo can run; this syntax is invalid.</span><span class='qd'><b>login oracle</b>: login is for new terminal sessions, not switching users from an existing shell.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-052", domain:3, obj:"3.3", diff:"hard", q:"A custom SELinux denial keeps blocking an app and you have confirmed the action is legitimate. Which workflow generates and installs a targeted policy module from the logged denials?", options:["setenforce 0 permanently","chcon -R -t default_t /","ausearch -m avc -ts recent | audit2allow -M myapp then semodule -i myapp.pp","semanage permissive -a unconfined_t"], answer:2, explain:"<strong>ausearch ... | audit2allow -M myapp then semodule -i myapp.pp</strong> compiles the observed denials into a custom policy module and installs it, allowing just that behavior while staying enforcing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>setenforce 0 permanently</b>: disabling enforcement removes all SELinux protection rather than allowing one action.</span><span class='qd'><b>chcon -R -t default_t /</b>: relabeling the whole filesystem to default_t would break the system.</span><span class='qd'><b>semanage permissive -a unconfined_t</b>: making unconfined_t permissive is overly broad and unrelated to the specific app domain.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-053", domain:3, obj:"3.3", diff:"medium", q:"You must give the group dba read and execute on /usr/local/dbtool but leave others with no access, without disturbing the owner. Which symbolic chmod works?", options:["chmod g=rx,o= /usr/local/dbtool","chmod 755 /usr/local/dbtool","chmod o+rx /usr/local/dbtool","chmod a=rx /usr/local/dbtool"], answer:0, explain:"<strong>chmod g=rx,o= /usr/local/dbtool</strong> sets the group to exactly read+execute and clears all permissions for others, leaving the owner untouched.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod 755</b>: that grants read+execute to others as well, violating the no-access requirement.</span><span class='qd'><b>chmod o+rx</b>: this adds access for others, the opposite of what is wanted.</span><span class='qd'><b>chmod a=rx</b>: 'a' includes owner and others, overwriting owner permissions and granting others access.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-054", domain:3, obj:"3.3", diff:"medium", q:"Which command lists the current SELinux mode and whether it is enforcing, permissive, or disabled?", options:["setenforce","sestatus -b","semanage status","getenforce"], answer:3, explain:"<strong>getenforce</strong> prints the current SELinux mode: Enforcing, Permissive, or Disabled.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>setenforce</b>: setenforce changes the mode at runtime; it does not report it.</span><span class='qd'><b>sestatus -b</b>: -b lists boolean values, not the headline mode in isolation.</span><span class='qd'><b>semanage status</b>: 'status' is not a valid semanage subcommand.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-055", domain:3, obj:"3.3", diff:"medium", q:"You want to copy ACLs along with files when archiving so permissions are preserved. Which cp option keeps ACLs and other attributes?", options:["cp -r","cp -p only","cp --no-preserve=all","cp -a"], answer:3, explain:"<strong>cp -a</strong> (archive) preserves ownership, timestamps, symbolic links, and extended attributes including ACLs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cp -r</b>: recursive copy alone does not preserve ACLs or ownership.</span><span class='qd'><b>cp -p only</b>: -p preserves mode and timestamps but not ACLs unless extended; -a is the comprehensive choice.</span><span class='qd'><b>cp --no-preserve=all</b>: that explicitly strips all attributes, the opposite of preservation.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-056", domain:3, obj:"3.3", diff:"hard", q:"An auditor asks you to confirm that the /etc/shadow file cannot be read by ordinary users. Which permission set is correct and secure for /etc/shadow?", options:["0644 root:root","0777 root:root","0000 (or 0640 root:shadow on Debian)","4755 root:root"], answer:2, explain:"<strong>0000, or 0640 root:shadow on Debian</strong>: shadow should be readable only by root (and the shadow group where applicable), keeping password hashes inaccessible to users.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>0644 root:root</b>: world-readable would expose password hashes to every user.</span><span class='qd'><b>0777 root:root</b>: world-writable and readable is catastrophic for a credential file.</span><span class='qd'><b>4755 root:root</b>: SUID plus world read/execute is wholly inappropriate for shadow.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-057", domain:3, obj:"3.3", diff:"medium", q:"You want sudo to require the invoking user's own password (default) but log each command's full path. Which Defaults line ensures command paths are logged via I/O or to syslog with details?", options:["Defaults !authenticate","Defaults targetpw","Defaults runas_default=games","Defaults log_input, log_output"], answer:3, explain:"<strong>Defaults log_input, log_output</strong> records the input and output of sudo sessions, capturing exactly what was run for auditing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Defaults !authenticate</b>: that disables password prompts, weakening security.</span><span class='qd'><b>Defaults targetpw</b>: this requires the target user's password instead of the invoker's, changing auth behavior, not logging.</span><span class='qd'><b>Defaults runas_default=games</b>: that changes the default run-as account, unrelated to logging.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-058", domain:3, obj:"3.4", diff:"medium", q:"Corporate policy requires passwords to expire every 90 days for all new users. Which file controls this default for newly created accounts?", options:["/etc/shadow directly","/etc/login.defs (PASS_MAX_DAYS)","/etc/security/pwquality.conf","/etc/default/grub"], answer:1, explain:"<strong>/etc/login.defs (PASS_MAX_DAYS)</strong> sets the default maximum password age applied when accounts are created.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/shadow directly</b>: editing shadow changes existing users one at a time, not the default for new accounts.</span><span class='qd'><b>/etc/security/pwquality.conf</b>: that governs complexity rules, not aging.</span><span class='qd'><b>/etc/default/grub</b>: grub config controls the bootloader, unrelated to password aging.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-059", domain:3, obj:"3.4", diff:"medium", q:"You must force user jdoe to change their password at next login after a suspected compromise. Which command does this immediately?", options:["passwd -l jdoe","usermod -L jdoe","chage -d 0 jdoe","chage -E 0 jdoe"], answer:2, explain:"<strong>chage -d 0 jdoe</strong> sets the last-change date to epoch zero, which the system treats as immediately expired, prompting a change at next login.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>passwd -l jdoe</b>: -l locks the account, preventing login rather than forcing a change.</span><span class='qd'><b>usermod -L jdoe</b>: -L also locks the password, blocking access.</span><span class='qd'><b>chage -E 0 jdoe</b>: -E sets the account expiration date to epoch, disabling the account entirely.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-060", domain:3, obj:"3.4", diff:"medium", q:"A vendor account should be usable only from a restricted shell that limits the user to a fixed set of commands and prevents changing directories. Which shell provides this?", options:["zsh","rbash (restricted bash)","tcsh","dash"], answer:1, explain:"<strong>rbash (restricted bash)</strong> blocks cd, setting PATH, redirecting output, and running commands with slashes, confining the user to a controlled command set.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>zsh</b>: zsh is a full-featured interactive shell with no built-in restriction mode of this kind.</span><span class='qd'><b>tcsh</b>: tcsh is an enhanced C shell without rbash-style confinement.</span><span class='qd'><b>dash</b>: dash is a minimal POSIX shell but does not restrict navigation or command execution.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-061", domain:3, obj:"3.4", diff:"hard", q:"You are deploying TOTP-based multifactor authentication for SSH logins. Which PAM module and configuration step are required?", options:["Install google-authenticator and add 'auth required pam_google_authenticator.so' plus ChallengeResponseAuthentication yes","Add pam_unix.so with nullok","Set PasswordAuthentication no only","Enable pam_rootok.so for all users"], answer:0, explain:"<strong>Install google-authenticator and add pam_google_authenticator.so plus ChallengeResponseAuthentication yes</strong>: the PAM module validates the TOTP code and SSH must allow challenge-response for the second factor prompt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>pam_unix.so with nullok</b>: nullok permits empty passwords and provides no second factor.</span><span class='qd'><b>PasswordAuthentication no only</b>: disabling passwords alone gives single-factor key auth, not MFA.</span><span class='qd'><b>pam_rootok.so for all users</b>: pam_rootok lets root bypass auth, weakening security rather than adding a factor.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-062", domain:3, obj:"3.4", diff:"medium", q:"To verify the current aging settings (last change, expiry, max days) for user sam, which command should you run?", options:["passwd -S sam","chage -l sam","id sam","getent shadow sam"], answer:1, explain:"<strong>chage -l sam</strong> lists all password-aging parameters including last change, minimum, maximum, warning, and expiration dates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>passwd -S sam</b>: -S gives a brief status line but not the full aging detail chage shows.</span><span class='qd'><b>id sam</b>: id reports UID, GID, and groups, not aging.</span><span class='qd'><b>getent shadow sam</b>: this dumps raw shadow fields and is harder to interpret than chage -l.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-063", domain:3, obj:"3.4", diff:"medium", q:"Best practice says admins should not log in directly as root. Which approach lets a sysadmin perform privileged tasks while preserving accountability?", options:["Share the root password among the team","Log in as a named user and use sudo for privileged commands","Enable PermitRootLogin yes and log in as root","Set the root shell to /bin/bash for everyone"], answer:1, explain:"<strong>Log in as a named user and use sudo</strong>: each admin authenticates as themselves and elevates per-command, producing an auditable trail tied to an individual.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Share the root password</b>: shared credentials destroy accountability and are a security risk.</span><span class='qd'><b>Enable PermitRootLogin yes</b>: direct root login removes the individual audit trail and widens attack surface.</span><span class='qd'><b>Set the root shell to /bin/bash for everyone</b>: that statement is nonsensical for individual accountability and does not address the issue.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-064", domain:3, obj:"3.4", diff:"medium", q:"A contractor account must be automatically disabled on 2026-12-31. Which command sets that account expiration date?", options:["chage -M 365 contractor","usermod -e never contractor","chage -E 2026-12-31 contractor","passwd -x 30 contractor"], answer:2, explain:"<strong>chage -E 2026-12-31 contractor</strong> sets the account expiration date, after which the account is disabled entirely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chage -M 365 contractor</b>: -M sets the maximum password age, not an account end date.</span><span class='qd'><b>usermod -e never contractor</b>: 'never' removes any expiration rather than setting one.</span><span class='qd'><b>passwd -x 30 contractor</b>: -x sets max password age in days, not a fixed expiration date.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-065", domain:3, obj:"3.4", diff:"easy", q:"Which file stores the encrypted password hashes and aging data for local accounts?", options:["/etc/passwd","/etc/shadow","/etc/group","/etc/gshadow"], answer:1, explain:"<strong>/etc/shadow</strong> holds the hashed passwords and aging fields for local users, readable only by root.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/passwd</b>: passwd stores account metadata but uses an x placeholder instead of the hash.</span><span class='qd'><b>/etc/group</b>: group lists group memberships, not password hashes.</span><span class='qd'><b>/etc/gshadow</b>: gshadow holds group passwords, not user hashes and aging.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-066", domain:3, obj:"3.4", diff:"medium", q:"You must prevent password reuse so users cannot recycle their last five passwords. Which PAM setting enforces password history?", options:["remember=5 on the pam_pwhistory or pam_unix line","minlen=5 in pwquality.conf","retry=5 on pam_pwquality","difok=5 on pam_pwquality"], answer:0, explain:"<strong>remember=5 on the pam_pwhistory or pam_unix line</strong> records prior hashes in /etc/security/opasswd and blocks reuse of the last five.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>minlen=5</b>: minlen sets minimum length, not history.</span><span class='qd'><b>retry=5</b>: retry controls how many attempts a user gets at a new password prompt.</span><span class='qd'><b>difok=5</b>: difok requires a number of changed characters, not a reuse window.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-067", domain:3, obj:"3.4", diff:"medium", q:"A service account named backup should never be usable for interactive login but must still own scheduled jobs. Which setting best enforces no-login while keeping the account?", options:["Delete the account with userdel","Set its password to a blank string","Add it to the wheel group","Set its shell to /usr/sbin/nologin"], answer:3, explain:"<strong>Set its shell to /usr/sbin/nologin</strong> politely refuses interactive logins while the account continues to exist and own files and cron jobs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the account with userdel</b>: deleting it would orphan its files and scheduled jobs.</span><span class='qd'><b>Set its password to a blank string</b>: a blank password could permit login and is insecure.</span><span class='qd'><b>Add it to the wheel group</b>: wheel grants sudo privileges, the opposite of restricting it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-068", domain:3, obj:"3.4", diff:"hard", q:"You configured pam_faillock to lock accounts after failures, but legitimate users remain locked even after the unlock_time passes. Which command manually clears a user's fail counter?", options:["faillock --user jdoe --reset","pam_tally2 --reset jdoe","chage -d 0 jdoe","passwd -u jdoe"], answer:0, explain:"<strong>faillock --user jdoe --reset</strong> clears the recorded failures for the user, immediately unlocking the account managed by pam_faillock.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>pam_tally2 --reset jdoe</b>: pam_tally2 is the legacy module replaced by faillock and will not touch faillock's counters.</span><span class='qd'><b>chage -d 0 jdoe</b>: that forces a password change, not a lockout reset.</span><span class='qd'><b>passwd -u jdoe</b>: -u unlocks a password locked by passwd -l, a different mechanism.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-069", domain:3, obj:"3.4", diff:"medium", q:"Policy mandates that new passwords differ from the old one by at least 4 characters. Which pam_pwquality parameter enforces this?", options:["difok=4","minlen=4","maxrepeat=4","ucredit=4"], answer:0, explain:"<strong>difok=4</strong> requires at least four characters in the new password to differ from the previous one.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>minlen=4</b>: minlen sets total length, not the difference from the old password.</span><span class='qd'><b>maxrepeat=4</b>: maxrepeat limits consecutive identical characters.</span><span class='qd'><b>ucredit=4</b>: ucredit adjusts credit for uppercase characters, not difference.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-070", domain:3, obj:"3.5", diff:"medium", q:"You must encrypt an entire new data partition /dev/sdb1 at rest using LUKS. Which command initializes the encrypted container?", options:["mkfs.ext4 /dev/sdb1","gpg -c /dev/sdb1","openssl enc -aes-256-cbc -in /dev/sdb1","cryptsetup luksFormat /dev/sdb1"], answer:3, explain:"<strong>cryptsetup luksFormat /dev/sdb1</strong> sets up the LUKS header and encryption parameters on the partition, the first step in full-disk encryption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mkfs.ext4</b>: that makes a plaintext filesystem with no encryption.</span><span class='qd'><b>gpg -c</b>: gpg encrypts individual files, not block devices.</span><span class='qd'><b>openssl enc</b>: openssl enc encrypts streams or files, not a live partition as a managed volume.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-071", domain:3, obj:"3.5", diff:"medium", q:"After luksFormat, you must open the encrypted device so it appears as /dev/mapper/secure for formatting. Which command does this?", options:["cryptsetup luksClose secure","mount /dev/sdb1 /secure","cryptsetup luksFormat /dev/mapper/secure","cryptsetup luksOpen /dev/sdb1 secure"], answer:3, explain:"<strong>cryptsetup luksOpen /dev/sdb1 secure</strong> unlocks the LUKS volume and maps it to /dev/mapper/secure for filesystem creation and mounting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cryptsetup luksClose secure</b>: luksClose tears down an already-open mapping.</span><span class='qd'><b>mount /dev/sdb1 /secure</b>: you cannot mount the raw encrypted device; it must be opened first.</span><span class='qd'><b>cryptsetup luksFormat /dev/mapper/secure</b>: re-formatting would wipe the header you just created.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-072", domain:3, obj:"3.5", diff:"medium", q:"You need to encrypt a sensitive file backup.tar for a colleague using their public key so only they can decrypt it. Which GPG command is correct?", options:["gpg --symmetric backup.tar","gpg --sign backup.tar","gpg --export colleague@example.com","gpg --encrypt --recipient colleague@example.com backup.tar"], answer:3, explain:"<strong>gpg --encrypt --recipient colleague@example.com backup.tar</strong> encrypts the file with the recipient's public key so only their private key can decrypt it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>gpg --symmetric</b>: symmetric uses a shared passphrase, not the colleague's public key.</span><span class='qd'><b>gpg --sign</b>: signing proves authorship but does not encrypt the contents.</span><span class='qd'><b>gpg --export</b>: that exports a public key, not the file.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-073", domain:3, obj:"3.5", diff:"easy", q:"You downloaded an ISO and a published SHA-256 checksum. Which command computes the file's hash to compare?", options:["md5sum image.iso","gpg --verify image.iso","openssl genrsa image.iso","sha256sum image.iso"], answer:3, explain:"<strong>sha256sum image.iso</strong> produces the SHA-256 digest you compare against the published value to verify integrity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>md5sum</b>: MD5 is a different and weaker algorithm; it would not match a SHA-256 checksum.</span><span class='qd'><b>gpg --verify</b>: that checks a detached signature, not a raw checksum.</span><span class='qd'><b>openssl genrsa</b>: genrsa generates an RSA key, unrelated to hashing a file.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-074", domain:3, obj:"3.5", diff:"hard", q:"You must generate a 2048-bit RSA private key and a certificate signing request for www.example.com in one OpenSSL command. Which command is correct?", options:["openssl x509 -req -in www.csr -signkey www.key","openssl genrsa -out www.key 2048 -csr","openssl req -new -newkey rsa:2048 -nodes -keyout www.key -out www.csr","openssl s_client -connect www.example.com:443"], answer:2, explain:"<strong>openssl req -new -newkey rsa:2048 -nodes -keyout www.key -out www.csr</strong> creates the key and the CSR together, with -nodes leaving the key unencrypted for unattended use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>openssl x509 -req -in www.csr -signkey www.key</b>: that self-signs an existing CSR; it does not generate a key and CSR.</span><span class='qd'><b>openssl genrsa -out www.key 2048 -csr</b>: genrsa only makes a key and has no -csr option.</span><span class='qd'><b>openssl s_client -connect ...</b>: s_client tests a TLS connection, not certificate generation.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-075", domain:3, obj:"3.5", diff:"medium", q:"To inspect the subject, issuer, and validity dates of an existing certificate file server.crt, which OpenSSL command works?", options:["openssl req -in server.crt -text","openssl x509 -in server.crt -noout -text","openssl rsa -in server.crt","openssl dgst -sha256 server.crt"], answer:1, explain:"<strong>openssl x509 -in server.crt -noout -text</strong> decodes the X.509 certificate and prints its fields including subject, issuer, and validity period.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>openssl req -in server.crt -text</b>: req parses CSRs, not issued certificates.</span><span class='qd'><b>openssl rsa -in server.crt</b>: rsa handles private/public keys, not certificates.</span><span class='qd'><b>openssl dgst -sha256 server.crt</b>: dgst hashes the file rather than decoding the certificate.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-076", domain:3, obj:"3.5", diff:"medium", q:"You are setting up a WireGuard VPN tunnel. Which command generates the private key, and how is the public key derived?", options:["wg genkey produces the private key; wg pubkey derives the public key from it","ssh-keygen -t wg creates both keys","openssl wireguard -keygen","wg-quick genkey both"], answer:0, explain:"<strong>wg genkey produces the private key; wg pubkey derives the public key</strong>: you typically pipe wg genkey into a file and tee it through wg pubkey to obtain the matching public key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ssh-keygen -t wg</b>: ssh-keygen has no wg key type; WireGuard uses its own tooling.</span><span class='qd'><b>openssl wireguard -keygen</b>: openssl has no wireguard subcommand.</span><span class='qd'><b>wg-quick genkey both</b>: wg-quick brings tunnels up/down and does not generate keys.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-077", domain:3, obj:"3.5", diff:"medium", q:"You must verify that a colleague's GPG-signed message message.txt.asc genuinely came from them. Which command checks the signature?", options:["gpg --decrypt --symmetric message.txt.asc","gpg --verify message.txt.asc","gpg --import message.txt.asc","sha256sum message.txt.asc"], answer:1, explain:"<strong>gpg --verify message.txt.asc</strong> validates the digital signature against the sender's imported public key, confirming authenticity and integrity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>gpg --decrypt --symmetric</b>: symmetric decryption expects a passphrase, not a signature check.</span><span class='qd'><b>gpg --import</b>: import adds keys to the keyring; it does not verify a signature.</span><span class='qd'><b>sha256sum</b>: a checksum proves integrity but not who signed the message.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-078", domain:3, obj:"3.5", diff:"hard", q:"A LUKS-encrypted volume must unlock automatically at boot from a key file stored on a separate encrypted device. Which file maps the device to its key for systemd to open it?", options:["/etc/fstab","/etc/luks.conf","/etc/crypttab","/etc/cryptsetup-keys.d/init"], answer:2, explain:"<strong>/etc/crypttab</strong> lists encrypted devices, their UUIDs, and the key file or password source used to unlock them at boot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/fstab</b>: fstab mounts filesystems after they are unlocked, referencing the mapper device, not the LUKS key.</span><span class='qd'><b>/etc/luks.conf</b>: no such standard configuration file governs auto-unlock.</span><span class='qd'><b>/etc/cryptsetup-keys.d/init</b>: that directory may store key files but does not define the device-to-key mapping crypttab provides.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-079", domain:3, obj:"3.5", diff:"medium", q:"You need to add a second passphrase to an existing LUKS volume on /dev/sdb1 without destroying the current key. Which command does this?", options:["cryptsetup luksFormat /dev/sdb1","cryptsetup luksAddKey /dev/sdb1","cryptsetup luksRemoveKey /dev/sdb1","cryptsetup resize /dev/sdb1"], answer:1, explain:"<strong>cryptsetup luksAddKey /dev/sdb1</strong> adds a new passphrase to an available key slot while leaving existing slots intact.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cryptsetup luksFormat</b>: reformatting overwrites the header and destroys all existing keys and data.</span><span class='qd'><b>cryptsetup luksRemoveKey</b>: that deletes a passphrase rather than adding one.</span><span class='qd'><b>cryptsetup resize</b>: resize changes the mapped device size, not key slots.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-080", domain:3, obj:"3.5", diff:"medium", q:"For a web server you must combine the server certificate with the intermediate CA certificate into a single chain file for TLS. What is the correct order in the bundle?", options:["Server certificate first, then intermediate CA certificate","Intermediate CA first, then server certificate","Root CA first, then server certificate","Private key first, then certificates"], answer:0, explain:"<strong>Server certificate first, then intermediate CA certificate</strong>: TLS chain files are ordered leaf-to-root, so the server cert precedes the intermediate(s).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Intermediate CA first, then server certificate</b>: reversing the order breaks chain validation in many clients.</span><span class='qd'><b>Root CA first, then server certificate</b>: the root is normally omitted and never placed first in the chain.</span><span class='qd'><b>Private key first, then certificates</b>: the private key belongs in a separate file, not concatenated into the public chain.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-081", domain:3, obj:"3.5", diff:"medium", q:"You want to encrypt a single archive with a shared passphrase using AES-256 via GPG (no key pair). Which command is correct?", options:["gpg --encrypt --recipient self secret.tar","gpg --gen-key","gpg --symmetric --cipher-algo AES256 secret.tar","openssl rsautl -encrypt -in secret.tar"], answer:2, explain:"<strong>gpg --symmetric --cipher-algo AES256 secret.tar</strong> encrypts with a passphrase using AES-256, requiring no public/private keys.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>gpg --encrypt --recipient self</b>: that uses asymmetric keys, not a shared passphrase.</span><span class='qd'><b>gpg --gen-key</b>: that creates a key pair and encrypts nothing.</span><span class='qd'><b>openssl rsautl -encrypt</b>: rsautl needs an RSA key and is unsuited to large files or passphrase-only encryption.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-082", domain:3, obj:"3.5", diff:"hard", q:"A TLS handshake to your service fails with 'certificate verify failed: unable to get local issuer certificate'. The leaf cert is valid. What is the most likely fix?", options:["Regenerate the private key","Disable SELinux on the server","Install or bundle the missing intermediate CA certificate in the chain","Switch the cipher to RC4"], answer:2, explain:"<strong>Install or bundle the missing intermediate CA certificate</strong>: this error means the client cannot build a path to a trusted root because the intermediate is absent from the served chain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Regenerate the private key</b>: the key is fine; the issue is chain completeness.</span><span class='qd'><b>Disable SELinux</b>: SELinux does not cause certificate path-building failures.</span><span class='qd'><b>Switch the cipher to RC4</b>: RC4 is insecure and unrelated to issuer verification.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-083", domain:3, obj:"3.5", diff:"medium", q:"You must confirm which cipher and TLS version a remote HTTPS server negotiates. Which OpenSSL command connects and reports this?", options:["openssl ciphers -v","openssl x509 -in cert.pem -text","openssl rand -hex 16","openssl s_client -connect example.com:443"], answer:3, explain:"<strong>openssl s_client -connect example.com:443</strong> opens a TLS session and prints the negotiated protocol, cipher, and presented certificate chain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>openssl ciphers -v</b>: that lists locally supported ciphers, not what the server negotiates.</span><span class='qd'><b>openssl x509 -in cert.pem -text</b>: that decodes a local file, not a live connection.</span><span class='qd'><b>openssl rand -hex 16</b>: rand generates random bytes, unrelated to TLS inspection.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-084", domain:3, obj:"3.5", diff:"medium", q:"Your organization runs an internal PKI. To trust certificates issued by your private CA on a RHEL host, where do you place the CA certificate and which command updates the trust store?", options:["Copy to /etc/pki/ca-trust/source/anchors/ then run update-ca-trust","Copy to /etc/ssl/certs then reboot","Add it to ~/.ssh/known_hosts","Run openssl x509 -trust on every connection"], answer:0, explain:"<strong>Copy to /etc/pki/ca-trust/source/anchors/ then run update-ca-trust</strong> installs the CA into the system trust store on RHEL-family systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Copy to /etc/ssl/certs then reboot</b>: that is the Debian path and a reboot does not rebuild the RHEL trust bundle.</span><span class='qd'><b>Add it to ~/.ssh/known_hosts</b>: known_hosts stores SSH host keys, not TLS CAs.</span><span class='qd'><b>openssl x509 -trust on every connection</b>: that is not a practical system-wide trust mechanism.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-085", domain:3, obj:"3.5", diff:"medium", q:"You must back up the LUKS header of /dev/sdb1 so you can recover if it becomes corrupted. Which command saves the header?", options:["cryptsetup luksHeaderBackup /dev/sdb1 --header-backup-file hdr.img","cryptsetup luksDump /dev/sdb1 > hdr.img","dd if=/dev/sdb1 of=hdr.img bs=1M count=1","cryptsetup luksErase /dev/sdb1"], answer:0, explain:"<strong>cryptsetup luksHeaderBackup /dev/sdb1 --header-backup-file hdr.img</strong> writes a clean copy of the LUKS header for later restoration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cryptsetup luksDump > hdr.img</b>: luksDump prints human-readable metadata, not a restorable binary header.</span><span class='qd'><b>dd ... count=1</b>: a crude dd copy may not capture the full header layout reliably and risks size errors.</span><span class='qd'><b>cryptsetup luksErase</b>: that destroys all key slots, the opposite of a backup.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-086", domain:3, obj:"3.6", diff:"medium", q:"Security mandates a scheduled scan of a RHEL host against a CIS or STIG profile to produce a remediation report. Which tool performs SCAP-based compliance scanning?", options:["rkhunter","oscap (OpenSCAP)","aide","nmap"], answer:1, explain:"<strong>oscap (OpenSCAP)</strong> evaluates the system against SCAP content such as CIS and DISA STIG profiles and generates compliance and remediation reports.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rkhunter</b>: rkhunter hunts for rootkits, not policy compliance.</span><span class='qd'><b>aide</b>: AIDE checks file integrity, not benchmark compliance.</span><span class='qd'><b>nmap</b>: nmap scans networks and ports, unrelated to SCAP compliance.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-087", domain:3, obj:"3.6", diff:"medium", q:"You installed AIDE for file integrity monitoring. After configuration, which step must run before AIDE can detect future changes?", options:["aide --check immediately","rkhunter --update","aide --remove","aide --init to build the baseline database"], answer:3, explain:"<strong>aide --init to build the baseline database</strong> records the current known-good state; later --check runs compare against this baseline to flag changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>aide --check immediately</b>: a check has nothing to compare against until the baseline exists.</span><span class='qd'><b>rkhunter --update</b>: that updates a different tool's signatures, not AIDE's database.</span><span class='qd'><b>aide --remove</b>: that is not how you establish a baseline and would not initialize anything.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-088", domain:3, obj:"3.6", diff:"medium", q:"After an AIDE baseline is built, integrity checks report many false positives because legitimate updates changed files. Which command accepts the new state as the baseline?", options:["aide --init --force-clean","rm /var/lib/aide/aide.db","aide --update then move the new database into place","aide --report-only"], answer:2, explain:"<strong>aide --update then move the new database into place</strong> generates an updated database reflecting the legitimate changes, which you then promote to the active baseline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>aide --init --force-clean</b>: --force-clean is not a standard AIDE option for rebaselining.</span><span class='qd'><b>rm /var/lib/aide/aide.db</b>: deleting the database leaves AIDE with no baseline at all.</span><span class='qd'><b>aide --report-only</b>: that just reports and does not update the baseline.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-089", domain:3, obj:"3.6", diff:"medium", q:"You must securely erase a single sensitive file on an HDD so its contents cannot be recovered. Which command overwrites and removes it?", options:["rm -f secret.dat","truncate -s 0 secret.dat","mv secret.dat /dev/null","shred -u -n 3 secret.dat"], answer:3, explain:"<strong>shred -u -n 3 secret.dat</strong> overwrites the file three times then unlinks it, making recovery on a traditional disk far harder.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rm -f secret.dat</b>: rm only unlinks the inode, leaving the data blocks recoverable.</span><span class='qd'><b>truncate -s 0</b>: truncation drops the size but may leave residual data and does not overwrite securely.</span><span class='qd'><b>mv secret.dat /dev/null</b>: moving to /dev/null is not a deletion and behaves unexpectedly.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-090", domain:3, obj:"3.6", diff:"hard", q:"A vulnerability report lists CVE-2024-XXXX affecting openssl on your servers. You must confirm whether the installed package includes the fix. Which approach is most reliable on RHEL?", options:["Run openssl version and assume upstream version maps to the CVE","Delete openssl and reinstall","Check rpm changelog with rpm -q --changelog openssl and compare against the vendor advisory","Disable openssl in firewalld"], answer:2, explain:"<strong>Check rpm -q --changelog openssl against the vendor advisory</strong>: distributions backport security fixes, so the changelog (and the RHSA/CVE reference) is the reliable way to confirm the patch is present.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>openssl version and assume upstream mapping</b>: backporting means the upstream version number alone does not indicate the fix.</span><span class='qd'><b>Delete openssl and reinstall</b>: reinstalling the same version changes nothing and may break dependencies.</span><span class='qd'><b>Disable openssl in firewalld</b>: openssl is a library, not a firewall service to disable.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-091", domain:3, obj:"3.6", diff:"medium", q:"You want to scan a host for known rootkits, backdoors, and suspicious local file changes. Which tool is purpose-built for this?", options:["oscap","lynis --pentest only","tcpdump","rkhunter"], answer:3, explain:"<strong>rkhunter</strong> scans for rootkits, backdoors, and known malicious patterns by checking file hashes, suspicious files, and configuration anomalies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>oscap</b>: OpenSCAP evaluates compliance benchmarks, not rootkit signatures.</span><span class='qd'><b>lynis --pentest only</b>: lynis audits configuration hardening broadly but is not the dedicated rootkit hunter implied, and --pentest is a mode flag, not a rootkit scan.</span><span class='qd'><b>tcpdump</b>: tcpdump captures network packets, not local rootkits.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-092", domain:3, obj:"3.6", diff:"medium", q:"A decommissioned SSD must be sanitized before disposal. Why is shred a poor choice and what is the recommended approach?", options:["shred works perfectly on SSDs, no change needed","Use rm -rf / on the device","Format with mkfs and consider it sanitized","SSD wear-leveling can leave copies; use the drive's secure-erase (ATA Secure Erase via hdparm or blkdiscard) or crypto-erase"], answer:3, explain:"<strong>SSD wear-leveling can leave copies; use ATA Secure Erase (hdparm/blkdiscard) or crypto-erase</strong>: because SSD controllers remap blocks, overwriting logical addresses does not guarantee all cells are cleared, so a controller-level secure erase is recommended.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>shred works perfectly on SSDs</b>: shred assumes overwriting the same physical sectors, which wear-leveling defeats.</span><span class='qd'><b>Use rm -rf / on the device</b>: that deletes files but leaves data recoverable and is dangerous.</span><span class='qd'><b>Format with mkfs</b>: a quick format leaves the underlying data largely intact.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-093", domain:3, obj:"3.6", diff:"medium", q:"After running an OpenSCAP scan you must produce a human-readable HTML report from the results XML. Which oscap option generates it?", options:["oscap info results.xml","oscap xccdf eval --fetch-remote-resources","oscap oval collect results.xml","oscap xccdf generate report results.xml > report.html"], answer:3, explain:"<strong>oscap xccdf generate report results.xml > report.html</strong> transforms the scan results into a formatted HTML report for review.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>oscap info results.xml</b>: info summarizes content metadata, not a full report.</span><span class='qd'><b>oscap xccdf eval --fetch-remote-resources</b>: that runs a new evaluation rather than rendering an existing result.</span><span class='qd'><b>oscap oval collect results.xml</b>: collect gathers OVAL system characteristics, not a report.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-094", domain:3, obj:"3.6", diff:"hard", q:"You must overwrite an entire old spinning disk /dev/sdc before redeployment, leaving zeros across the whole device. Which command is appropriate?", options:["dd if=/dev/zero of=/dev/sdc bs=4M status=progress","shred -n 1 /dev/sdc1 only","rm -rf /dev/sdc","mkfs.xfs /dev/sdc"], answer:0, explain:"<strong>dd if=/dev/zero of=/dev/sdc bs=4M status=progress</strong> writes zeros across the entire device, a standard whole-disk wipe for an HDD before redeployment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>shred -n 1 /dev/sdc1 only</b>: targeting one partition leaves the rest of the disk and any other partitions intact.</span><span class='qd'><b>rm -rf /dev/sdc</b>: rm cannot remove a block device's data and is meaningless here.</span><span class='qd'><b>mkfs.xfs /dev/sdc</b>: making a filesystem leaves most underlying data recoverable.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-095", domain:3, obj:"3.6", diff:"medium", q:"An AIDE check flags /usr/bin/find as changed after a routine yum update. Before re-baselining, how do you decide whether this is benign?", options:["Immediately restore the file from backup","Disable AIDE permanently","Cross-reference the change with the package manager's update history (e.g., yum history / rpm -V)","Run shred on /usr/bin/find"], answer:2, explain:"<strong>Cross-reference with the package manager's update history</strong>: correlating the changed binary with a legitimate yum/rpm update confirms it is an expected change before you accept it into the baseline.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately restore from backup</b>: that could revert a legitimate security update.</span><span class='qd'><b>Disable AIDE permanently</b>: turning off integrity monitoring defeats its purpose.</span><span class='qd'><b>Run shred on /usr/bin/find</b>: destroying a core utility would break the system.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-096", domain:3, obj:"3.6", diff:"medium", q:"You must apply an OpenSCAP profile and have it automatically remediate failing rules during the scan on a RHEL host. Which option enables automatic remediation?", options:["oscap xccdf eval --report-only","oscap xccdf eval --skip-rules all","oscap info --remediate","oscap xccdf eval --remediate --profile ..."], answer:3, explain:"<strong>oscap xccdf eval --remediate --profile ...</strong> runs the evaluation and then applies the bundled fixes for rules that failed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>--report-only</b>: that is not a remediation flag and does not change the system.</span><span class='qd'><b>--skip-rules all</b>: skipping rules avoids checking them, the opposite of remediating.</span><span class='qd'><b>oscap info --remediate</b>: info inspects content and has no remediation capability.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-097", domain:3, obj:"3.6", diff:"medium", q:"A daily AIDE run should email the admin when integrity changes are detected. Which is the most appropriate place to schedule and wire this?", options:["Adding aide --check to /etc/fstab","Setting AIDE in /etc/sudoers","Putting aide --check in ~/.bashrc","A cron job (or systemd timer) running aide --check and piping output to mail"], answer:3, explain:"<strong>A cron job or systemd timer running aide --check piped to mail</strong> schedules regular checks and alerts the admin when differences appear.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Adding it to /etc/fstab</b>: fstab defines mounts, not scheduled commands.</span><span class='qd'><b>Setting AIDE in /etc/sudoers</b>: sudoers grants privileges; it does not schedule jobs.</span><span class='qd'><b>Putting it in ~/.bashrc</b>: bashrc runs at interactive shell start, not on a reliable daily schedule.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-098", domain:3, obj:"3.6", diff:"easy", q:"Which command displays detailed information about a known vulnerability fix included in an installed RPM, including the CVE references in its changelog?", options:["rpm -V kernel","rpm -e kernel","rpm -q --changelog kernel","yum clean all"], answer:2, explain:"<strong>rpm -q --changelog kernel</strong> prints the package changelog, which lists the backported security fixes and their CVE identifiers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>rpm -V kernel</b>: -V verifies installed files against package metadata, not CVE history.</span><span class='qd'><b>rpm -e kernel</b>: -e erases the package, a destructive action.</span><span class='qd'><b>yum clean all</b>: that clears cached metadata and shows no changelog.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-099", domain:3, obj:"3.6", diff:"hard", q:"You suspect a host is compromised. AIDE, rkhunter, and an OpenSCAP scan all run from the potentially compromised system. What is the key limitation of trusting their results?", options:["The tools cannot run as root","A rootkit may subvert the tools or kernel, so scanning from a trusted live medium is more reliable","The results are always encrypted and unreadable","Scans require disabling SELinux first"], answer:1, explain:"<strong>A rootkit may subvert the tools or kernel, so scanning from a trusted live medium is more reliable</strong>: on a compromised host, the kernel and binaries can be tampered with to hide the intrusion, so forensic checks should run from known-good external media.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The tools cannot run as root</b>: these tools normally run as root, which is not the limitation.</span><span class='qd'><b>The results are always encrypted and unreadable</b>: the reports are plain readable output.</span><span class='qd'><b>Scans require disabling SELinux first</b>: they do not require disabling SELinux.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D3-100", domain:3, obj:"3.6", diff:"medium", q:"Before disposing of backup tapes containing client data, what is the most appropriate sanitization method given that overwriting tapes reliably is impractical?", options:["A single rm of the index files","Rewinding and ejecting the tapes","Degaussing followed by physical destruction","Storing them in a locked drawer indefinitely"], answer:2, explain:"<strong>Degaussing followed by physical destruction</strong>: magnetic tape is best sanitized by degaussing (which erases the magnetic domains) and then physically destroyed to guarantee data cannot be recovered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single rm of the index files</b>: removing an index leaves the actual recorded data intact on the tape.</span><span class='qd'><b>Rewinding and ejecting the tapes</b>: that performs no sanitization at all.</span><span class='qd'><b>Storing them in a locked drawer indefinitely</b>: retention is not disposal and leaves the data at ongoing risk.</span>" }
);

/* linux+ :: XK0-006 Domain 4 question bank (100 items, inline). Populates LINUXPLUS.questions. */
window.LINUXPLUS = window.LINUXPLUS || {}; LINUXPLUS.questions = LINUXPLUS.questions || [];
LINUXPLUS.questions.push(
{ id:"D4-001", domain:4, obj:"4.1", diff:"medium", q:"Which characteristic best defines Infrastructure as Code (IaC)?", options:["Defining and provisioning infrastructure through machine-readable definition files under version control","Manually documenting server builds in a wiki for repeatability","Using a GUI console to click through cloud resource creation","Storing server passwords in an encrypted vault"], answer:0, explain:"<strong>IaC</strong> manages and provisions infrastructure through declarative or imperative definition files that can be versioned, reviewed, and reused, ensuring consistent, repeatable deployments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manually documenting server builds in a wiki for repeatability</b>: documentation is not executable code and cannot automatically provision anything.</span><span class='qd'><b>Using a GUI console to click through cloud resource creation</b>: clicking through a console is manual and not codified or repeatable.</span><span class='qd'><b>Storing server passwords in an encrypted vault</b>: secrets management is unrelated to defining infrastructure as code.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-002", domain:4, obj:"4.1", diff:"easy", q:"Which Ansible component is the inventory file used for?", options:["Defining the tasks to run on hosts","Storing reusable variable defaults for a role","Encrypting sensitive playbook data","Listing the managed hosts and groups Ansible will target"], answer:3, explain:"<strong>The inventory</strong> lists the managed hosts (and optional groups) that Ansible connects to and acts upon, either as a static file or generated dynamically.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Defining the tasks to run on hosts</b>: tasks are defined in playbooks and roles, not the inventory.</span><span class='qd'><b>Storing reusable variable defaults for a role</b>: role defaults live in a role's defaults/main.yml, not inventory.</span><span class='qd'><b>Encrypting sensitive playbook data</b>: encryption of secrets is handled by Ansible Vault.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-003", domain:4, obj:"4.1", diff:"medium", q:"Ansible is frequently described as 'agentless.' What does this mean?", options:["It requires a daemon installed on every managed node","It can only manage the control node itself","It connects to managed nodes over SSH without needing pre-installed agent software","It uses a proprietary binary protocol instead of SSH"], answer:2, explain:"<strong>Agentless</strong> means Ansible pushes configuration over SSH (or WinRM) and does not require a persistent agent process running on each managed node.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It requires a daemon installed on every managed node</b>: that describes agent-based tools like Puppet, the opposite of agentless.</span><span class='qd'><b>It can only manage the control node itself</b>: Ansible manages many remote nodes, not just localhost.</span><span class='qd'><b>It uses a proprietary binary protocol instead of SSH</b>: Ansible relies on standard SSH transport, not a proprietary protocol.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-004", domain:4, obj:"4.1", diff:"medium", q:"In Puppet's architecture, what is the role of the Puppet agent?", options:["It compiles the catalog from manifests","It stores reports in PuppetDB","It serves as the certificate authority","It runs on managed nodes, requests a catalog, and applies the desired state"], answer:3, explain:"<strong>The Puppet agent</strong> runs on each managed node, periodically contacts the Puppet server to fetch a compiled catalog, and enforces the described desired state locally.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It compiles the catalog from manifests</b>: catalog compilation is done by the Puppet server (master), not the agent.</span><span class='qd'><b>It stores reports in PuppetDB</b>: PuppetDB storage is a server-side function.</span><span class='qd'><b>It serves as the certificate authority</b>: the CA is a server-side service that signs agent certificates.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-005", domain:4, obj:"4.1", diff:"medium", q:"What is OpenTofu?", options:["A container runtime that replaces Docker","A configuration management agent like Puppet","An open-source, community-driven fork of Terraform for declarative infrastructure provisioning","A CI/CD pipeline orchestrator"], answer:2, explain:"<strong>OpenTofu</strong> is an open-source fork of Terraform that provides declarative, provider-based infrastructure provisioning using HCL configuration files and state management.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A container runtime that replaces Docker</b>: OpenTofu provisions infrastructure, it is not a container runtime.</span><span class='qd'><b>A configuration management agent like Puppet</b>: OpenTofu provisions resources declaratively rather than acting as a node agent.</span><span class='qd'><b>A CI/CD pipeline orchestrator</b>: it is an IaC tool, not a pipeline engine.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-006", domain:4, obj:"4.1", diff:"medium", q:"During an automated Red Hat installation, which file provides answers to the installer so no interactive prompts are needed?", options:["preseed.cfg","autoyast.xml","kickstart (ks.cfg)","cloud-config.yaml"], answer:2, explain:"<strong>Kickstart (ks.cfg)</strong> supplies answers to the Anaconda installer so RHEL-family systems can be installed unattended, defining partitioning, packages, and post-install scripts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>preseed.cfg</b>: preseed is the unattended-install mechanism for Debian/Ubuntu, not Red Hat.</span><span class='qd'><b>autoyast.xml</b>: AutoYaST is the SUSE automated install format.</span><span class='qd'><b>cloud-config.yaml</b>: cloud-init configures instances after boot, not the OS installer.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-007", domain:4, obj:"4.1", diff:"medium", q:"What is the primary purpose of cloud-init on a cloud virtual machine?", options:["To install the operating system from scratch","To act as a long-running configuration management agent","To perform early initialization and customization of an instance on first boot using metadata","To build container images"], answer:2, explain:"<strong>cloud-init</strong> runs during the first boot of a cloud instance to handle early initialization tasks such as setting hostnames, injecting SSH keys, creating users, and running user-data scripts from provider metadata.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To install the operating system from scratch</b>: the OS is already present in the image; cloud-init customizes it, not installs it.</span><span class='qd'><b>To act as a long-running configuration management agent</b>: cloud-init focuses on boot-time setup, not continuous enforcement.</span><span class='qd'><b>To build container images</b>: image building is unrelated to cloud-init's instance customization role.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-008", domain:4, obj:"4.1", diff:"easy", q:"What does CI/CD stand for in DevOps pipelines?", options:["Code Inspection / Code Deployment","Container Image / Container Distribution","Central Inventory / Configuration Database","Continuous Integration / Continuous Delivery (or Deployment)"], answer:3, explain:"<strong>CI/CD</strong> stands for Continuous Integration and Continuous Delivery (or Deployment), the practice of automatically building, testing, and releasing code changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Code Inspection / Code Deployment</b>: this is not the standard expansion of the acronym.</span><span class='qd'><b>Container Image / Container Distribution</b>: these terms relate to containers, not the CI/CD pipeline concept.</span><span class='qd'><b>Central Inventory / Configuration Database</b>: this describes a CMDB, not CI/CD.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-009", domain:4, obj:"4.1", diff:"medium", q:"In a CI/CD pipeline, what is the primary goal of the Continuous Integration stage?", options:["Automatically deploy to production after every commit","Provision cloud infrastructure with Terraform","Roll back failed releases automatically","Frequently merge code and automatically build and test it to catch defects early"], answer:3, explain:"<strong>Continuous Integration</strong> emphasizes merging developer changes frequently and automatically building and running tests so integration problems are detected early.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Automatically deploy to production after every commit</b>: that describes continuous deployment, a later stage.</span><span class='qd'><b>Provision cloud infrastructure with Terraform</b>: provisioning is an IaC task, not the focus of CI.</span><span class='qd'><b>Roll back failed releases automatically</b>: rollback is a deployment concern, not the CI build/test goal.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-010", domain:4, obj:"4.1", diff:"medium", q:"Which practice best describes DevSecOps?", options:["Running security scans only after the application is in production","Separating the security team entirely from developers","Replacing all manual testing with penetration testing","Integrating security testing and controls throughout the development and deployment pipeline"], answer:3, explain:"<strong>DevSecOps</strong> shifts security left by embedding automated security testing, policy checks, and controls throughout the CI/CD pipeline rather than treating security as a final gate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Running security scans only after the application is in production</b>: that is the late, traditional approach DevSecOps aims to replace.</span><span class='qd'><b>Separating the security team entirely from developers</b>: DevSecOps integrates security with development rather than isolating it.</span><span class='qd'><b>Replacing all manual testing with penetration testing</b>: DevSecOps adds automation across the pipeline, not just pen testing.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-011", domain:4, obj:"4.1", diff:"medium", q:"In Kubernetes, what is a Pod?", options:["A physical worker machine in the cluster","A persistent storage volume","The smallest deployable unit, wrapping one or more tightly coupled containers","A network load balancer"], answer:2, explain:"<strong>A Pod</strong> is the smallest deployable unit in Kubernetes; it encapsulates one or more containers that share networking and storage and are scheduled together.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A physical worker machine in the cluster</b>: that is a Node, not a Pod.</span><span class='qd'><b>A persistent storage volume</b>: storage is provided by PersistentVolumes, not Pods.</span><span class='qd'><b>A network load balancer</b>: load balancing is handled by Services, not Pods.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-012", domain:4, obj:"4.1", diff:"medium", q:"Which Kubernetes object maintains a specified number of replica Pods and replaces ones that fail?", options:["ConfigMap","Namespace","Secret","Deployment"], answer:3, explain:"<strong>A Deployment</strong> manages a ReplicaSet to keep a declared number of Pod replicas running, performing rolling updates and recreating failed Pods.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ConfigMap</b>: a ConfigMap stores configuration data, it does not manage Pod replicas.</span><span class='qd'><b>Namespace</b>: a Namespace provides logical isolation, not replica management.</span><span class='qd'><b>Secret</b>: a Secret stores sensitive data, not workload replicas.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-013", domain:4, obj:"4.1", diff:"medium", q:"What does the Docker Compose file (compose.yaml) primarily define?", options:["The kernel modules a container needs","The firewall rules for the Docker host","The base image layers of a single image","A multi-container application with its services, networks, and volumes"], answer:3, explain:"<strong>compose.yaml</strong> declaratively defines a multi-container application, including its services, the images they use, networks, and volumes, so the whole stack can be started with one command.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The kernel modules a container needs</b>: Compose does not manage kernel modules.</span><span class='qd'><b>The firewall rules for the Docker host</b>: host firewalling is configured separately, not in Compose.</span><span class='qd'><b>The base image layers of a single image</b>: image layers are defined by a Dockerfile, not Compose.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-014", domain:4, obj:"4.1", diff:"easy", q:"Which command brings up all services defined in a compose.yaml in the background?", options:["docker compose start --detached","docker run -d compose.yaml","docker compose up -d","docker stack deploy compose.yaml"], answer:2, explain:"<strong>docker compose up -d</strong> creates and starts all services defined in the Compose file in detached (background) mode.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>docker compose start --detached</b>: start only restarts existing stopped services and --detached is not the flag; -d is used with up.</span><span class='qd'><b>docker run -d compose.yaml</b>: docker run launches a single container from an image, not a Compose stack.</span><span class='qd'><b>docker stack deploy compose.yaml</b>: stack deploy targets Swarm and requires a -c/--compose-file flag with a stack name.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-015", domain:4, obj:"4.1", diff:"medium", q:"In Docker Swarm, what is a service?", options:["A single immutable image stored in a registry","A read-only configuration object","The definition of the desired state for a set of replicated container tasks across the swarm","A standalone container that ignores the swarm scheduler"], answer:2, explain:"<strong>A Swarm service</strong> defines the desired state for running tasks (container replicas) across the cluster, and the swarm manager schedules and maintains those tasks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A single immutable image stored in a registry</b>: that describes an image, not a running service.</span><span class='qd'><b>A read-only configuration object</b>: that describes a config or secret, not a service.</span><span class='qd'><b>A standalone container that ignores the swarm scheduler</b>: services are scheduled and managed by the swarm, not standalone.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-016", domain:4, obj:"4.1", diff:"hard", q:"What is the key difference between a declarative and an imperative approach in infrastructure automation?", options:["Declarative is always slower than imperative","Declarative defines the desired end state; imperative specifies the exact steps to reach it","Imperative cannot be stored in version control","Declarative only works with containers"], answer:1, explain:"<strong>Declarative</strong> automation describes the desired end state and lets the tool determine how to achieve it, while <strong>imperative</strong> automation specifies the explicit ordered commands to run.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Declarative is always slower than imperative</b>: speed is implementation-specific and not the defining difference.</span><span class='qd'><b>Imperative cannot be stored in version control</b>: both styles can be versioned as code.</span><span class='qd'><b>Declarative only works with containers</b>: declarative tools manage many resource types, not just containers.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-017", domain:4, obj:"4.1", diff:"medium", q:"Why is idempotency an important property in configuration management tools like Ansible and Puppet?", options:["It guarantees tasks run in random order for resilience","It forces every run to reinstall all packages","Running the same configuration repeatedly produces the same end state without unintended changes","It encrypts the configuration at rest"], answer:2, explain:"<strong>Idempotency</strong> ensures that applying the same desired-state configuration multiple times converges to the same result and only makes changes when the system drifts from that state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It guarantees tasks run in random order for resilience</b>: idempotency concerns repeatable outcomes, not ordering.</span><span class='qd'><b>It forces every run to reinstall all packages</b>: idempotent runs skip changes that are already in the desired state.</span><span class='qd'><b>It encrypts the configuration at rest</b>: encryption is unrelated to idempotency.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-018", domain:4, obj:"4.1", diff:"medium", q:"Which file format do Ansible playbooks use?", options:["JSON","INI","XML","YAML"], answer:3, explain:"<strong>YAML</strong> is the format Ansible playbooks are written in, using indentation-based structure to define plays, tasks, and variables.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>JSON</b>: while Ansible can read some JSON data, playbooks are authored in YAML.</span><span class='qd'><b>INI</b>: INI is used for static inventory files, not playbooks.</span><span class='qd'><b>XML</b>: Ansible does not use XML for playbooks.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-019", domain:4, obj:"4.1", diff:"hard", q:"In Terraform/OpenTofu, what is the purpose of the state file?", options:["To map real-world resources to the configuration and track metadata for planning changes","To store the provider plugin binaries","To hold the user's cloud credentials in plaintext for convenience","To cache downloaded modules"], answer:0, explain:"<strong>The state file</strong> records the mapping between declared resources and the real infrastructure, enabling the tool to compute accurate plans and detect drift.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To store the provider plugin binaries</b>: plugins are stored separately in the .terraform directory.</span><span class='qd'><b>To hold the user's cloud credentials in plaintext for convenience</b>: credentials should be supplied via environment or provider config, not stored as the state's purpose.</span><span class='qd'><b>To cache downloaded modules</b>: module caching is a separate function from state tracking.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-020", domain:4, obj:"4.1", diff:"medium", q:"Which YAML snippet correctly represents a list of two packages?", options:["packages: nginx, git","packages: {nginx, git}","packages:\n  - nginx\n  - git","packages = [nginx git]"], answer:2, explain:"<strong>packages:</strong> followed by indented hyphenated items is the standard YAML block sequence syntax for a list.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>packages: nginx, git</b>: this is a single string, not a parsed YAML list.</span><span class='qd'><b>packages: {nginx, git}</b>: curly braces denote a mapping flow style, not a sequence, and this is malformed.</span><span class='qd'><b>packages = [nginx git]</b>: the equals sign and space-separated values are not valid YAML syntax.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-021", domain:4, obj:"4.1", diff:"medium", q:"What is a container orchestration platform primarily responsible for?", options:["Compiling application source code into binaries","Building a single container image from a Dockerfile","Automating deployment, scaling, networking, and lifecycle management of containers across hosts","Encrypting container filesystems at rest"], answer:2, explain:"<strong>Container orchestration</strong> automates scheduling, scaling, networking, health management, and the lifecycle of containers across a cluster of hosts, as Kubernetes and Swarm do.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Compiling application source code into binaries</b>: compilation is a build step, not orchestration.</span><span class='qd'><b>Building a single container image from a Dockerfile</b>: image building is done by tools like docker build, not the orchestrator.</span><span class='qd'><b>Encrypting container filesystems at rest</b>: storage encryption is a separate concern from orchestration.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-022", domain:4, obj:"4.1", diff:"medium", q:"An administrator wants a freshly booted cloud instance to automatically create a user and inject an SSH key without manual login. Which mechanism is designed for this?", options:["Kickstart post section","A Puppet manifest applied at compile time","A Dockerfile RUN instruction","cloud-init user-data"], answer:3, explain:"<strong>cloud-init user-data</strong> is processed on first boot and can create users, set passwords, and inject SSH keys automatically using a cloud-config document.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Kickstart post section</b>: Kickstart runs during OS installation, not on cloud instance first boot from an image.</span><span class='qd'><b>A Puppet manifest applied at compile time</b>: Puppet requires the agent to run and is not the native first-boot cloud mechanism.</span><span class='qd'><b>A Dockerfile RUN instruction</b>: Dockerfile instructions build images and do not configure a booting VM.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-023", domain:4, obj:"4.2", diff:"easy", q:"Which line is the correct shebang to ensure a script runs with the Bash interpreter?", options:["#!/bin/bash","# /bin/bash","!#/bin/bash","#/bin/bash"], answer:0, explain:"<strong>#!/bin/bash</strong> is the proper shebang: the #! sequence at the very start of the file tells the kernel which interpreter to use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b># /bin/bash</b>: a space after # makes it an ordinary comment, not a shebang.</span><span class='qd'><b>!#/bin/bash</b>: the characters are reversed; it must be #! exactly.</span><span class='qd'><b>#/bin/bash</b>: this is missing the exclamation point and is just a comment.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-024", domain:4, obj:"4.2", diff:"easy", q:"In Bash, how do you correctly assign the value 5 to a variable named count?", options:["count = 5","$count = 5","count=5","set count 5"], answer:2, explain:"<strong>count=5</strong> is the correct Bash assignment; there must be no spaces around the equals sign.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>count = 5</b>: spaces around = make Bash treat count as a command with arguments.</span><span class='qd'><b>$count = 5</b>: the $ is only used when reading a variable, not when assigning it.</span><span class='qd'><b>set count 5</b>: set manipulates shell options and positional parameters, not named variable assignment.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-025", domain:4, obj:"4.2", diff:"medium", q:"What does the special variable $? hold immediately after a command runs?", options:["The exit status (return code) of the most recently executed command","The process ID of the last background command","The number of arguments passed to the script","The name of the script"], answer:0, explain:"<strong>$?</strong> contains the exit status of the last command, where 0 conventionally means success and non-zero indicates an error.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The process ID of the last background command</b>: that value is held by $!, not $?.</span><span class='qd'><b>The number of arguments passed to the script</b>: argument count is in $#.</span><span class='qd'><b>The name of the script</b>: the script name is in $0.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-026", domain:4, obj:"4.2", diff:"medium", q:"In Bash, what is the difference between single quotes and double quotes around a string?", options:["Single quotes allow variable expansion; double quotes do not","Both are identical in behavior","Single quotes allow command substitution but not variable expansion","Double quotes allow variable and command expansion; single quotes treat everything literally"], answer:3, explain:"<strong>Double quotes</strong> permit variable expansion and command substitution while preserving most literal text, whereas <strong>single quotes</strong> preserve every character literally with no expansion.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Single quotes allow variable expansion; double quotes do not</b>: this is reversed; single quotes suppress expansion.</span><span class='qd'><b>Both are identical in behavior</b>: they differ specifically in how expansion is handled.</span><span class='qd'><b>Single quotes allow command substitution but not variable expansion</b>: single quotes disable both expansions entirely.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-027", domain:4, obj:"4.2", diff:"medium", q:"Which construct captures the output of the date command into a variable in modern Bash?", options:["now=(date)","now=`date`","now=$(date)","now=$[date]"], answer:2, explain:"<strong>now=$(date)</strong> uses command substitution to run date and assign its output to now; the $() form is the modern, nestable syntax.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>now=(date)</b>: parentheses without a dollar sign create an array containing the literal word date.</span><span class='qd'><b>now=`date`</b>: backticks work but are legacy, harder to nest, and not the preferred modern form.</span><span class='qd'><b>now=$[date]</b>: $[...] is deprecated arithmetic syntax and does not run commands.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-028", domain:4, obj:"4.2", diff:"medium", q:"In a Bash script, which test correctly checks whether the file /etc/hosts exists and is a regular file?", options:["if [ -d /etc/hosts ]","if [ -f /etc/hosts ]","if [ -x /etc/hosts ]","if [ -e -f /etc/hosts ]"], answer:1, explain:"<strong>if [ -f /etc/hosts ]</strong> uses the -f operator, which is true when the path exists and is a regular file.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>if [ -d /etc/hosts ]</b>: -d tests for a directory, which /etc/hosts is not.</span><span class='qd'><b>if [ -x /etc/hosts ]</b>: -x tests executability, not whether it is a regular file.</span><span class='qd'><b>if [ -e -f /etc/hosts ]</b>: combining -e and -f like this is invalid test syntax.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-029", domain:4, obj:"4.2", diff:"medium", q:"What does the && operator do in the command: mkdir /data && cd /data ?", options:["Runs cd /data only if mkdir /data succeeds","Runs both commands in parallel","Runs cd /data only if mkdir /data fails","Pipes the output of mkdir into cd"], answer:0, explain:"<strong>&&</strong> is a logical AND that runs the second command only if the first command exits with a success status (0).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Runs both commands in parallel</b>: && runs them sequentially, not in parallel.</span><span class='qd'><b>Runs cd /data only if mkdir /data fails</b>: that is the behavior of ||, not &&.</span><span class='qd'><b>Pipes the output of mkdir into cd</b>: piping uses |, and && does not pass data between commands.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-030", domain:4, obj:"4.2", diff:"medium", q:"In the command cmd1 || cmd2, when does cmd2 execute?", options:["Always, regardless of cmd1","Only if cmd1 succeeds","Only if cmd1 returns a non-zero exit status","Never; || is a syntax error"], answer:2, explain:"<strong>||</strong> is logical OR: cmd2 runs only when cmd1 fails (returns a non-zero exit status), which is useful for fallback actions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Always, regardless of cmd1</b>: that would be a semicolon, not ||.</span><span class='qd'><b>Only if cmd1 succeeds</b>: that describes &&, the opposite operator.</span><span class='qd'><b>Never; || is a syntax error</b>: || is valid shell logic, not an error.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-031", domain:4, obj:"4.2", diff:"medium", q:"Which loop construct correctly iterates over the values 1 through 3 in Bash?", options:["foreach i (1 2 3) echo $i","for i in 1 2 3; do echo $i; done","loop i 1 3; echo $i; end","for (i=1; i&lt;=3) echo $i"], answer:1, explain:"<strong>for i in 1 2 3; do echo $i; done</strong> is the standard Bash for loop iterating over a word list.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>foreach i (1 2 3) echo $i</b>: foreach is csh/tcsh syntax, not Bash.</span><span class='qd'><b>loop i 1 3; echo $i; end</b>: loop is not a Bash keyword.</span><span class='qd'><b>for (i=1; i&lt;=3) echo $i</b>: this is malformed; Bash C-style loops use double parentheses and proper increments.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-032", domain:4, obj:"4.2", diff:"hard", q:"What advantage does the [[ ]] keyword have over the [ ] test command in Bash?", options:["[[ ]] supports pattern matching and logical operators like &amp;&amp; without word-splitting pitfalls","[[ ]] is POSIX-portable while [ ] is Bash-only","[[ ]] runs faster by forking a subprocess","[[ ]] automatically converts strings to integers"], answer:0, explain:"<strong>[[ ]]</strong> is a Bash keyword that supports regex/glob pattern matching, the &amp;&amp; and || operators inside it, and avoids the word-splitting and globbing problems of the older [ ] command.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>[[ ]] is POSIX-portable while [ ] is Bash-only</b>: it is the reverse; [ is POSIX and [[ is a Bash extension.</span><span class='qd'><b>[[ ]] runs faster by forking a subprocess</b>: [[ is a builtin keyword and does not fork a subprocess.</span><span class='qd'><b>[[ ]] automatically converts strings to integers</b>: it does not auto-convert types; arithmetic uses (( )).</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-033", domain:4, obj:"4.2", diff:"medium", q:"Inside a Bash function, what does the parameter $1 refer to?", options:["The first positional argument passed to the function","The function's exit code","The total number of arguments","The name of the function"], answer:0, explain:"<strong>$1</strong> refers to the first positional parameter passed to the function (or script), with $2, $3, and so on for subsequent arguments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The function's exit code</b>: the exit code is found in $? after the function returns.</span><span class='qd'><b>The total number of arguments</b>: argument count is in $#.</span><span class='qd'><b>The name of the function</b>: $0 holds the script name, not the function name.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-034", domain:4, obj:"4.2", diff:"medium", q:"Which redirection appends standard output of a command to an existing log file without truncating it?", options:["command &gt; logfile","command &lt; logfile","command 2&gt; logfile","command &gt;&gt; logfile"], answer:3, explain:"<strong>command &gt;&gt; logfile</strong> appends stdout to the file, preserving existing contents.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>command &gt; logfile</b>: a single &gt; truncates and overwrites the file.</span><span class='qd'><b>command &lt; logfile</b>: &lt; redirects input from the file, not output to it.</span><span class='qd'><b>command 2&gt; logfile</b>: this redirects only standard error and overwrites it.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-035", domain:4, obj:"4.2", diff:"medium", q:"How do you redirect both standard output and standard error to the same file in Bash?", options:["command 1&gt;&amp;2 file","command &gt; file 2&gt;&amp;1","command &gt; file 2&gt; file","command &gt;&gt; file &amp;"], answer:1, explain:"<strong>command &gt; file 2&gt;&amp;1</strong> first points stdout to the file, then directs stderr to wherever stdout currently goes, merging both into the same file.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>command 1&gt;&amp;2 file</b>: this sends stdout to stderr and is malformed for writing to a file.</span><span class='qd'><b>command &gt; file 2&gt; file</b>: opening the same file twice independently can cause the streams to overwrite each other.</span><span class='qd'><b>command &gt;&gt; file &amp;</b>: the trailing &amp; backgrounds the command and does not redirect stderr.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-036", domain:4, obj:"4.2", diff:"medium", q:"What does the exit status convention 0 mean in a shell script?", options:["A fatal error occurred","The script is still running","The command completed successfully","The command was interrupted by a signal"], answer:2, explain:"<strong>Exit status 0</strong> conventionally signals success, while any non-zero value indicates some kind of failure or error condition.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A fatal error occurred</b>: errors are represented by non-zero exit codes.</span><span class='qd'><b>The script is still running</b>: an exit status is only available after the command finishes.</span><span class='qd'><b>The command was interrupted by a signal</b>: signal terminations yield exit codes of 128 plus the signal number, not 0.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-037", domain:4, obj:"4.2", diff:"hard", q:"Which Bash parameter expansion provides the value of VAR, or the string 'default' if VAR is unset or empty?", options:["${VAR-default}","${VAR:-default}","${VAR:=default}","${VAR:?default}"], answer:1, explain:"<strong>${VAR:-default}</strong> returns the value of VAR if it is set and non-empty, otherwise it returns 'default' without assigning it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>${VAR-default}</b>: without the colon, it substitutes the default only when VAR is unset, not when it is set but empty.</span><span class='qd'><b>${VAR:=default}</b>: this also assigns the default to VAR as a side effect, which was not requested.</span><span class='qd'><b>${VAR:?default}</b>: this prints an error and exits if VAR is unset, rather than substituting a fallback.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-038", domain:4, obj:"4.2", diff:"medium", q:"Which command makes a script named deploy.sh executable for its owner?", options:["chmod +x deploy.sh","chown +x deploy.sh","setexec deploy.sh","chmod 000 deploy.sh"], answer:0, explain:"<strong>chmod +x deploy.sh</strong> adds the execute permission so the script can be run directly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chown +x deploy.sh</b>: chown changes ownership, not permissions, and +x is not valid for it.</span><span class='qd'><b>setexec deploy.sh</b>: setexec is not a real command.</span><span class='qd'><b>chmod 000 deploy.sh</b>: 000 removes all permissions, making the file inaccessible.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-039", domain:4, obj:"4.2", diff:"medium", q:"In a case statement, what character sequence terminates each pattern block in Bash?", options:["break","return","two semicolons (;;)","end"], answer:2, explain:"<strong>Two semicolons (;;)</strong> end each pattern branch of a Bash case statement before the next pattern or esac.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>break</b>: break exits loops, not case branches.</span><span class='qd'><b>return</b>: return exits a function, not a case branch.</span><span class='qd'><b>end</b>: case statements close with esac, and branches end with ;;, not end.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-040", domain:4, obj:"4.2", diff:"hard", q:"Which arithmetic construct correctly increments the variable i by 1 in Bash?", options:["i = i + 1","i++ alone on a line","add i 1","let i=i+1"], answer:3, explain:"<strong>let i=i+1</strong> performs arithmetic evaluation and increments i; equivalently (( i++ )) or i=$((i+1)) would work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>i = i + 1</b>: spaces and bare = treat this as a command, not arithmetic, and it fails.</span><span class='qd'><b>i++ alone on a line</b>: i++ by itself is not evaluated as arithmetic outside (( )) and is treated as a command.</span><span class='qd'><b>add i 1</b>: add is not a shell arithmetic command.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-041", domain:4, obj:"4.2", diff:"medium", q:"What does the read command do in a Bash script?", options:["Reads a line of input into one or more variables","Reads a file and prints it to stdout","Reads the exit status of the last command","Reads environment variables into a file"], answer:0, explain:"<strong>read</strong> reads a line from standard input (or a here-string) and splits it into the supplied variable names.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reads a file and prints it to stdout</b>: that is the job of cat, not read.</span><span class='qd'><b>Reads the exit status of the last command</b>: the exit status is accessed via $?.</span><span class='qd'><b>Reads environment variables into a file</b>: env or printenv lists variables; read does not export to a file.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-042", domain:4, obj:"4.2", diff:"medium", q:"Which extended regular expression matches a line consisting only of one or more digits?", options:["^\\d*","^[0-9]+$","[a-z]+","^.*$"], answer:1, explain:"<strong>^[0-9]+$</strong> anchors the match to the whole line and requires one or more digit characters and nothing else.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>^\\d*</b>: \\d is not standard in POSIX ERE (grep -E) and * allows zero digits, also it lacks an end anchor.</span><span class='qd'><b>[a-z]+</b>: this matches lowercase letters, not digits.</span><span class='qd'><b>^.*$</b>: this matches any line, including empty and non-digit lines.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-043", domain:4, obj:"4.2", diff:"medium", q:"In the expression grep -E 'colou?r' file.txt, what does the ? quantifier mean?", options:["The preceding character u is optional (zero or one occurrence)","Any single character may appear there","The u must appear one or more times","It marks the end of the pattern"], answer:0, explain:"<strong>The ?</strong> quantifier makes the preceding element optional, matching zero or one occurrence, so it matches both 'color' and 'colour'.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Any single character may appear there</b>: that is the role of the dot (.), not ?.</span><span class='qd'><b>The u must appear one or more times</b>: that is the + quantifier, not ?.</span><span class='qd'><b>It marks the end of the pattern</b>: end of line is anchored with $, not ?.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-044", domain:4, obj:"4.2", diff:"medium", q:"Which globbing pattern matches all files ending in .conf in the current directory?", options:["?.conf","[conf]","%.conf","*.conf"], answer:3, explain:"<strong>*.conf</strong> uses the asterisk wildcard, which matches any sequence of characters followed by the literal .conf suffix.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>?.conf</b>: ? matches exactly one character, so it only matches single-character names plus .conf.</span><span class='qd'><b>[conf]</b>: brackets match a single character from the set c, o, n, or f.</span><span class='qd'><b>%.conf</b>: % is not a shell globbing wildcard.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-045", domain:4, obj:"4.2", diff:"hard", q:"What is the effect of placing set -e near the top of a Bash script?", options:["It causes the script to exit immediately if any command returns a non-zero status","It enables verbose tracing of every command","It treats unset variables as errors","It disables filename globbing"], answer:0, explain:"<strong>set -e</strong> makes the script terminate as soon as a command fails (returns non-zero), helping prevent cascading errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It enables verbose tracing of every command</b>: command tracing is enabled by set -x.</span><span class='qd'><b>It treats unset variables as errors</b>: that behavior comes from set -u.</span><span class='qd'><b>It disables filename globbing</b>: globbing is disabled with set -f (noglob).</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-046", domain:4, obj:"4.2", diff:"medium", q:"Which syntax pipes the output of ps into grep to find sshd processes?", options:["ps aux &gt; grep sshd","ps aux | grep sshd","ps aux &amp;&amp; grep sshd","ps aux 2&gt; grep sshd"], answer:1, explain:"<strong>ps aux | grep sshd</strong> uses a pipe to send the standard output of ps as the standard input of grep.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ps aux &gt; grep sshd</b>: &gt; redirects output to a file literally named grep, it does not run grep.</span><span class='qd'><b>ps aux &amp;&amp; grep sshd</b>: && runs grep separately on stdin/files, not on ps output.</span><span class='qd'><b>ps aux 2&gt; grep sshd</b>: this redirects stderr to a file named grep, not a pipe.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-047", domain:4, obj:"4.2", diff:"medium", q:"What does the loop in: while read line; do echo $line; done &lt; file.txt accomplish?", options:["Loops forever printing the file name","Counts the words in file.txt","Reads only the first line of file.txt","Reads file.txt one line at a time, echoing each until end of file"], answer:3, explain:"<strong>while read line</strong> with input redirected from file.txt reads the file line by line, executing the loop body for each line until read fails at end of file.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Loops forever printing the file name</b>: read returns non-zero at EOF, ending the loop, and it prints content not the name.</span><span class='qd'><b>Counts the words in file.txt</b>: counting words would require wc, not this loop.</span><span class='qd'><b>Reads only the first line of file.txt</b>: the loop continues until all lines are read, not just the first.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-048", domain:4, obj:"4.5", diff:"medium", q:"An AI assistant produces a Bash one-liner that uses a command flag a sysadmin does not recognize. What is the best way to confirm it is safe before running it?", options:["Trust the AI and run it on production immediately","Consult the official man page or documentation for that command and flag to understand its real effect","Search social media for opinions about the command","Run it with sudo so any errors are suppressed"], answer:1, explain:"<strong>Consulting the man page or official documentation</strong> lets the administrator verify what an unfamiliar AI-suggested flag actually does before trusting it in a real environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Trust the AI and run it on production immediately</b>: AI output can be wrong, and production is the worst place to test it.</span><span class='qd'><b>Search social media for opinions about the command</b>: unverified opinions are less authoritative than the official documentation.</span><span class='qd'><b>Run it with sudo so any errors are suppressed</b>: sudo elevates privileges and does not suppress or validate errors, increasing risk.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-049", domain:4, obj:"4.5", diff:"medium", q:"Why should AI-generated code be run through the same code review and testing process as human-written code?", options:["Because AI code is always slower and needs optimization","Because AI can introduce subtle bugs, insecure patterns, or incorrect logic that review and testing are designed to catch","Because reviewers must rewrite all AI code by hand","Because AI code cannot be stored in version control otherwise"], answer:1, explain:"<strong>AI-generated code</strong> can contain subtle defects, security weaknesses, or wrong assumptions, so subjecting it to normal review and testing safeguards quality just as with human-authored code.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because AI code is always slower and needs optimization</b>: performance is not the reason review is required, and AI code is not inherently slower.</span><span class='qd'><b>Because reviewers must rewrite all AI code by hand</b>: review verifies correctness; it does not mandate full rewrites.</span><span class='qd'><b>Because AI code cannot be stored in version control otherwise</b>: AI code can be committed normally regardless of review.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-050", domain:4, obj:"4.5", diff:"hard", q:"An organization must comply with strict data-residency regulations. Which approach to AI-assisted coding best respects those data governance requirements?", options:["Send all source code to any free public AI service for convenience","Email snippets to a personal account to use a consumer chatbot","Disable the firewall so the AI service can reach internal systems","Use an approved AI tool that processes data within the required jurisdiction or on-premises"], answer:3, explain:"<strong>Using an approved tool that keeps data within the required jurisdiction or on-premises</strong> satisfies data-residency rules while still allowing AI assistance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Send all source code to any free public AI service for convenience</b>: this can move regulated data outside the permitted jurisdiction.</span><span class='qd'><b>Email snippets to a personal account to use a consumer chatbot</b>: this bypasses controls and leaks data to unmanaged services.</span><span class='qd'><b>Disable the firewall so the AI service can reach internal systems</b>: weakening security controls creates serious exposure and does not address residency.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-051", domain:4, obj:"4.5", diff:"medium", q:"After an AI assistant generates a Python script, the administrator runs it in a disposable test virtual machine first. What is the main benefit of this practice?", options:["It makes the script run faster in production","It guarantees the AI will not make mistakes","It limits the blast radius so any harmful or incorrect behavior is contained before production use","It automatically rewrites the script to be secure"], answer:2, explain:"<strong>Running AI-generated code in an isolated test VM</strong> contains any destructive or incorrect behavior, letting the administrator observe and verify results without risking the production environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It makes the script run faster in production</b>: testing in a VM does not affect production performance.</span><span class='qd'><b>It guarantees the AI will not make mistakes</b>: testing reveals mistakes but cannot guarantee the AI made none.</span><span class='qd'><b>It automatically rewrites the script to be secure</b>: a test VM observes behavior; it does not modify the code.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-052", domain:4, obj:"4.5", diff:"medium", q:"An AI tool confidently generates a firewall rule but cites a command option that does not exist. What does this illustrate about using AI for system administration?", options:["AI can hallucinate plausible but incorrect details, so its output must be verified","AI tools are incapable of generating firewall rules","Nonexistent options always work anyway","Verification is only needed for networking tasks"], answer:0, explain:"<strong>AI can hallucinate</strong> convincing but false details such as nonexistent flags, which is why every AI-generated command should be checked against authoritative documentation before use.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI tools are incapable of generating firewall rules</b>: AI can generate such rules; the issue is accuracy, not capability.</span><span class='qd'><b>Nonexistent options always work anyway</b>: a nonexistent option will simply fail or behave unexpectedly.</span><span class='qd'><b>Verification is only needed for networking tasks</b>: verification is needed for all AI-generated administration output, not just networking.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-053", domain:4, obj:"4.5", diff:"medium", q:"Which of the following is the strongest reason to prefer an on-premises (locally hosted) AI model for handling regulated healthcare data during script generation?", options:["It eliminates the need to review the generated code","It is guaranteed to be cheaper than any cloud option","It keeps protected health information inside the controlled environment, supporting privacy compliance","It makes the generated scripts run without a Python interpreter"], answer:2, explain:"<strong>A locally hosted model</strong> ensures protected health information never leaves the organization's controlled environment, which supports privacy and regulatory compliance for sensitive data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It eliminates the need to review the generated code</b>: code review is still required regardless of where the model runs.</span><span class='qd'><b>It is guaranteed to be cheaper than any cloud option</b>: cost varies and is not the privacy benefit in question.</span><span class='qd'><b>It makes the generated scripts run without a Python interpreter</b>: scripts still require their normal runtime to execute.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-054", domain:4, obj:"4.2", diff:"medium", q:"Which command tests whether the string in $name is non-empty in a Bash conditional?", options:["[ -n '$name' ]","[ -z '$name' ]","[ -e '$name' ]","[ -s '$name' ]"], answer:0, explain:"<strong>[ -n '$name' ]</strong> uses the -n operator, which is true when the quoted string has non-zero length, correctly testing for non-emptiness (in practice double quotes are used so the value still expands).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>[ -z '$name' ]</b>: -z is true when the string is empty, the opposite test.</span><span class='qd'><b>[ -e '$name' ]</b>: -e tests whether a path exists as a file, not string content.</span><span class='qd'><b>[ -s '$name' ]</b>: -s tests whether a file exists and is non-empty, not a string variable.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-055", domain:4, obj:"4.5", diff:"hard", q:"A team adopts an AI coding assistant. Which combination of practices best balances productivity with security and governance?", options:["Allow unrestricted data sharing and skip code review to move faster","Ban AI entirely and forbid any automation","Verify AI output, restrict sensitive data to approved or local models, and keep AI usage within policy and review","Use AI only for documentation and never for any code"], answer:2, explain:"<strong>Verifying output, restricting sensitive data to approved or local models, and keeping usage within policy and review</strong> captures the productivity benefits of AI while managing security and governance risks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allow unrestricted data sharing and skip code review to move faster</b>: this abandons the controls that prevent data leakage and defects.</span><span class='qd'><b>Ban AI entirely and forbid any automation</b>: a total ban forfeits real productivity gains rather than managing risk.</span><span class='qd'><b>Use AI only for documentation and never for any code</b>: this is overly restrictive and ignores that code can be used safely with verification.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-056", domain:4, obj:"4.3", diff:"easy", q:"Which command runs a Python 3 script named app.py?", options:["run app.py","python3 app.py","exec app","py.run app.py"], answer:1, explain:"<strong>python3 app.py</strong> invokes the Python 3 interpreter to execute the script app.py.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>run app.py</b>: run is not a standard interpreter command.</span><span class='qd'><b>exec app</b>: exec replaces the shell process and would not interpret a .py file by itself.</span><span class='qd'><b>py.run app.py</b>: py.run is not a valid command on Linux.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-057", domain:4, obj:"4.3", diff:"medium", q:"What is the purpose of a Python virtual environment created with python3 -m venv myenv ?", options:["To compile Python into a standalone binary","To create an isolated directory with its own Python interpreter and packages","To encrypt Python source files","To run Python scripts as a system service"], answer:1, explain:"<strong>A venv</strong> creates an isolated environment with its own interpreter symlink and site-packages so project dependencies do not conflict with the system or other projects.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To compile Python into a standalone binary</b>: venv does not compile binaries; tools like PyInstaller do that.</span><span class='qd'><b>To encrypt Python source files</b>: venv provides isolation, not encryption.</span><span class='qd'><b>To run Python scripts as a system service</b>: services are managed by systemd, not venv.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-058", domain:4, obj:"4.3", diff:"easy", q:"Which command installs the requests package into the currently active Python environment using pip?", options:["pip install requests","pip get requests","pip add requests","python requests install"], answer:0, explain:"<strong>pip install requests</strong> downloads and installs the requests package from PyPI into the active environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>pip get requests</b>: get is not a pip subcommand.</span><span class='qd'><b>pip add requests</b>: add is not a pip subcommand (that is npm/poetry style).</span><span class='qd'><b>python requests install</b>: this is not valid syntax for installing packages.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-059", domain:4, obj:"4.3", diff:"medium", q:"After creating a venv at ./venv, which command activates it in Bash?", options:["venv start","source venv/bin/activate","activate venv","python venv activate"], answer:1, explain:"<strong>source venv/bin/activate</strong> sources the activation script, adjusting PATH so the venv's interpreter and pip are used in the current shell.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>venv start</b>: venv has no start subcommand.</span><span class='qd'><b>activate venv</b>: activate must be sourced from inside the venv's bin directory.</span><span class='qd'><b>python venv activate</b>: this is not how virtual environments are activated.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-060", domain:4, obj:"4.3", diff:"medium", q:"Which file is conventionally used to list a Python project's dependencies for pip to install?", options:["packages.txt","deps.cfg","modules.list","requirements.txt"], answer:3, explain:"<strong>requirements.txt</strong> is the conventional file listing package names and versions, installable with pip install -r requirements.txt.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>packages.txt</b>: this is not the recognized pip convention.</span><span class='qd'><b>deps.cfg</b>: dependencies are not declared in a deps.cfg by pip convention.</span><span class='qd'><b>modules.list</b>: pip does not read a modules.list file.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-061", domain:4, obj:"4.3", diff:"medium", q:"Why is indentation significant in Python, unlike in Bash?", options:["Indentation is only cosmetic in Python","Python uses indentation to define code blocks instead of braces or keywords","Python requires tabs and forbids spaces","Indentation determines variable scope by line number"], answer:1, explain:"<strong>Python</strong> uses consistent indentation to delimit blocks (such as loops, functions, and conditionals), so incorrect indentation changes program structure or causes errors.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Indentation is only cosmetic in Python</b>: it is syntactically required, not cosmetic.</span><span class='qd'><b>Python requires tabs and forbids spaces</b>: spaces (typically four) are recommended; mixing tabs and spaces is the problem, not spaces themselves.</span><span class='qd'><b>Indentation determines variable scope by line number</b>: scope is determined by function and module boundaries, not raw line numbers.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-062", domain:4, obj:"4.3", diff:"medium", q:"Which Python data type is an ordered, mutable sequence?", options:["tuple","frozenset","list","str"], answer:2, explain:"<strong>A list</strong> is an ordered, mutable collection that allows elements to be added, removed, or changed in place.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tuple</b>: tuples are ordered but immutable.</span><span class='qd'><b>frozenset</b>: a frozenset is unordered and immutable.</span><span class='qd'><b>str</b>: strings are ordered but immutable; you cannot change a character in place.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-063", domain:4, obj:"4.3", diff:"medium", q:"Which Python data structure stores key-value pairs?", options:["list","dict","tuple","set"], answer:1, explain:"<strong>A dict (dictionary)</strong> maps unique keys to values, allowing fast lookup by key.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>list</b>: a list stores ordered values indexed by integer position, not keys.</span><span class='qd'><b>tuple</b>: a tuple is an immutable ordered sequence, not a key-value map.</span><span class='qd'><b>set</b>: a set stores unique unordered values with no associated keys.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-064", domain:4, obj:"4.3", diff:"medium", q:"In Python, how do you access the value associated with the key 'host' in a dictionary named config?", options:["config-&gt;host","config.host()","config(host)","config['host']"], answer:3, explain:"<strong>config['host']</strong> uses subscript notation with the key to retrieve its associated value from the dictionary.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>config-&gt;host</b>: the arrow operator is not valid Python syntax.</span><span class='qd'><b>config.host()</b>: dot-call syntax accesses methods or attributes, not dictionary keys.</span><span class='qd'><b>config(host)</b>: calling config like a function is not how dictionary lookup works.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-065", domain:4, obj:"4.3", diff:"easy", q:"Which symbol begins a single-line comment in Python?", options:["//","#","--","/*"], answer:1, explain:"<strong>The # symbol</strong> starts a comment in Python; everything after it on that line is ignored by the interpreter.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>//</b>: // is integer division in Python, not a comment marker.</span><span class='qd'><b>--</b>: -- is not a comment syntax in Python.</span><span class='qd'><b>/*</b>: /* begins block comments in C-like languages, not Python.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-066", domain:4, obj:"4.3", diff:"medium", q:"Which Python type would a function return if it is meant to represent a true/false condition?", options:["str","float","bool","bytes"], answer:2, explain:"<strong>bool</strong> is the Boolean type whose only values are True and False, ideal for representing conditions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>str</b>: a string holds text, not a logical truth value directly.</span><span class='qd'><b>float</b>: float represents real numbers, not conditions.</span><span class='qd'><b>bytes</b>: bytes holds raw binary data, not a boolean condition.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-067", domain:4, obj:"4.3", diff:"medium", q:"What does the python3 -m pip freeze command output?", options:["A list of installed packages with their exact versions","The Python interpreter version only","The contents of the standard library","A frozen binary of the script"], answer:0, explain:"<strong>pip freeze</strong> lists the installed packages and their pinned versions in requirements format, useful for reproducing an environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The Python interpreter version only</b>: the interpreter version comes from python3 --version.</span><span class='qd'><b>The contents of the standard library</b>: freeze lists installed third-party and local packages, not the stdlib modules.</span><span class='qd'><b>A frozen binary of the script</b>: freeze does not produce binaries.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-068", domain:4, obj:"4.3", diff:"hard", q:"Why are virtual environments preferred over installing packages system-wide with sudo pip install?", options:["They run scripts faster","They automatically update the OS package manager","They isolate project dependencies, avoiding version conflicts and protecting the system Python","They encrypt installed packages"], answer:2, explain:"<strong>Virtual environments</strong> keep each project's dependencies separate, preventing version conflicts between projects and avoiding changes to the distribution's system Python that could break OS tooling.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>They run scripts faster</b>: venvs do not improve execution speed.</span><span class='qd'><b>They automatically update the OS package manager</b>: venvs are unrelated to apt/dnf updates.</span><span class='qd'><b>They encrypt installed packages</b>: isolation is not encryption.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-069", domain:4, obj:"4.3", diff:"medium", q:"In Python, which statement correctly defines a function named greet that takes one parameter?", options:["function greet(name):","func greet(name) {","define greet(name):","def greet(name):"], answer:3, explain:"<strong>def greet(name):</strong> is the correct Python syntax to define a function, using the def keyword followed by the name, parameter list, and a colon.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>function greet(name):</b>: function is JavaScript syntax, not Python.</span><span class='qd'><b>func greet(name) {</b>: func with braces is Go-style, not Python.</span><span class='qd'><b>define greet(name):</b>: Python uses def, not define.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-070", domain:4, obj:"4.3", diff:"medium", q:"What does the Python expression len([1, 2, 3]) return?", options:["The number of elements (3)","The sum of the elements","The last element","A boolean indicating non-empty"], answer:0, explain:"<strong>len()</strong> returns the number of items in a container, so len([1, 2, 3]) returns 3.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The sum of the elements</b>: summing is done by sum(), not len().</span><span class='qd'><b>The last element</b>: the last element is accessed with index [-1].</span><span class='qd'><b>A boolean indicating non-empty</b>: len returns an integer count, not a boolean.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-071", domain:4, obj:"4.3", diff:"hard", q:"Which statement about pip and PyPI is accurate?", options:["pip can only install packages bundled with the OS","pip installs packages from the Python Package Index (PyPI) by default","PyPI is a local cache directory created by venv","pip compiles C extensions but cannot install pure-Python packages"], answer:1, explain:"<strong>pip</strong> resolves and installs packages from the Python Package Index (PyPI) by default, downloading distributions and their dependencies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>pip can only install packages bundled with the OS</b>: pip fetches from PyPI and other indexes, not just OS-bundled packages.</span><span class='qd'><b>PyPI is a local cache directory created by venv</b>: PyPI is a public online repository, not a local directory.</span><span class='qd'><b>pip compiles C extensions but cannot install pure-Python packages</b>: pip installs both pure-Python and compiled packages.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-072", domain:4, obj:"4.3", diff:"medium", q:"What is the result of the Python expression type(3.14) ?", options:["&lt;class 'int'&gt;","&lt;class 'float'&gt;","&lt;class 'str'&gt;","&lt;class 'decimal'&gt;"], answer:1, explain:"<strong>3.14</strong> is a floating-point literal, so type(3.14) returns &lt;class 'float'&gt;.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>&lt;class 'int'&gt;</b>: int is for whole numbers without a decimal point.</span><span class='qd'><b>&lt;class 'str'&gt;</b>: str is for text in quotes, not a numeric literal.</span><span class='qd'><b>&lt;class 'decimal'&gt;</b>: Decimal requires explicit use of the decimal module, not a plain literal.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-073", domain:4, obj:"4.3", diff:"medium", q:"Which Python construct iterates over each item in a list named hosts?", options:["for host in hosts:","foreach host in hosts:","loop host of hosts:","while host in hosts:"], answer:0, explain:"<strong>for host in hosts:</strong> is Python's syntax to iterate over each element of an iterable such as a list.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>foreach host in hosts:</b>: foreach is not a Python keyword.</span><span class='qd'><b>loop host of hosts:</b>: loop and of are not valid Python iteration keywords.</span><span class='qd'><b>while host in hosts:</b>: this is a conditional membership test, not iteration over each element.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-074", domain:4, obj:"4.4", diff:"easy", q:"Which command initializes a new, empty Git repository in the current directory?", options:["git start","git init","git create","git new"], answer:1, explain:"<strong>git init</strong> creates a new .git directory, turning the current folder into a Git repository.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git start</b>: start is not a Git subcommand.</span><span class='qd'><b>git create</b>: create is not a Git subcommand.</span><span class='qd'><b>git new</b>: new is not a Git subcommand.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-075", domain:4, obj:"4.4", diff:"easy", q:"Which command makes a local copy of a remote repository at a given URL?", options:["git copy &lt;url&gt;","git clone &lt;url&gt;","git pull &lt;url&gt;","git fetch &lt;url&gt;"], answer:1, explain:"<strong>git clone &lt;url&gt;</strong> downloads the entire repository, including history, and sets up the remote tracking.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git copy &lt;url&gt;</b>: copy is not a Git subcommand.</span><span class='qd'><b>git pull &lt;url&gt;</b>: pull updates an existing repository; it does not create the initial clone.</span><span class='qd'><b>git fetch &lt;url&gt;</b>: fetch retrieves objects but does not set up a working copy from scratch like clone.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-076", domain:4, obj:"4.4", diff:"medium", q:"What does git add file.txt do?", options:["Commits file.txt to history","Pushes file.txt to the remote","Stages file.txt's changes for the next commit","Deletes file.txt from the repository"], answer:2, explain:"<strong>git add</strong> stages the specified file's changes into the index so they will be included in the next commit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Commits file.txt to history</b>: committing requires git commit; add only stages.</span><span class='qd'><b>Pushes file.txt to the remote</b>: pushing is done with git push after committing.</span><span class='qd'><b>Deletes file.txt from the repository</b>: removal uses git rm, not git add.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-077", domain:4, obj:"4.4", diff:"medium", q:"Which command records staged changes into the repository history with a message?", options:["git save -m 'message'","git push -m 'message'","git stage -m 'message'","git commit -m 'message'"], answer:3, explain:"<strong>git commit -m 'message'</strong> creates a new commit from the staged changes, attaching the provided message.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git save -m 'message'</b>: save is not a standard Git command for committing.</span><span class='qd'><b>git push -m 'message'</b>: push uploads commits and does not take a -m message.</span><span class='qd'><b>git stage -m 'message'</b>: stage adds files to the index but does not record a commit.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-078", domain:4, obj:"4.4", diff:"medium", q:"What does git push do after you commit locally?", options:["Uploads your local commits to the remote repository","Downloads new commits from the remote","Creates a new branch","Reverts the last commit"], answer:0, explain:"<strong>git push</strong> uploads commits from your local branch to the corresponding branch on the remote repository.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Downloads new commits from the remote</b>: downloading is done by git fetch or git pull.</span><span class='qd'><b>Creates a new branch</b>: branches are created with git branch or git checkout -b.</span><span class='qd'><b>Reverts the last commit</b>: reverting uses git revert or git reset, not push.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-079", domain:4, obj:"4.4", diff:"medium", q:"What is the difference between git fetch and git pull?", options:["git fetch downloads remote changes without merging; git pull fetches and then merges them","git pull only downloads; git fetch merges","They are identical","git fetch uploads commits; git pull downloads them"], answer:0, explain:"<strong>git fetch</strong> retrieves remote objects and updates remote-tracking branches without changing your working branch, while <strong>git pull</strong> performs a fetch and then merges (or rebases) into the current branch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git pull only downloads; git fetch merges</b>: this reverses the actual behavior.</span><span class='qd'><b>They are identical</b>: pull adds a merge/rebase step that fetch does not perform.</span><span class='qd'><b>git fetch uploads commits; git pull downloads them</b>: neither uploads; uploading is push.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-080", domain:4, obj:"4.4", diff:"medium", q:"Which command creates a new branch named feature without switching to it?", options:["git branch feature","git checkout feature","git switch feature","git merge feature"], answer:0, explain:"<strong>git branch feature</strong> creates the new branch pointer at the current commit but leaves you on your present branch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git checkout feature</b>: this attempts to switch to feature and fails if it does not already exist (without -b).</span><span class='qd'><b>git switch feature</b>: switch moves to an existing branch; it does not create one without -c.</span><span class='qd'><b>git merge feature</b>: merge integrates a branch's changes; it does not create a branch.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-081", domain:4, obj:"4.4", diff:"medium", q:"Which command switches your working tree to an existing branch named develop in modern Git?", options:["git branch develop","git push develop","git switch develop","git tag develop"], answer:2, explain:"<strong>git switch develop</strong> changes the current working tree to the existing develop branch (git checkout develop also works).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git branch develop</b>: this creates the branch but does not switch to it.</span><span class='qd'><b>git push develop</b>: push uploads commits and does not change the working branch.</span><span class='qd'><b>git tag develop</b>: tag creates a label on a commit, not a branch switch.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-082", domain:4, obj:"4.4", diff:"medium", q:"What does git merge feature do when run while on the main branch?", options:["Deletes the feature branch","Renames main to feature","Uploads main to the remote","Integrates the changes from feature into main"], answer:3, explain:"<strong>git merge feature</strong> combines the commits from the feature branch into the current branch (main), creating a merge commit if needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Deletes the feature branch</b>: merging does not delete the source branch; you delete it separately.</span><span class='qd'><b>Renames main to feature</b>: branch renaming uses git branch -m, not merge.</span><span class='qd'><b>Uploads main to the remote</b>: uploading requires git push.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-083", domain:4, obj:"4.4", diff:"medium", q:"What is the purpose of a .gitignore file?", options:["It lists files Git should encrypt","It specifies intentionally untracked files that Git should ignore","It stores commit messages","It defines remote repository URLs"], answer:1, explain:"<strong>.gitignore</strong> lists path patterns for files and directories that Git should not track, such as build artifacts, logs, and secrets.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It lists files Git should encrypt</b>: Git does not encrypt files based on .gitignore.</span><span class='qd'><b>It stores commit messages</b>: commit messages are entered at commit time, not in .gitignore.</span><span class='qd'><b>It defines remote repository URLs</b>: remotes are configured with git remote, stored in .git/config.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-084", domain:4, obj:"4.4", diff:"medium", q:"Which command creates an annotated tag named v1.0 on the current commit?", options:["git tag -a v1.0 -m 'release 1.0'","git tag v1.0","git branch v1.0","git commit --tag v1.0"], answer:0, explain:"<strong>git tag -a v1.0 -m 'release 1.0'</strong> creates an annotated tag that stores the tagger, date, and message, suitable for marking releases.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git tag v1.0</b>: this creates a lightweight tag without annotation metadata.</span><span class='qd'><b>git branch v1.0</b>: this creates a branch, not a tag.</span><span class='qd'><b>git commit --tag v1.0</b>: commit has no --tag option for creating tags.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-085", domain:4, obj:"4.4", diff:"medium", q:"Which command shows the current status of the working directory and staging area?", options:["git log","git diff --stat","git show","git status"], answer:3, explain:"<strong>git status</strong> reports which files are staged, modified, or untracked, and the current branch state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git log</b>: log shows commit history, not the current working/staging state.</span><span class='qd'><b>git diff --stat</b>: this summarizes changes between commits or the index, not the overall status.</span><span class='qd'><b>git show</b>: show displays details of a specific commit or object.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-086", domain:4, obj:"4.4", diff:"hard", q:"During a git merge, what does a merge conflict indicate?", options:["The remote repository is unreachable","Git could not automatically reconcile changes to the same lines and requires manual resolution","The branch being merged does not exist","Your working tree is clean"], answer:1, explain:"<strong>A merge conflict</strong> occurs when both branches modified the same region of a file differently, so Git pauses and marks the file for you to resolve manually.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The remote repository is unreachable</b>: network problems produce connection errors, not merge conflicts.</span><span class='qd'><b>The branch being merged does not exist</b>: a missing branch causes a different error before merging.</span><span class='qd'><b>Your working tree is clean</b>: a clean tree has no conflicts; conflicts leave conflict markers in files.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-087", domain:4, obj:"4.4", diff:"medium", q:"Which command displays the commit history of the repository?", options:["git history","git commits","git log","git show-all"], answer:2, explain:"<strong>git log</strong> lists commits in reverse chronological order, showing author, date, hash, and message.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git history</b>: history is not a Git subcommand.</span><span class='qd'><b>git commits</b>: commits is not a Git subcommand.</span><span class='qd'><b>git show-all</b>: show-all is not a valid Git command.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-088", domain:4, obj:"4.4", diff:"medium", q:"Which command adds a remote named origin pointing to a repository URL?", options:["git origin add &lt;url&gt;","git remote add origin &lt;url&gt;","git add remote origin &lt;url&gt;","git push origin &lt;url&gt;"], answer:1, explain:"<strong>git remote add origin &lt;url&gt;</strong> registers a new remote named origin that future push and fetch operations can reference.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git origin add &lt;url&gt;</b>: the subcommand order is wrong; it must be git remote add.</span><span class='qd'><b>git add remote origin &lt;url&gt;</b>: git add stages files; it does not manage remotes.</span><span class='qd'><b>git push origin &lt;url&gt;</b>: push uploads commits and does not create a remote.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-089", domain:4, obj:"4.4", diff:"hard", q:"What does git reset --hard HEAD~1 do?", options:["Creates a new branch one commit back","Discards the most recent commit and resets the working tree to the previous commit, losing uncommitted changes","Pushes the previous commit to the remote","Merges the last commit into HEAD"], answer:1, explain:"<strong>git reset --hard HEAD~1</strong> moves the branch pointer back one commit and forcibly resets the index and working tree to match, discarding the last commit and any uncommitted work.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Creates a new branch one commit back</b>: reset moves the current branch pointer; it does not create a branch.</span><span class='qd'><b>Pushes the previous commit to the remote</b>: reset is a local operation and does not push.</span><span class='qd'><b>Merges the last commit into HEAD</b>: reset rewinds history rather than merging.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-090", domain:4, obj:"4.4", diff:"medium", q:"Which command lists all local branches and marks the current one?", options:["git branch","git switch","git log --branches","git remote -v"], answer:0, explain:"<strong>git branch</strong> with no arguments lists local branches and highlights the active branch with an asterisk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git switch</b>: switch changes branches and is not used to list them.</span><span class='qd'><b>git log --branches</b>: this shows commit history across branches, not a clean branch list.</span><span class='qd'><b>git remote -v</b>: this lists configured remotes, not local branches.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-091", domain:4, obj:"4.4", diff:"medium", q:"After editing files, which two-step sequence correctly records the changes in Git?", options:["git commit then git add","git push then git add","git clone then git commit","git add then git commit"], answer:3, explain:"<strong>git add then git commit</strong> stages the modified files into the index and then records them as a commit in history.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>git commit then git add</b>: the order is reversed; nothing is staged for the commit yet.</span><span class='qd'><b>git push then git add</b>: push requires existing commits and does not record local changes.</span><span class='qd'><b>git clone then git commit</b>: clone copies a repository and is unrelated to recording new edits.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-092", domain:4, obj:"4.4", diff:"hard", q:"In a typical feature-branch workflow, why is a branch created before starting new work?", options:["To isolate changes from the main branch so the main line stays stable until the work is merged","Because Git cannot commit on the main branch","To automatically deploy the code to production","To permanently delete the main branch"], answer:0, explain:"<strong>A feature branch</strong> isolates in-progress changes from the stable main branch, allowing development and review without disrupting others until the work is merged.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Because Git cannot commit on the main branch</b>: Git can commit directly on main; branching is a workflow choice.</span><span class='qd'><b>To automatically deploy the code to production</b>: branching does not trigger deployment by itself.</span><span class='qd'><b>To permanently delete the main branch</b>: creating a branch does not delete main.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-093", domain:4, obj:"4.5", diff:"medium", q:"When an AI assistant generates a shell script for a production task, what is the most important first step before using it?", options:["Run it immediately as root to test it quickly","Review and verify the generated code for correctness and safety before execution","Push it to the main branch without inspection","Assume it is correct because AI produced it"], answer:1, explain:"<strong>Reviewing and verifying</strong> AI-generated code for correctness, security, and unintended side effects is essential before running it, because the model can produce plausible-looking but flawed or harmful commands.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Run it immediately as root to test it quickly</b>: running unverified code as root risks serious system damage.</span><span class='qd'><b>Push it to the main branch without inspection</b>: skipping review can introduce defects or vulnerabilities into shared code.</span><span class='qd'><b>Assume it is correct because AI produced it</b>: AI output is not guaranteed correct and must be validated.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-094", domain:4, obj:"4.5", diff:"medium", q:"Why should sensitive data such as customer records be handled carefully when using a public, cloud-hosted AI coding assistant?", options:["Public AI services may log or retain submitted data, risking exposure of confidential information","AI assistants automatically encrypt all submitted data","Public AI tools cannot process text data","Data governance rules do not apply to AI tools"], answer:0, explain:"<strong>Public AI services</strong> may transmit, log, or retain inputs, so pasting confidential or regulated data into them can violate data governance policies and expose sensitive information.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI assistants automatically encrypt all submitted data</b>: there is no guarantee of end-to-end protection or non-retention.</span><span class='qd'><b>Public AI tools cannot process text data</b>: they readily process text, which is precisely the exposure concern.</span><span class='qd'><b>Data governance rules do not apply to AI tools</b>: governance and compliance requirements still apply when using AI tools.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-095", domain:4, obj:"4.5", diff:"medium", q:"What is a key advantage of using a locally hosted AI model over a public cloud AI service for code generation in a regulated environment?", options:["Local models are always more accurate","Local models never require any hardware","Public services are free of any cost","Sensitive data stays within the organization's control, aiding compliance and privacy"], answer:3, explain:"<strong>A locally hosted model</strong> keeps prompts and proprietary data inside the organization's boundary, reducing data-leakage risk and supporting privacy and compliance requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Local models are always more accurate</b>: accuracy depends on the model, not merely where it runs.</span><span class='qd'><b>Local models never require any hardware</b>: local models require capable compute hardware to run.</span><span class='qd'><b>Public services are free of any cost</b>: cost is not the privacy advantage being described and is often not free.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-096", domain:4, obj:"4.5", diff:"medium", q:"An AI tool suggests a command that includes rm -rf on a path built from a variable. What is the prudent action?", options:["Execute it without checking because AI is reliable","Add sudo to make sure it works","Carefully verify the variable's value and the path before running such a destructive command","Run it on the production server first to see what happens"], answer:2, explain:"<strong>Verifying the variable and path</strong> before running a destructive recursive delete is critical, since an empty or unexpected value could erase far more than intended.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Execute it without checking because AI is reliable</b>: AI suggestions can be wrong and destructive commands demand scrutiny.</span><span class='qd'><b>Add sudo to make sure it works</b>: adding sudo increases the blast radius rather than making it safe.</span><span class='qd'><b>Run it on the production server first to see what happens</b>: testing destructive commands on production is reckless.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-097", domain:4, obj:"4.5", diff:"medium", q:"Why is it important to validate the output of AI-generated configuration files (such as YAML for Ansible) before deployment?", options:["AI may produce syntactically invalid or logically incorrect configs that could break systems if applied unverified","AI never makes syntax errors, so validation is optional","Validation converts YAML to JSON automatically","AI output is automatically tested by the linter"], answer:0, explain:"<strong>Validating AI-generated configs</strong> is important because the model can introduce syntax errors or incorrect logic that, if applied directly, could disrupt or misconfigure systems.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>AI never makes syntax errors, so validation is optional</b>: AI can and does produce invalid syntax.</span><span class='qd'><b>Validation converts YAML to JSON automatically</b>: validation checks correctness; it is not a format conversion step.</span><span class='qd'><b>AI output is automatically tested by the linter</b>: linting only runs if you explicitly run it, and it does not catch all logic errors.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-098", domain:4, obj:"4.5", diff:"hard", q:"Which practice best supports responsible data governance when integrating AI assistants into a development workflow?", options:["Allow any data to be sent to any AI service without restriction","Establish policies defining what data may be shared with which AI tools and prefer approved or local models for sensitive work","Disable all logging so no records of AI usage exist","Share API keys publicly to encourage collaboration"], answer:1, explain:"<strong>Defining clear policies</strong> on what data can be shared with which AI tools, and routing sensitive work to approved or local models, is a sound data governance practice that balances productivity with privacy and compliance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allow any data to be sent to any AI service without restriction</b>: this ignores governance and risks leaking sensitive data.</span><span class='qd'><b>Disable all logging so no records of AI usage exist</b>: removing audit trails undermines accountability and security.</span><span class='qd'><b>Share API keys publicly to encourage collaboration</b>: exposing API keys is a severe security failure.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-099", domain:4, obj:"4.5", diff:"medium", q:"A developer asks an AI assistant to write a Python function and it returns code using a deprecated library call. What should the developer do?", options:["Use it as-is since the AI knows best","Immediately publish it as a public package","Ignore the deprecation because the code still runs today","Verify the code against current documentation and update or replace the deprecated call"], answer:3, explain:"<strong>Verifying against current documentation</strong> and replacing deprecated calls ensures the code remains correct, secure, and maintainable, since AI training data may lag behind current library versions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use it as-is since the AI knows best</b>: AI can rely on outdated patterns and should not be trusted blindly.</span><span class='qd'><b>Immediately publish it as a public package</b>: publishing unverified, deprecated code spreads technical debt and risk.</span><span class='qd'><b>Ignore the deprecation because the code still runs today</b>: deprecated calls can break in future versions and may carry security issues.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D4-100", domain:4, obj:"4.5", diff:"hard", q:"An administrator wants to paste a proprietary internal script into a public AI chatbot to ask for a refactor. What is the most appropriate consideration?", options:["Public chatbots guarantee the code is never stored, so it is always safe","Proprietary code is automatically excluded from AI training","Sharing proprietary code may violate organizational policy and risk intellectual-property exposure, so it should be checked or anonymized first","There is no risk because the code is just text"], answer:2, explain:"<strong>Sharing proprietary code</strong> with a public AI service can expose intellectual property and breach data-handling policy, so the administrator should follow organizational rules and consider anonymizing or using an approved tool.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Public chatbots guarantee the code is never stored, so it is always safe</b>: no such universal guarantee exists; many services retain inputs.</span><span class='qd'><b>Proprietary code is automatically excluded from AI training</b>: there is no automatic exclusion of submitted proprietary data.</span><span class='qd'><b>There is no risk because the code is just text</b>: text can still contain secrets and proprietary logic that create real risk.</span>" }
);

/* linux+ :: XK0-006 Domain 5 question bank (100 items, inline). Populates LINUXPLUS.questions. */
window.LINUXPLUS = window.LINUXPLUS || {}; LINUXPLUS.questions = LINUXPLUS.questions || [];
LINUXPLUS.questions.push(
{ id:"D5-001", domain:5, obj:"5.1", diff:"medium", q:"A monitoring contract guarantees 99.9% uptime per month. Which term describes this externally committed target that carries penalties if breached?", options:["SLA","SLO","SLI","KPI"], answer:0, explain:"<strong>An SLA (Service Level Agreement)</strong> is the formal, externally committed target with consequences (penalties) for breach.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SLO</b>: an internal objective the team aims for, usually stricter than the SLA and without contractual penalties.</span><span class='qd'><b>SLI</b>: the actual measured indicator (e.g., measured uptime), not the committed target.</span><span class='qd'><b>KPI</b>: a generic business performance metric, not the contractual availability commitment.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-002", domain:5, obj:"5.1", diff:"medium", q:"You need to collect metrics from network switches that cannot run a host agent. Which monitoring approach fits best?", options:["Install a sidecar container","Push metrics with node_exporter","Agentless polling via SNMP","Scrape /proc on the switch"], answer:2, explain:"<strong>Agentless polling via SNMP</strong> lets the monitoring server query device OIDs without installing software on the switch.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Install a sidecar container</b>: switches generally cannot run arbitrary containers.</span><span class='qd'><b>Push metrics with node_exporter</b>: node_exporter is a host agent and cannot be installed on a closed switch OS.</span><span class='qd'><b>Scrape /proc on the switch</b>: network switches do not expose a Linux /proc to remote scrapers.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-003", domain:5, obj:"5.1", diff:"easy", q:"An alert fires every few minutes then clears, never indicating a real outage. Which adjustment most directly reduces this noisy flapping?", options:["Lower the alert threshold","Disable the alert entirely","Increase scrape interval to 1 hour","Add a duration/for clause before firing"], answer:3, explain:"<strong>Adding a duration (a 'for' clause)</strong> requires the condition to persist before alerting, smoothing out transient spikes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Lower the alert threshold</b>: lowering it makes the alert even more sensitive and noisier.</span><span class='qd'><b>Disable the alert entirely</b>: that removes useful coverage and hides genuine outages.</span><span class='qd'><b>Increase scrape interval to 1 hour</b>: coarse sampling delays real detection without fixing flapping logic.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-004", domain:5, obj:"5.1", diff:"medium", q:"Your team measured 99.5% availability this month but committed to 99.9% in the contract. Which statement is accurate?", options:["The SLI met the SLA","The SLI breached the SLA","The SLO was exceeded","No measurement occurred"], answer:1, explain:"<strong>The measured indicator (SLI) of 99.5% is below the 99.9% SLA</strong>, so the agreement was breached.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The SLI met the SLA</b>: 99.5% is less than 99.9%, so the target was not met.</span><span class='qd'><b>The SLO was exceeded</b>: falling short of the target is the opposite of exceeding it.</span><span class='qd'><b>No measurement occurred</b>: 99.5% is itself a measured SLI value.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-005", domain:5, obj:"5.1", diff:"medium", q:"A Prometheus-style server reaches out to each host's /metrics endpoint on a schedule to gather data. What is this collection model called?", options:["Push model","Pull/scrape model","Trap model","Syslog forwarding"], answer:1, explain:"<strong>The pull/scrape model</strong> has the monitoring server periodically request metrics from each target endpoint.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Push model</b>: in a push model the agent sends data to the server, not the reverse.</span><span class='qd'><b>Trap model</b>: SNMP traps are unsolicited device-initiated events, not scheduled scrapes.</span><span class='qd'><b>Syslog forwarding</b>: syslog ships log lines, not a scraped metrics endpoint.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-006", domain:5, obj:"5.1", diff:"hard", q:"You want CPU alerts to escalate to PagerDuty only for production hosts, while dev hosts just log. Which monitoring feature implements this differentiation?", options:["Raising the global threshold","Label/tag-based routing","Disabling dev scraping","Lowering scrape interval"], answer:1, explain:"<strong>Label/tag-based routing</strong> matches an environment label and sends alerts to different receivers accordingly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Raising the global threshold</b>: a single threshold cannot route by environment.</span><span class='qd'><b>Disabling dev scraping</b>: that loses dev visibility entirely instead of routing.</span><span class='qd'><b>Lowering scrape interval</b>: interval changes sampling frequency, not alert destinations.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-007", domain:5, obj:"5.1", diff:"easy", q:"Which tool gives a real-time, continuously updating view of per-process CPU and memory for a quick first look at a busy server?", options:["cron","journald rotation","top","logrotate"], answer:2, explain:"<strong>top</strong> displays a live, refreshing list of processes ranked by resource usage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cron</b>: cron schedules jobs and shows nothing about live resource use.</span><span class='qd'><b>journald rotation</b>: rotation manages log size, not real-time process metrics.</span><span class='qd'><b>logrotate</b>: logrotate trims log files and is unrelated to live monitoring.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-008", domain:5, obj:"5.1", diff:"medium", q:"An SNMP v2c poller returns no data from a host, but pings succeed. Which is the most likely cause to check first?", options:["Bad DNS resolution","Full root filesystem","Wrong community string or blocked UDP 161","Expired TLS certificate"], answer:2, explain:"<strong>A wrong community string or blocked UDP 161</strong> is the classic SNMP polling failure even when ICMP works.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Bad DNS resolution</b>: if you can ping the host by IP, name resolution is not the blocker.</span><span class='qd'><b>Full root filesystem</b>: a full disk does not specifically stop SNMP responses on UDP 161.</span><span class='qd'><b>Expired TLS certificate</b>: SNMP v2c does not use TLS certificates.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-009", domain:5, obj:"5.1", diff:"medium", q:"You want to alert when free disk space will be exhausted soon, not just when it is already full. Which approach best meets this goal?", options:["Static 100% used threshold","Alert only on reboot","Predictive/trend-based threshold on usage rate","Page only when df returns an error"], answer:2, explain:"<strong>A predictive/trend-based threshold</strong> projects the usage growth rate to warn before space runs out.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Static 100% used threshold</b>: that only fires after the disk is already full.</span><span class='qd'><b>Alert only on reboot</b>: reboots are unrelated to disk fill prediction.</span><span class='qd'><b>Page only when df returns an error</b>: df rarely errors just because a disk is nearly full.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-010", domain:5, obj:"5.1", diff:"easy", q:"Which command shows a continuously updating count of established and listening sockets to confirm a service is accepting connections?", options:["tar -tvf","modprobe","fdisk -l","watch -n1 'ss -s'"], answer:3, explain:"<strong>watch -n1 'ss -s'</strong> refreshes socket summary statistics every second for live verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tar -tvf</b>: lists archive contents, unrelated to sockets.</span><span class='qd'><b>modprobe</b>: loads kernel modules, not socket monitoring.</span><span class='qd'><b>fdisk -l</b>: lists disk partitions, not network connections.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-011", domain:5, obj:"5.1", diff:"hard", q:"A dashboard shows average request latency well under target, yet users complain of slowness. Which monitoring refinement best surfaces the real problem?", options:["Increase the averaging window","Remove the latency panel","Alert only on host down","Track p95/p99 percentile latency"], answer:3, explain:"<strong>Tracking p95/p99 percentiles</strong> exposes the tail of slow requests that averages hide.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase the averaging window</b>: longer averaging masks spikes even more.</span><span class='qd'><b>Remove the latency panel</b>: removing visibility makes diagnosis harder.</span><span class='qd'><b>Alert only on host down</b>: the host is up; the issue is request-level latency.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-012", domain:5, obj:"5.1", diff:"medium", q:"Which mechanism lets a network device asynchronously notify the monitoring server the instant an interface goes down, instead of waiting for the next poll?", options:["cron job","logrotate","SNMP trap","df --inodes"], answer:2, explain:"<strong>An SNMP trap</strong> is pushed by the device immediately when an event occurs, reducing detection delay.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cron job</b>: cron runs on a fixed schedule and is not event-driven by the device.</span><span class='qd'><b>logrotate</b>: it manages log files, not asynchronous device events.</span><span class='qd'><b>df --inodes</b>: that reports inode usage, unrelated to interface state notifications.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-013", domain:5, obj:"5.1", diff:"medium", q:"You configured an error-budget policy: once the budget is consumed, feature releases pause. Which value defines that budget?", options:["100% minus the SLO","The SLA penalty fee","The scrape interval","The number of dashboards"], answer:0, explain:"<strong>The error budget equals 100% minus the SLO</strong> (the allowable unreliability over a window).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The SLA penalty fee</b>: that is a financial consequence, not the reliability budget.</span><span class='qd'><b>The scrape interval</b>: sampling frequency is unrelated to budget size.</span><span class='qd'><b>The number of dashboards</b>: dashboards do not define allowable error.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-014", domain:5, obj:"5.1", diff:"easy", q:"A junior admin asks which file lets you query recent boots and filter by service and time for monitoring. Which command queries the systemd journal?", options:["ifconfig","umount","blkid","journalctl"], answer:3, explain:"<strong>journalctl</strong> queries the systemd journal with filters for unit, priority, and time range.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ifconfig</b>: shows network interface configuration, not logs.</span><span class='qd'><b>umount</b>: unmounts filesystems, unrelated to journal queries.</span><span class='qd'><b>blkid</b>: prints block device UUIDs, not log data.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-015", domain:5, obj:"5.1", diff:"medium", q:"To reduce alert fatigue, you want related alerts about the same incident combined into a single notification. Which alertmanager concept does this?", options:["Scraping","Federation","Grouping","Relabeling"], answer:2, explain:"<strong>Grouping</strong> batches alerts sharing common labels into one consolidated notification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Scraping</b>: scraping collects metrics, it does not consolidate alerts.</span><span class='qd'><b>Federation</b>: federation aggregates metrics across servers, not alert notifications.</span><span class='qd'><b>Relabeling</b>: relabeling rewrites labels but does not group notifications.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-016", domain:5, obj:"5.1", diff:"medium", q:"A capacity report needs historical CPU trends over the past year, but your metrics store only keeps 15 days. Which fix addresses this?", options:["Lower the alert threshold","Add more dashboards","Switch to SNMP traps","Increase retention / use long-term storage"], answer:3, explain:"<strong>Increasing retention or adding long-term storage</strong> preserves the historical data needed for yearly trends.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Lower the alert threshold</b>: thresholds do not extend how long data is kept.</span><span class='qd'><b>Add more dashboards</b>: dashboards only visualize data that still exists.</span><span class='qd'><b>Switch to SNMP traps</b>: traps are event notifications and do not store long-term trends.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-017", domain:5, obj:"5.2", diff:"easy", q:"Following the standard troubleshooting methodology, what is the correct first step when a user reports a server problem?", options:["Reboot immediately","Replace the hardware","Restore from backup","Identify the problem and gather information"], answer:3, explain:"<strong>Identifying the problem and gathering information</strong> is the documented first step before any change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reboot immediately</b>: rebooting before understanding can destroy evidence and may not help.</span><span class='qd'><b>Replace the hardware</b>: replacement is premature without a diagnosis.</span><span class='qd'><b>Restore from backup</b>: restoring is a last-resort action, not the first investigative step.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-018", domain:5, obj:"5.2", diff:"medium", q:"After a kernel update the system halts with 'VFS: Unable to mount root fs on unknown-block'. Which is the most likely cause?", options:["Expired user password","Missing initramfs/driver for the root device","Wrong DNS server","Full /var partition"], answer:1, explain:"<strong>A missing initramfs or storage driver</strong> prevents the kernel from mounting the root filesystem at boot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Expired user password</b>: login credentials are irrelevant before root is mounted.</span><span class='qd'><b>Wrong DNS server</b>: name resolution plays no role in mounting a local root device.</span><span class='qd'><b>Full /var partition</b>: /var is not needed to mount the root filesystem during early boot.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-019", domain:5, obj:"5.2", diff:"medium", q:"A server drops to an emergency shell at boot after an /etc/fstab edit. Which command best identifies the offending entry?", options:["passwd root","dig example.com","systemctl status, then review fstab for a bad UUID/option","iptables -L"], answer:2, explain:"<strong>Checking systemctl/journal status and reviewing fstab for a bad UUID or option</strong> pinpoints the failed mount that forced emergency mode.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>passwd root</b>: changing a password does not fix a mount failure.</span><span class='qd'><b>dig example.com</b>: DNS lookups are unrelated to local mounts.</span><span class='qd'><b>iptables -L</b>: firewall rules do not cause fstab mount failures.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-020", domain:5, obj:"5.2", diff:"hard", q:"A non-bootable fstab entry should not block boot if the device is missing. Which mount option allows the system to continue booting?", options:["sync","nofail","exec","relatime"], answer:1, explain:"<strong>nofail</strong> lets the boot proceed even when the listed device is absent or unmountable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sync</b>: forces synchronous I/O and has no effect on boot blocking.</span><span class='qd'><b>exec</b>: permits binary execution from the mount, unrelated to boot failure handling.</span><span class='qd'><b>relatime</b>: controls atime update behavior, not boot resilience.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-021", domain:5, obj:"5.2", diff:"medium", q:"Users cannot write new files even though df shows the partition only 60% full. Which command reveals the real cause?", options:["df -i (inode exhaustion)","ping -c4","traceroute","nmcli con up"], answer:0, explain:"<strong>df -i</strong> shows inode usage; running out of inodes blocks new files even with free blocks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ping -c4</b>: tests connectivity, irrelevant to local file creation.</span><span class='qd'><b>traceroute</b>: maps network paths, not filesystem capacity.</span><span class='qd'><b>nmcli con up</b>: brings up a network connection, unrelated to inodes.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-022", domain:5, obj:"5.2", diff:"medium", q:"At the GRUB menu you need to boot into a minimal environment to reset a forgotten root password. Which kernel parameter should you append?", options:["quiet splash","ro","init=/bin/bash or systemd.unit=rescue.target","selinux=0"], answer:2, explain:"<strong>Appending init=/bin/bash (or systemd.unit=rescue.target)</strong> boots a minimal shell to reset the password.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>quiet splash</b>: only hides boot messages, giving no shell access.</span><span class='qd'><b>ro</b>: mounts root read-only, which would block writing the new password.</span><span class='qd'><b>selinux=0</b>: disables SELinux but does not provide a recovery shell.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-023", domain:5, obj:"5.2", diff:"medium", q:"After patching, the system shows 'error: file /vmlinuz not found' at the GRUB prompt. Which action most directly resolves it?", options:["Reset the user quota","Flush the DNS cache","Regenerate the GRUB config (grub2-mkconfig/update-grub)","Restart sshd"], answer:2, explain:"<strong>Regenerating the GRUB config</strong> rewrites menu entries to point at the correct installed kernel image.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reset the user quota</b>: quotas have nothing to do with locating the kernel.</span><span class='qd'><b>Flush the DNS cache</b>: DNS is irrelevant to a local boot loader path.</span><span class='qd'><b>Restart sshd</b>: the system is not even booted, so sshd is not the issue.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-024", domain:5, obj:"5.2", diff:"hard", q:"A filesystem shows corruption after an unclean shutdown and refuses to mount. Which command checks and repairs it while unmounted?", options:["mount -a","tune2fs -l only","sync","fsck"], answer:3, explain:"<strong>fsck</strong> checks and repairs filesystem inconsistencies on an unmounted volume.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>mount -a</b>: attempts to mount but does not repair corruption.</span><span class='qd'><b>tune2fs -l only</b>: only displays superblock info; it does not repair.</span><span class='qd'><b>sync</b>: flushes buffers but performs no integrity check.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-025", domain:5, obj:"5.2", diff:"medium", q:"A systemd service fails on start. Which command shows the most relevant recent logs to diagnose why?", options:["crontab -l","ls -l /etc","journalctl -u myservice -e","route -n"], answer:2, explain:"<strong>journalctl -u myservice -e</strong> shows that unit's most recent log entries explaining the failure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>crontab -l</b>: lists cron jobs, not service logs.</span><span class='qd'><b>ls -l /etc</b>: lists config files but not runtime failure messages.</span><span class='qd'><b>route -n</b>: shows the routing table, unrelated to a service start failure.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-026", domain:5, obj:"5.2", diff:"easy", q:"After establishing a theory of probable cause, what does the troubleshooting methodology prescribe next?", options:["Document everything and close","Test the theory to determine cause","Inform the user it is fixed","Replace the motherboard"], answer:1, explain:"<strong>Testing the theory to determine the actual cause</strong> follows establishing a probable cause.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Document everything and close</b>: documentation is the final step, not the one right after theorizing.</span><span class='qd'><b>Inform the user it is fixed</b>: nothing is confirmed fixed until the theory is tested.</span><span class='qd'><b>Replace the motherboard</b>: hardware replacement is unjustified before testing.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-027", domain:5, obj:"5.2", diff:"hard", q:"A user exceeded their disk quota and cannot save files, but root can still write to the same filesystem. Which command displays the user's quota usage and limits?", options:["du -sh /","quota -u username","fsck -n","lsblk"], answer:1, explain:"<strong>quota -u username</strong> reports that user's block/inode usage against their soft and hard limits.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>du -sh /</b>: totals directory size but does not show per-user quota limits.</span><span class='qd'><b>fsck -n</b>: checks filesystem integrity, not quotas.</span><span class='qd'><b>lsblk</b>: lists block devices, not user quota usage.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-028", domain:5, obj:"5.2", diff:"medium", q:"A kernel panic scrolls past too fast to read on a headless server. Which configuration helps capture it for later analysis?", options:["raising user quota","kdump/crash dump capture","disabling swap","setting MTU 9000"], answer:1, explain:"<strong>kdump (crash dump capture)</strong> saves a vmcore on panic so the cause can be analyzed afterward.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>raising user quota</b>: quotas are unrelated to capturing panics.</span><span class='qd'><b>disabling swap</b>: swap settings do not preserve panic output.</span><span class='qd'><b>setting MTU 9000</b>: MTU is a network parameter, irrelevant to crash dumps.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-029", domain:5, obj:"5.2", diff:"medium", q:"The root filesystem is 100% full and even logins are slow. Which command quickly identifies the largest space consumers under /var?", options:["du -sh /var/* | sort -h","cat /etc/fstab","systemctl daemon-reload","modinfo ext4"], answer:0, explain:"<strong>du -sh /var/* | sort -h</strong> summarizes and ranks subdirectory sizes to find the space hog.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cat /etc/fstab</b>: shows mount config, not what is consuming space.</span><span class='qd'><b>systemctl daemon-reload</b>: reloads unit files and frees no space.</span><span class='qd'><b>modinfo ext4</b>: prints module info, unrelated to disk usage.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-030", domain:5, obj:"5.2", diff:"medium", q:"A deleted-but-still-open log file keeps the disk full even after rm. Which command reveals processes holding the deleted file?", options:["lsof | grep deleted","grub2-install","tar -czf","chage -l"], answer:0, explain:"<strong>lsof | grep deleted</strong> lists processes still holding handles to unlinked files that retain disk space.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>grub2-install</b>: reinstalls the boot loader, unrelated to open file handles.</span><span class='qd'><b>tar -czf</b>: creates archives, it does not find open deleted files.</span><span class='qd'><b>chage -l</b>: shows password aging, not file handles.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-031", domain:5, obj:"5.2", diff:"easy", q:"You changed a unit file under /etc/systemd/system but systemctl still uses the old definition. What must you run?", options:["systemctl daemon-reload","reboot the kernel","fsck the disk","flush iptables"], answer:0, explain:"<strong>systemctl daemon-reload</strong> reloads unit definitions so changes take effect without rebooting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>reboot the kernel</b>: a full reboot is unnecessary just to reload unit files.</span><span class='qd'><b>fsck the disk</b>: filesystem checks do not reload systemd units.</span><span class='qd'><b>flush iptables</b>: clearing firewall rules is unrelated to systemd config.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-032", domain:5, obj:"5.2", diff:"hard", q:"After moving disks to a new controller, the system fails to find root by device name like /dev/sdb2. Which fstab/GRUB change is most robust?", options:["Hard-code /dev/sda always","Reference the filesystem by UUID","Use a relative path","Remove the root entry"], answer:1, explain:"<strong>Referencing by UUID</strong> survives device-name reordering caused by controller or enumeration changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Hard-code /dev/sda always</b>: device letters can change, reintroducing the failure.</span><span class='qd'><b>Use a relative path</b>: relative paths are invalid for root device references.</span><span class='qd'><b>Remove the root entry</b>: removing root makes the system unbootable.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-033", domain:5, obj:"5.2", diff:"medium", q:"A service that depends on a network mount fails because it starts before the mount is ready. Which systemd directive enforces correct ordering?", options:["After= and Requires= on the mount unit","Restart=always only","Nice=-20","TimeoutSec=0"], answer:0, explain:"<strong>After= and Requires= referencing the mount unit</strong> ensure the service starts only once the mount is available.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Restart=always only</b>: it just retries blindly without fixing ordering.</span><span class='qd'><b>Nice=-20</b>: adjusts CPU priority, not start order.</span><span class='qd'><b>TimeoutSec=0</b>: disables a timeout but does not establish a dependency.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-034", domain:5, obj:"5.2", diff:"medium", q:"During boot one disk in a software RAID is missing and the array starts degraded. Which command inspects the array state?", options:["cat /proc/mdstat","getenforce","dhclient -r","arp -a"], answer:0, explain:"<strong>cat /proc/mdstat</strong> shows the md RAID status, including degraded or rebuilding arrays.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>getenforce</b>: reports SELinux mode, not RAID state.</span><span class='qd'><b>dhclient -r</b>: releases a DHCP lease, unrelated to RAID.</span><span class='qd'><b>arp -a</b>: shows the ARP cache, not array health.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-035", domain:5, obj:"5.2", diff:"medium", q:"A custom kernel boots but a needed network card has no driver and shows no interface. Which command confirms whether the module is loaded?", options:["lsmod | grep <driver>","quota -u","du -h","passwd"], answer:0, explain:"<strong>lsmod | grep &lt;driver&gt;</strong> confirms whether the required module is currently loaded.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>quota -u</b>: shows disk quotas, not loaded modules.</span><span class='qd'><b>du -h</b>: reports disk usage, irrelevant to drivers.</span><span class='qd'><b>passwd</b>: changes passwords, unrelated to kernel modules.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-036", domain:5, obj:"5.2", diff:"hard", q:"You suspect a recent change caused a boot regression. Which methodology principle helps isolate it fastest?", options:["Change one variable at a time","Change many settings at once","Skip backups to save time","Avoid documenting changes"], answer:0, explain:"<strong>Changing one variable at a time</strong> isolates which change caused the regression.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Change many settings at once</b>: simultaneous changes make the true cause ambiguous.</span><span class='qd'><b>Skip backups to save time</b>: skipping backups risks unrecoverable mistakes.</span><span class='qd'><b>Avoid documenting changes</b>: poor documentation hinders rollback and learning.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-037", domain:5, obj:"5.2", diff:"medium", q:"A previously working service is now masked and refuses to start with 'Unit is masked'. Which command restores its ability to run?", options:["systemctl daemon-reexec","fsck -f","grub2-mkconfig","systemctl unmask <unit>"], answer:3, explain:"<strong>systemctl unmask &lt;unit&gt;</strong> removes the mask symlink so the unit can start again.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl daemon-reexec</b>: re-executes systemd but leaves the mask in place.</span><span class='qd'><b>fsck -f</b>: checks a filesystem, unrelated to masking.</span><span class='qd'><b>grub2-mkconfig</b>: regenerates boot config, not service masks.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-038", domain:5, obj:"5.2", diff:"medium", q:"After a crash, fsck repaired files and placed orphaned data somewhere. Where should you look for recovered fragments?", options:["lost+found at the filesystem root","/etc/skel","/proc/sys","/dev/null"], answer:0, explain:"<strong>The lost+found directory</strong> at each filesystem's root holds orphaned inodes recovered by fsck.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/skel</b>: holds default new-user files, not recovered data.</span><span class='qd'><b>/proc/sys</b>: exposes kernel tunables, not filesystem orphans.</span><span class='qd'><b>/dev/null</b>: discards data; nothing is recoverable there.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-039", domain:5, obj:"5.2", diff:"easy", q:"You need to boot the previous, known-good kernel because the newest one panics. Where do you select it?", options:["/etc/passwd","GRUB boot menu / Advanced options","crontab","ss -tlnp"], answer:1, explain:"<strong>The GRUB boot menu's advanced options</strong> let you choose an older, working kernel entry.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/passwd</b>: stores user accounts, not boot entries.</span><span class='qd'><b>crontab</b>: schedules jobs, unrelated to kernel selection.</span><span class='qd'><b>ss -tlnp</b>: lists listening sockets, not boot menus.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-040", domain:5, obj:"5.2", diff:"medium", q:"After a forced shutdown, a journaled ext4 volume mounts but you want to force a full check on next boot. Which command schedules it?", options:["tune2fs -c or touch /forcefsck","setenforce 0","ip link set down","systemctl isolate"], answer:0, explain:"<strong>Using tune2fs to set the mount count (or creating /forcefsck)</strong> forces fsck at the next boot.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>setenforce 0</b>: changes SELinux mode, not fsck scheduling.</span><span class='qd'><b>ip link set down</b>: disables an interface, unrelated to filesystem checks.</span><span class='qd'><b>systemctl isolate</b>: switches targets but does not force fsck.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-041", domain:5, obj:"5.3", diff:"easy", q:"A host can ping its gateway by IP but cannot reach websites by name. Which subsystem is most likely misconfigured?", options:["Local CPU governor","DNS resolution","Disk scheduler","SELinux booleans"], answer:1, explain:"<strong>DNS resolution</strong> is the likely culprit when IP connectivity works but name lookups fail.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Local CPU governor</b>: CPU frequency settings do not affect name resolution.</span><span class='qd'><b>Disk scheduler</b>: storage I/O scheduling is unrelated to DNS.</span><span class='qd'><b>SELinux booleans</b>: a boolean would not selectively break only name lookups while ping works.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-042", domain:5, obj:"5.3", diff:"medium", q:"You suspect a DNS record is wrong. Which command queries a specific record type directly from a chosen server?", options:["du -sh","dig @8.8.8.8 example.com A","lsblk -f","systemctl restart"], answer:1, explain:"<strong>dig @8.8.8.8 example.com A</strong> queries the A record from a specified resolver for direct verification.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>du -sh</b>: reports disk usage, not DNS records.</span><span class='qd'><b>lsblk -f</b>: lists block devices and filesystems, unrelated to DNS.</span><span class='qd'><b>systemctl restart</b>: restarts a service but does not query DNS.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-043", domain:5, obj:"5.3", diff:"medium", q:"A laptop got an IP of 169.254.x.x and cannot reach the network. What does this address indicate?", options:["DHCP failed; APIPA self-assignment","Static IP success","Correct gateway set","DNS is healthy"], answer:0, explain:"<strong>A 169.254.x.x address means DHCP failed and the host self-assigned an APIPA/link-local address.</strong><br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Static IP success</b>: APIPA is automatic, not a configured static address.</span><span class='qd'><b>Correct gateway set</b>: link-local addressing has no usable default gateway.</span><span class='qd'><b>DNS is healthy</b>: with no real IP, DNS is also unreachable.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-044", domain:5, obj:"5.3", diff:"medium", q:"Large packets fail across a VPN while small pings succeed, suggesting fragmentation issues. Which setting should you check?", options:["User quota","Interface MTU","SELinux context","CPU affinity"], answer:1, explain:"<strong>The interface MTU</strong> is the prime suspect when small packets pass but large ones fail.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>User quota</b>: disk quotas have nothing to do with packet size.</span><span class='qd'><b>SELinux context</b>: security contexts do not fragment packets.</span><span class='qd'><b>CPU affinity</b>: process-to-CPU binding is unrelated to MTU.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-045", domain:5, obj:"5.3", diff:"medium", q:"You need to see which process is listening on TCP port 443 and its PID. Which command is best?", options:["dig -x","mount","ss -tlnp","udevadm"], answer:2, explain:"<strong>ss -tlnp</strong> lists listening TCP sockets with the owning process and PID.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dig -x</b>: performs reverse DNS, not socket inspection.</span><span class='qd'><b>mount</b>: shows mounted filesystems, unrelated to ports.</span><span class='qd'><b>udevadm</b>: queries device events, not listening sockets.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-046", domain:5, obj:"5.3", diff:"hard", q:"Two hosts on the same subnet intermittently lose connectivity, and the ARP table shows the same MAC for two different IPs. What is the likely cause?", options:["Duplicate IP / IP conflict","Wrong DNS TTL","Full inode table","High swap usage"], answer:0, explain:"<strong>A duplicate IP (IP conflict)</strong> produces ARP confusion and intermittent reachability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wrong DNS TTL</b>: DNS caching does not change ARP MAC mappings.</span><span class='qd'><b>Full inode table</b>: a filesystem issue does not corrupt ARP entries.</span><span class='qd'><b>High swap usage</b>: memory pressure does not create duplicate ARP MACs.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-047", domain:5, obj:"5.3", diff:"easy", q:"A server cannot reach any remote network but talks fine to local hosts. Which configuration is most likely missing or wrong?", options:["DNS search domain","Hostname","Default gateway/route","Time zone"], answer:2, explain:"<strong>The default gateway/route</strong> is required to reach networks beyond the local subnet.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS search domain</b>: that affects name suffixing, not routing off-subnet.</span><span class='qd'><b>Hostname</b>: the system name does not control routing.</span><span class='qd'><b>Time zone</b>: clock settings are irrelevant to packet forwarding.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-048", domain:5, obj:"5.3", diff:"medium", q:"A web service is up locally (curl localhost works) but external clients time out. Which is the most likely cause?", options:["Wrong shell prompt","Full /tmp","Firewall blocking the port","Bad locale setting"], answer:2, explain:"<strong>A firewall blocking the listening port</strong> explains local success but external timeouts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wrong shell prompt</b>: cosmetic prompt settings do not block traffic.</span><span class='qd'><b>Full /tmp</b>: a full temp directory would not selectively block remote access while localhost works.</span><span class='qd'><b>Bad locale setting</b>: locale affects formatting, not network reachability.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-049", domain:5, obj:"5.3", diff:"medium", q:"Traffic to a remote host dies after a specific hop. Which tool best shows where the path breaks?", options:["chmod","useradd","traceroute / tracepath","sysctl -a"], answer:2, explain:"<strong>traceroute (or tracepath)</strong> reveals each hop, exposing where the path stops responding.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod</b>: changes file permissions, unrelated to routing.</span><span class='qd'><b>useradd</b>: creates accounts, not network diagnostics.</span><span class='qd'><b>sysctl -a</b>: dumps kernel parameters but does not trace routes.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-050", domain:5, obj:"5.3", diff:"hard", q:"After enabling jumbo frames on a server (MTU 9000) but not on the switch, throughput collapses. What is the correct fix?", options:["Lower server CPU clock","Match MTU consistently end-to-end","Increase swap","Disable DNS caching"], answer:1, explain:"<strong>Matching MTU consistently across the path</strong> resolves the mismatch that breaks jumbo-frame traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Lower server CPU clock</b>: CPU speed is unrelated to MTU mismatch.</span><span class='qd'><b>Increase swap</b>: memory has no bearing on frame size handling.</span><span class='qd'><b>Disable DNS caching</b>: DNS does not affect MTU behavior.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-051", domain:5, obj:"5.3", diff:"medium", q:"You want to verify a host's IP, mask, and link state on a modern systemd-based distro. Which command is preferred?", options:["ip addr show","ifconfig -a only","cat /etc/hosts","crontab -e"], answer:0, explain:"<strong>ip addr show</strong> is the modern tool to display addresses, masks, and link state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ifconfig -a only</b>: ifconfig is deprecated and may be absent on minimal systems.</span><span class='qd'><b>cat /etc/hosts</b>: shows static name mappings, not interface state.</span><span class='qd'><b>crontab -e</b>: edits scheduled jobs, unrelated to interfaces.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-052", domain:5, obj:"5.3", diff:"medium", q:"An interface shows 'state DOWN' in ip link and no carrier. Which is the best first physical-layer check?", options:["DNS server entry","SELinux policy","Disk SMART status","Cable/SFP and link light"], answer:3, explain:"<strong>Checking the cable/SFP and link light</strong> is the right first move for a no-carrier, DOWN link.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS server entry</b>: DNS is layer 7, irrelevant to a dead physical link.</span><span class='qd'><b>SELinux policy</b>: security policy does not control carrier signal.</span><span class='qd'><b>Disk SMART status</b>: storage health is unrelated to link state.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-053", domain:5, obj:"5.3", diff:"medium", q:"A host gets an address but the wrong DNS servers from DHCP. Which file (on resolv-managed systems) should reflect the resolvers in use?", options:["/etc/resolv.conf","/etc/fstab","/etc/crontab","/boot/grub2/grub.cfg"], answer:0, explain:"<strong>/etc/resolv.conf</strong> lists the nameservers the resolver uses; it should reflect the DHCP-provided DNS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/fstab</b>: defines mounts, not DNS servers.</span><span class='qd'><b>/etc/crontab</b>: schedules jobs, unrelated to resolvers.</span><span class='qd'><b>/boot/grub2/grub.cfg</b>: is the boot loader config, not DNS.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-054", domain:5, obj:"5.3", diff:"hard", q:"A client at 10.0.5.40/24 cannot reach 10.0.6.10 even though both are 'in the company network'. Which misconfiguration most likely explains it?", options:["Wrong keyboard layout","Stale ARP for localhost","Bad NTP server","Subnet mask too narrow; needs routing/gateway"], answer:3, explain:"<strong>The /24 mask puts 10.0.6.10 on a different subnet, so a gateway/route is required to reach it.</strong><br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wrong keyboard layout</b>: input settings do not affect routing.</span><span class='qd'><b>Stale ARP for localhost</b>: localhost ARP does not govern remote-subnet reachability.</span><span class='qd'><b>Bad NTP server</b>: time sync issues do not block IP routing.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-055", domain:5, obj:"5.3", diff:"medium", q:"You changed firewalld rules but the new port is still blocked. Which command applies the change so it takes effect?", options:["sync","firewall-cmd --reload","modprobe -r","blkid"], answer:1, explain:"<strong>firewall-cmd --reload</strong> applies permanent firewalld changes to the running configuration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sync</b>: flushes disk buffers, unrelated to firewall rules.</span><span class='qd'><b>modprobe -r</b>: removes a kernel module, not firewall state.</span><span class='qd'><b>blkid</b>: shows block device UUIDs, irrelevant to firewalls.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-056", domain:5, obj:"5.3", diff:"medium", q:"To confirm whether a remote TCP port is reachable through the network, which command is most appropriate?", options:["ls -l /etc","du -h /home","passwd user","nc -zv host 443"], answer:3, explain:"<strong>nc -zv host 443</strong> performs a TCP connection test to verify port reachability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ls -l /etc</b>: lists files, not network ports.</span><span class='qd'><b>du -h /home</b>: reports disk usage, unrelated to connectivity.</span><span class='qd'><b>passwd user</b>: changes a password, not a port test.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-057", domain:5, obj:"5.3", diff:"easy", q:"A new VLAN interface has an IP but cannot ping anything off-link. Which command displays the routing table to verify the gateway?", options:["ip route show","getent passwd","tar -xzf","chown root"], answer:0, explain:"<strong>ip route show</strong> displays routes and the default gateway used for off-link traffic.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>getent passwd</b>: queries user databases, not routes.</span><span class='qd'><b>tar -xzf</b>: extracts archives, unrelated to routing.</span><span class='qd'><b>chown root</b>: changes ownership, not network routes.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-058", domain:5, obj:"5.3", diff:"medium", q:"Intermittent name resolution works for some domains but not others, and one resolver is unreachable. Which command tests a single resolver in isolation?", options:["dig @resolver_ip name","systemctl list-units","du --max-depth=1","lsmod"], answer:0, explain:"<strong>dig @resolver_ip name</strong> queries one specific resolver to isolate which server is failing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>systemctl list-units</b>: lists systemd units, not DNS responses.</span><span class='qd'><b>du --max-depth=1</b>: reports disk usage, irrelevant to DNS.</span><span class='qd'><b>lsmod</b>: lists kernel modules, not resolver behavior.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-059", domain:5, obj:"5.3", diff:"medium", q:"A bonded interface lost half its throughput after a NIC failure. Which file shows the current bond and slave status?", options:["/etc/shadow","/proc/net/bonding/bond0","/var/log/wtmp","/sys/class/dmi"], answer:1, explain:"<strong>/proc/net/bonding/bond0</strong> reports the bond mode and the status of each slave interface.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/etc/shadow</b>: holds password hashes, not bond state.</span><span class='qd'><b>/var/log/wtmp</b>: records logins, not interface bonding.</span><span class='qd'><b>/sys/class/dmi</b>: exposes hardware/BIOS info, not bond status.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-060", domain:5, obj:"5.3", diff:"hard", q:"Clients reach a service by IP but a load balancer health check using the hostname fails. The PTR/forward records mismatch. Which tool confirms the reverse record?", options:["fsck","quotaon","sysctl -w","dig -x <ip>"], answer:3, explain:"<strong>dig -x &lt;ip&gt;</strong> performs the reverse (PTR) lookup to verify it matches the forward record.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>fsck</b>: checks filesystems, not DNS records.</span><span class='qd'><b>quotaon</b>: enables disk quotas, unrelated to DNS.</span><span class='qd'><b>sysctl -w</b>: sets kernel parameters, not reverse lookups.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-061", domain:5, obj:"5.3", diff:"medium", q:"After a switch port was set to a different VLAN, a server lost network access entirely. Which layer should you investigate first?", options:["Application logging level","Disk scheduler","Data link / VLAN assignment","CPU governor"], answer:2, explain:"<strong>The data link layer / VLAN assignment</strong> is the right focus after a VLAN change broke connectivity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Application logging level</b>: log verbosity does not affect VLAN reachability.</span><span class='qd'><b>Disk scheduler</b>: storage I/O is unrelated to VLAN membership.</span><span class='qd'><b>CPU governor</b>: CPU frequency settings do not control networking.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-062", domain:5, obj:"5.3", diff:"medium", q:"You need to capture packets on eth0 to confirm whether SYN replies are returning. Which tool fits?", options:["tcpdump -i eth0","top -i","du -a","chmod 600"], answer:0, explain:"<strong>tcpdump -i eth0</strong> captures live packets to confirm whether handshake replies arrive.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>top -i</b>: shows processes, not packets.</span><span class='qd'><b>du -a</b>: lists file sizes, unrelated to packet capture.</span><span class='qd'><b>chmod 600</b>: changes permissions, not network capture.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-063", domain:5, obj:"5.4", diff:"medium", q:"A web app gets 'Permission denied' writing to /var/www even though file permissions look correct, and AVC denials appear in the audit log. What is the likely cause?", options:["Wrong user shell","Expired sudo timestamp","Missing swap","SELinux context on the directory"], answer:3, explain:"<strong>An incorrect SELinux context</strong> on the directory triggers AVC denials despite correct DAC permissions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wrong user shell</b>: the login shell does not produce AVC denials.</span><span class='qd'><b>Expired sudo timestamp</b>: sudo timing does not affect a daemon writing files.</span><span class='qd'><b>Missing swap</b>: swap has nothing to do with access denials.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-064", domain:5, obj:"5.4", diff:"medium", q:"Which command relabels a file to its correct SELinux context based on policy?", options:["restorecon -v /path","chmod 777 /path","setfacl -b /path","chattr +i /path"], answer:0, explain:"<strong>restorecon -v /path</strong> restores the policy-defined SELinux context on the target.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod 777 /path</b>: changes DAC bits, not SELinux labels, and is insecure.</span><span class='qd'><b>setfacl -b /path</b>: clears ACLs, not SELinux contexts.</span><span class='qd'><b>chattr +i /path</b>: sets the immutable attribute, unrelated to contexts.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-065", domain:5, obj:"5.4", diff:"hard", q:"Temporarily, you must confirm SELinux is the cause of a denial without permanently disabling it. Which command sets it to permissive at runtime?", options:["setenforce 1","setenforce 0","getenforce","sestatus -b"], answer:1, explain:"<strong>setenforce 0</strong> switches SELinux to permissive at runtime so denials are logged but not enforced, for testing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>setenforce 1</b>: sets enforcing mode, which keeps blocking.</span><span class='qd'><b>getenforce</b>: only reports the current mode without changing it.</span><span class='qd'><b>sestatus -b</b>: lists boolean values, it does not change mode.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-066", domain:5, obj:"5.4", diff:"medium", q:"A user belongs to the 'developers' group, which has rwx on a directory, yet still cannot enter it. Which permission is most likely missing?", options:["Read on /etc/passwd","Write on /tmp","Execute (x) bit on the directory path","SetUID on the shell"], answer:2, explain:"<strong>The execute (x) bit on the directory</strong> is required to traverse into it, regardless of read access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Read on /etc/passwd</b>: reading the passwd file is unrelated to entering a directory.</span><span class='qd'><b>Write on /tmp</b>: write access to /tmp does not grant directory traversal elsewhere.</span><span class='qd'><b>SetUID on the shell</b>: SetUID bits do not control directory entry.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-067", domain:5, obj:"5.4", diff:"medium", q:"A specific user needs read access to a file without changing its group or owner. Which mechanism grants this granular permission?", options:["chown alice file","chmod 644 file","setfacl -m u:alice:r file","umask 077"], answer:2, explain:"<strong>setfacl -m u:alice:r file</strong> adds a per-user ACL entry granting read without altering ownership.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chown alice file</b>: that changes ownership rather than adding a granular grant.</span><span class='qd'><b>chmod 644 file</b>: that affects owner/group/other broadly, not one specific user.</span><span class='qd'><b>umask 077</b>: umask sets default permissions for new files, not existing ones.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-068", domain:5, obj:"5.4", diff:"medium", q:"Even root cannot edit or delete a config file, and chmod has no effect. Which attribute likely set on it explains this?", options:["SetGID","Sticky bit","Immutable (chattr +i)","Read ACL"], answer:2, explain:"<strong>The immutable attribute (chattr +i)</strong> blocks modification and deletion even by root until removed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SetGID</b>: SetGID affects group inheritance, not write blocking.</span><span class='qd'><b>Sticky bit</b>: the sticky bit restricts deletion in shared dirs, not edits by root on a single file.</span><span class='qd'><b>Read ACL</b>: an ACL grant would not stop root from editing.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-069", domain:5, obj:"5.4", diff:"hard", q:"After moving a website into a non-default path, httpd still gets denied despite restorecon doing nothing. Which command adds a persistent SELinux file-context rule?", options:["semanage fcontext -a -t httpd_sys_content_t '/srv/web(/.*)?'","setenforce 0","chmod -R 777","userdel apache"], answer:0, explain:"<strong>semanage fcontext -a</strong> adds a persistent context mapping so restorecon can label the new path correctly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>setenforce 0</b>: disabling enforcement is a workaround, not a fix.</span><span class='qd'><b>chmod -R 777</b>: loosening DAC bits does not address SELinux labels.</span><span class='qd'><b>userdel apache</b>: deleting the service account breaks the web server.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-070", domain:5, obj:"5.4", diff:"medium", q:"SSH key login suddenly fails with 'Permission denied (publickey)' and the log shows 'Authentication refused: bad ownership or modes'. What is the cause?", options:["Wrong DNS record","Full /boot","Expired TLS cert","~/.ssh or authorized_keys permissions too open"], answer:3, explain:"<strong>Overly permissive ~/.ssh or authorized_keys</strong> causes sshd to refuse the key for security.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wrong DNS record</b>: DNS does not control key file permission checks.</span><span class='qd'><b>Full /boot</b>: boot partition space is unrelated to SSH key auth.</span><span class='qd'><b>Expired TLS cert</b>: SSH key auth does not rely on TLS certificates.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-071", domain:5, obj:"5.4", diff:"easy", q:"A user reports 'sudo: command not found by policy' style denial; you must see which sudo privileges they actually have. Which command shows this?", options:["whoami","id -Z","last","sudo -l -U username"], answer:3, explain:"<strong>sudo -l -U username</strong> lists the sudo privileges configured for that user.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>whoami</b>: prints only the current user name.</span><span class='qd'><b>id -Z</b>: shows the SELinux context, not sudo rules.</span><span class='qd'><b>last</b>: lists login history, not sudo permissions.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-072", domain:5, obj:"5.4", diff:"medium", q:"A browser warns the internal site's certificate is 'not trusted' though it is technically valid. Which is the most likely cause?", options:["DNS TTL too high","Disk nearly full","The CA chain/root is not trusted by the client","Wrong MTU"], answer:2, explain:"<strong>The signing CA chain or root not being trusted by the client</strong> causes a valid cert to appear untrusted.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>DNS TTL too high</b>: caching duration does not affect certificate trust.</span><span class='qd'><b>Disk nearly full</b>: storage capacity is unrelated to TLS trust chains.</span><span class='qd'><b>Wrong MTU</b>: packet size does not influence certificate validation.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-073", domain:5, obj:"5.4", diff:"medium", q:"A package install fails with 'Cannot retrieve repository metadata' and a 404. Which is the most likely cause?", options:["Expired user quota","Bad CPU microcode","Full swap","Misconfigured/disabled or stale repo baseurl"], answer:3, explain:"<strong>A misconfigured, disabled, or stale repository baseurl</strong> produces 404 metadata retrieval failures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Expired user quota</b>: quotas do not cause repo metadata 404s.</span><span class='qd'><b>Bad CPU microcode</b>: microcode has no effect on repo URLs.</span><span class='qd'><b>Full swap</b>: swap exhaustion does not return HTTP 404 from a mirror.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-074", domain:5, obj:"5.4", diff:"hard", q:"A package install aborts with 'GPG check FAILED' even though the network is fine. Which action correctly resolves it?", options:["Import the correct repo GPG key","Disable the firewall","Increase MTU","Reformat /var"], answer:0, explain:"<strong>Importing the correct repository GPG key</strong> lets the package manager verify signatures and proceed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disable the firewall</b>: the failure is signature verification, not connectivity.</span><span class='qd'><b>Increase MTU</b>: packet size does not affect GPG validation.</span><span class='qd'><b>Reformat /var</b>: reformatting destroys data and does not fix key trust.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-075", domain:5, obj:"5.4", diff:"medium", q:"To inspect why SELinux blocked an action and get a suggested fix, which tool analyzes recent AVC denials?", options:["tcpdump","ausearch/sealert (audit2why)","fdisk","nslookup"], answer:1, explain:"<strong>ausearch/sealert (audit2why)</strong> parses AVC denials and suggests remediation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tcpdump</b>: captures packets, not SELinux denials.</span><span class='qd'><b>fdisk</b>: edits partitions, unrelated to audit logs.</span><span class='qd'><b>nslookup</b>: resolves names, not SELinux events.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-076", domain:5, obj:"5.4", diff:"medium", q:"An FTP service must allow uploads to a home directory but SELinux blocks it. Which lever toggles the allowed behavior without custom modules?", options:["chmod 000","umount the home","An SELinux boolean (setsebool)","passwd -l"], answer:2, explain:"<strong>An SELinux boolean via setsebool</strong> toggles predefined policy behaviors like FTP home writes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod 000</b>: removing all permissions blocks legitimate access.</span><span class='qd'><b>umount the home</b>: unmounting the home directory breaks the service.</span><span class='qd'><b>passwd -l</b>: locking the account prevents login entirely.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-077", domain:5, obj:"5.4", diff:"medium", q:"Files created in a shared team directory keep getting the wrong owning group, breaking collaboration. Which special bit fixes new-file group inheritance?", options:["SetUID on files","Sticky bit","SetGID on the directory","chattr +a"], answer:2, explain:"<strong>SetGID on the directory</strong> makes new files inherit the directory's group for consistent collaboration.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SetUID on files</b>: SetUID affects execution identity, not group inheritance.</span><span class='qd'><b>Sticky bit</b>: the sticky bit restricts deletion, not group ownership.</span><span class='qd'><b>chattr +a</b>: append-only attribute does not set group inheritance.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-078", domain:5, obj:"5.4", diff:"hard", q:"After certificate renewal, clients still see the old expired cert from the web server. Which is the most likely cause?", options:["Wrong subnet mask","Inode exhaustion","Swap thrashing","Service not reloaded after cert replacement"], answer:3, explain:"<strong>The service was not reloaded</strong>, so it keeps serving the cached old certificate from memory.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wrong subnet mask</b>: addressing does not determine which cert is served.</span><span class='qd'><b>Inode exhaustion</b>: a filesystem issue does not cache an old cert in a daemon.</span><span class='qd'><b>Swap thrashing</b>: memory pressure does not pin an expired certificate.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-079", domain:5, obj:"5.4", diff:"medium", q:"A user can read a file via group permissions but a deny ACL entry blocks them. Which command shows the full ACL to confirm?", options:["ls -l file","getfacl file","stat -c %a file","id user"], answer:1, explain:"<strong>getfacl file</strong> displays all ACL entries, including any per-user denies.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ls -l file</b>: shows only base permissions, not full ACLs (only a '+' hint).</span><span class='qd'><b>stat -c %a file</b>: prints the octal mode, not ACL entries.</span><span class='qd'><b>id user</b>: lists group memberships, not file ACLs.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-080", domain:5, obj:"5.4", diff:"medium", q:"Remote SSH works from inside the office but fails from outside with connection refused, while the service is up. Which is the most likely cause?", options:["Wrong locale","Full /home","Bad shell rc file","Edge firewall/NAT not forwarding port 22"], answer:3, explain:"<strong>The edge firewall or NAT not forwarding port 22</strong> explains internal success but external refusal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wrong locale</b>: locale settings do not block remote connections.</span><span class='qd'><b>Full /home</b>: a full home partition would affect logins similarly inside and outside.</span><span class='qd'><b>Bad shell rc file</b>: an rc file issue would affect all sessions, not just external ones.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-081", domain:5, obj:"5.5", diff:"medium", q:"A server feels sluggish; top shows load average far above the CPU count and high %wa. Which subsystem is the bottleneck?", options:["Network bandwidth","DNS latency","Disk I/O (I/O wait)","CPU clock throttling"], answer:2, explain:"<strong>High %wa (I/O wait)</strong> points to disk I/O as the bottleneck stalling the CPU.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Network bandwidth</b>: network saturation does not register as I/O wait.</span><span class='qd'><b>DNS latency</b>: name resolution delays do not raise %wa.</span><span class='qd'><b>CPU clock throttling</b>: throttling shows as high %us/%sy, not I/O wait.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-082", domain:5, obj:"5.5", diff:"medium", q:"Which command provides per-device disk utilization, await, and %util to confirm a storage bottleneck?", options:["dig","ip neigh","setenforce","iostat -x 1"], answer:3, explain:"<strong>iostat -x 1</strong> reports extended per-device stats like await and %util for storage diagnosis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dig</b>: queries DNS, not disk stats.</span><span class='qd'><b>ip neigh</b>: shows the neighbor/ARP table, unrelated to I/O.</span><span class='qd'><b>setenforce</b>: changes SELinux mode, not storage metrics.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-083", domain:5, obj:"5.5", diff:"hard", q:"A box is constantly paging; vmstat shows high si/so values and low free memory. What is happening?", options:["Idle system","Active swapping due to memory pressure","Network congestion","Clock drift"], answer:1, explain:"<strong>High si/so in vmstat indicates active swapping</strong> driven by memory pressure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Idle system</b>: an idle system would show negligible swap activity.</span><span class='qd'><b>Network congestion</b>: si/so measure swap, not network traffic.</span><span class='qd'><b>Clock drift</b>: time sync issues do not produce swap-in/out counts.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-084", domain:5, obj:"5.5", diff:"medium", q:"A process was abruptly killed and dmesg shows 'Out of memory: Killed process'. Which mechanism acted?", options:["The CPU governor","The fsck pass","The DHCP client","The OOM killer"], answer:3, explain:"<strong>The OOM killer</strong> terminates a process to reclaim memory when the system runs out.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The CPU governor</b>: it manages clock frequency, not process termination.</span><span class='qd'><b>The fsck pass</b>: filesystem checks do not kill processes for memory.</span><span class='qd'><b>The DHCP client</b>: DHCP handles addressing, not memory reclaim.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-085", domain:5, obj:"5.5", diff:"medium", q:"Users report a web app is slow. top shows one process pegged at ~100% CPU on a single core. Which command identifies the exact thread/function consuming CPU?", options:["df -h","top -H (then perf/strace on the PID)","mount -a","journalctl --vacuum-size"], answer:1, explain:"<strong>top -H</strong> reveals per-thread CPU, and perf/strace on the PID pinpoints the hot path.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>df -h</b>: shows disk space, not CPU threads.</span><span class='qd'><b>mount -a</b>: mounts filesystems, unrelated to CPU profiling.</span><span class='qd'><b>journalctl --vacuum-size</b>: trims logs, not CPU analysis.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-086", domain:5, obj:"5.5", diff:"easy", q:"Which single command summarizes CPU, memory, swap, and I/O activity at a glance, refreshing every second?", options:["cat /etc/hostname","vmstat 1","echo $PATH","crontab -r"], answer:1, explain:"<strong>vmstat 1</strong> gives a one-second refreshing overview of CPU, memory, swap, and I/O.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cat /etc/hostname</b>: prints the hostname, not performance data.</span><span class='qd'><b>echo $PATH</b>: shows the search path, unrelated to metrics.</span><span class='qd'><b>crontab -r</b>: removes cron jobs, not a monitoring command.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-087", domain:5, obj:"5.5", diff:"hard", q:"Storage latency is high only during backups. iostat shows await climbing while %util hits 100%. Which conclusion is best supported?", options:["The disk is saturated and the queue is backing up","The NIC is dropping frames","DNS is timing out","The CPU is idle-throttled"], answer:0, explain:"<strong>await rising with %util at 100% means the disk is saturated</strong> and requests are queuing.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The NIC is dropping frames</b>: iostat measures disks, not network frames.</span><span class='qd'><b>DNS is timing out</b>: DNS latency does not appear in iostat await.</span><span class='qd'><b>The CPU is idle-throttled</b>: %util refers to the device, not CPU throttling.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-088", domain:5, obj:"5.5", diff:"medium", q:"A database server's throughput drops as concurrent clients grow, yet CPU and disk look fine. free shows almost no available memory and heavy cache eviction. What is the likely constraint?", options:["Wrong DNS server","Bad cable","Insufficient RAM for the working set","Expired certificate"], answer:2, explain:"<strong>Insufficient RAM for the working set</strong> forces cache eviction and limits throughput under load.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Wrong DNS server</b>: DNS does not cause memory-driven throughput drops.</span><span class='qd'><b>Bad cable</b>: a cable fault would show as link errors, not cache eviction.</span><span class='qd'><b>Expired certificate</b>: certs affect TLS handshakes, not memory pressure.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-089", domain:5, obj:"5.5", diff:"medium", q:"To find which process is generating the most disk reads/writes in real time, which tool is most appropriate?", options:["iotop","nslookup","getenforce","blkid"], answer:0, explain:"<strong>iotop</strong> shows per-process disk I/O in real time to find the heavy writer/reader.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nslookup</b>: resolves names, not disk I/O.</span><span class='qd'><b>getenforce</b>: reports SELinux mode, unrelated to I/O.</span><span class='qd'><b>blkid</b>: lists block UUIDs, not live I/O per process.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-090", domain:5, obj:"5.5", diff:"medium", q:"A service responds slowly and strace shows it blocking on read() from a network socket. Which area should you investigate next?", options:["Local disk fragmentation","Upstream dependency/network latency","SELinux booleans","User quota limits"], answer:1, explain:"<strong>Upstream dependency or network latency</strong> is implicated when the process blocks on a socket read.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Local disk fragmentation</b>: a socket read block is not a disk issue.</span><span class='qd'><b>SELinux booleans</b>: booleans would deny outright, not cause slow reads.</span><span class='qd'><b>User quota limits</b>: quotas restrict storage, not socket latency.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-091", domain:5, obj:"5.5", diff:"easy", q:"Which command quickly shows total, used, free, and available memory plus swap to confirm a memory shortage?", options:["route -n","umask","hostnamectl","free -h"], answer:3, explain:"<strong>free -h</strong> displays human-readable memory and swap usage to confirm shortages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>route -n</b>: shows the routing table, not memory.</span><span class='qd'><b>umask</b>: prints the file-creation mask, unrelated to memory.</span><span class='qd'><b>hostnamectl</b>: shows host identity info, not memory stats.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-092", domain:5, obj:"5.5", diff:"hard", q:"A multi-core server shows low overall CPU but one core constantly at 100% handling network interrupts, limiting throughput. Which tuning addresses this?", options:["Increase swap size","Lower the MTU to 576","Disable SELinux","Spread IRQs across cores (IRQ affinity/RSS)"], answer:3, explain:"<strong>Spreading IRQs across cores via IRQ affinity/RSS</strong> relieves the single saturated core handling interrupts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Increase swap size</b>: swap does not relieve interrupt-bound CPU saturation.</span><span class='qd'><b>Lower the MTU to 576</b>: smaller frames increase per-packet overhead, worsening it.</span><span class='qd'><b>Disable SELinux</b>: SELinux does not cause interrupt concentration.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-093", domain:5, obj:"5.5", diff:"medium", q:"After adding RAM, performance still lags and the system swaps heavily. You discover swappiness is at 60 and the app prefers RAM. Which adjustment can reduce premature swapping?", options:["Raise vm.swappiness to 100","Disable the page cache","Set MTU to 9000","Lower vm.swappiness"], answer:3, explain:"<strong>Lowering vm.swappiness</strong> makes the kernel prefer RAM and reduces premature swapping.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Raise vm.swappiness to 100</b>: that encourages even more swapping.</span><span class='qd'><b>Disable the page cache</b>: that hurts overall performance and is impractical.</span><span class='qd'><b>Set MTU to 9000</b>: MTU is a network setting, irrelevant to swap.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-094", domain:5, obj:"5.5", diff:"medium", q:"A nightly job makes the whole server unresponsive. sar data shows runqueue length spiking far above core count at that time. What does this indicate?", options:["A DNS outage","A full inode table","CPU saturation / too many runnable tasks","A bad certificate"], answer:2, explain:"<strong>A run-queue far above the core count indicates CPU saturation</strong> with more runnable tasks than cores.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A DNS outage</b>: DNS problems do not inflate the run queue.</span><span class='qd'><b>A full inode table</b>: inode exhaustion is a filesystem limit, not CPU scheduling.</span><span class='qd'><b>A bad certificate</b>: certificates do not affect runnable task counts.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-095", domain:5, obj:"5.5", diff:"medium", q:"You need historical, retrospective CPU/memory/I/O statistics to diagnose a slowdown that already ended. Which tool provides this?", options:["top","sar (sysstat)","watch","tail -f"], answer:1, explain:"<strong>sar from the sysstat package</strong> stores historical performance data for retrospective analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>top</b>: shows only the current live snapshot.</span><span class='qd'><b>watch</b>: repeats a command live but keeps no history.</span><span class='qd'><b>tail -f</b>: follows a file live, not historical metrics.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-096", domain:5, obj:"5.5", diff:"hard", q:"An NVMe-backed app shows low throughput despite fast hardware. You find the I/O scheduler set in a way that adds latency for SSDs. Which scheduler is typically best for NVMe?", options:["none/noop (minimal scheduling)","cfq with deep queues","Strict bfq for all","Disable the device"], answer:0, explain:"<strong>The 'none' (noop) scheduler</strong> minimizes overhead and suits low-latency NVMe devices.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cfq with deep queues</b>: cfq's fairness logic adds latency unsuited to NVMe.</span><span class='qd'><b>Strict bfq for all</b>: bfq adds scheduling overhead that can hurt fast SSDs.</span><span class='qd'><b>Disable the device</b>: disabling the disk makes the app unusable.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-097", domain:5, obj:"5.5", diff:"medium", q:"A report says the application is slow, but you must confirm whether the bottleneck is CPU, memory, disk, or network before acting. Which approach reflects good methodology?", options:["Reboot and hope it clears","Replace the disks immediately","Rewrite the application","Use targeted tools (top, free, iostat, ss) to localize the resource"], answer:3, explain:"<strong>Using targeted tools to localize the constrained resource</strong> follows methodical, evidence-based troubleshooting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Reboot and hope it clears</b>: rebooting blindly skips diagnosis and may recur.</span><span class='qd'><b>Replace the disks immediately</b>: hardware swaps are premature without evidence.</span><span class='qd'><b>Rewrite the application</b>: a rewrite is drastic and unjustified before root-cause analysis.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-098", domain:5, obj:"5.5", diff:"medium", q:"Throughput on a 10GbE link maxes at ~1Gbps. Both ends report the link as up. Which check is most relevant to the symptom?", options:["SELinux enforcing mode","Disk inode count","User shell setting","Negotiated link speed/duplex (ethtool)"], answer:3, explain:"<strong>Checking negotiated link speed/duplex with ethtool</strong> can reveal a 1Gbps autonegotiation cap on a 10GbE port.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>SELinux enforcing mode</b>: SELinux does not throttle link speed.</span><span class='qd'><b>Disk inode count</b>: filesystem inodes are unrelated to network throughput.</span><span class='qd'><b>User shell setting</b>: the login shell does not cap NIC speed.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-099", domain:5, obj:"5.5", diff:"hard", q:"A container host shows high overall CPU steal time (%st) in top. What does this most likely indicate?", options:["Local disk is full","DNS is misconfigured","The hypervisor is starving the VM of CPU cycles","A bad cable"], answer:2, explain:"<strong>High steal time (%st) means the hypervisor is giving the VM less CPU</strong> than it wants, a noisy-neighbor or oversubscription sign.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Local disk is full</b>: disk capacity does not produce CPU steal time.</span><span class='qd'><b>DNS is misconfigured</b>: DNS issues do not register as %st.</span><span class='qd'><b>A bad cable</b>: a network fault is unrelated to CPU steal.</span>" }
);
LINUXPLUS.questions.push(
{ id:"D5-100", domain:5, obj:"5.5", diff:"medium", q:"After fixing a slow server, what does the troubleshooting methodology require as the final step?", options:["Immediately deploy more changes","Document findings, actions, and outcomes","Delete all logs","Disable monitoring"], answer:1, explain:"<strong>Documenting findings, actions, and outcomes</strong> is the required final methodology step for future reference.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately deploy more changes</b>: piling on changes risks new regressions and skips documentation.</span><span class='qd'><b>Delete all logs</b>: removing logs destroys evidence needed later.</span><span class='qd'><b>Disable monitoring</b>: turning off monitoring removes the ability to catch recurrence.</span>" }
);

