      { label:"Final nmcli subcommand to apply changes", options:["reload","up","edit","clone"], answer:1, explain:"nmcli con up reactivates the connection with the new settings; reload re-reads files without reactivating, edit opens interactive mode, and clone copies a profile." },
      { label:"Command to verify the address took effect", options:["ip addr show eth0","route print","arp -a","hostname"], answer:0, explain:"ip addr show eth0 displays the interface's assigned addresses; route print is Windows syntax, arp shows the neighbor cache, and hostname prints the system name." }
